-- Poems batch 471
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-12','隱嘗在江陵忝故中令白公叨蒙知遇今復重過渚宮感事悲身遂成長句','羅隱','唐','御定全唐诗','yuding','','[]','往歲酂侯鎮渚宮，曾將清律暖孤蓬。才憐曼倩三冬後，',40,'御定全唐詩/json/657.json','["往歲酂侯鎮渚宮，曾將清律暖孤蓬。才憐曼倩三冬後，", "鳳凰池涸台星拆，回首岐山憶至公。"]'),
('yuding-13','夜泊毗陵無錫縣有寄','羅隱','唐','御定全唐诗','yuding','','[]','草蟲幽咽樹初團，獨系孤舟夜已闌。濁浪勢奔吳苑急，',40,'御定全唐詩/json/657.json','["草蟲幽咽樹初團，獨系孤舟夜已闌。濁浪勢奔吳苑急，", "他日親朋應大笑，始知書劍是無端。"]'),
('yuding-14','桃花','羅隱','唐','御定全唐诗','yuding','','[]','暖觸衣襟漠漠香，間梅遮柳不勝芳。數枝豔拂文君酒，',40,'御定全唐詩/json/657.json','["暖觸衣襟漠漠香，間梅遮柳不勝芳。數枝豔拂文君酒，", "舊山山下還如此，回首東風一斷腸。"]'),
('yuding-15','籌筆驛','羅隱','唐','御定全唐诗','yuding','','[]','拋擲南陽為主憂，北征東討盡良籌。時來天地皆同力，',40,'御定全唐詩/json/657.json','["拋擲南陽為主憂，北征東討盡良籌。時來天地皆同力，", "唯餘岩下多情水，猶解年年傍驛流。"]'),
('yuding-16','重過隨州故兵部李侍郎恩知因抒長句','羅隱','唐','御定全唐诗','yuding','','[]','莊周高論伯牙琴，閑夜思量淚滿襟。四海共誰言近事，',40,'御定全唐詩/json/657.json','["莊周高論伯牙琴，閑夜思量淚滿襟。四海共誰言近事，", "慚愧蒼生還有意，解歌襦袴至如今。"]'),
('yuding-17','商于驛樓東望有感','羅隱','唐','御定全唐诗','yuding','','[]','山川去接漢江東，曾伴隋侯醉此中。歌繞夜梁珠宛轉，',40,'御定全唐詩/json/657.json','["山川去接漢江東，曾伴隋侯醉此中。歌繞夜梁珠宛轉，", "惆悵知音竟難得，兩行清淚白楊風。"]'),
('yuding-18','寄南城韋逸人','羅隱','唐','御定全唐诗','yuding','','[]','杜甫詩中韋曲花，至今無賴尚豪家。美人曉折露沾袖，',40,'御定全唐詩/json/657.json','["杜甫詩中韋曲花，至今無賴尚豪家。美人曉折露沾袖，", "羨他南澗高眠客，春去春來任物華。"]'),
('yuding-19','梅花','羅隱','唐','御定全唐诗','yuding','','[]','吳王醉處十餘裏，照野拂衣今正繁。經雨不隨山鳥散，',40,'御定全唐詩/json/657.json','["吳王醉處十餘裏，照野拂衣今正繁。經雨不隨山鳥散，", "欲寄所思無好信，為人惆悵又黃昏。"]'),
('yuding-20','淮南高駢所造迎仙樓','羅隱','唐','御定全唐诗','yuding','','[]','鸞音鶴信杳難回，鳳駕龍車早晚來。仙境是誰知處所，',40,'御定全唐詩/json/657.json','["鸞音鶴信杳難回，鳳駕龍車早晚來。仙境是誰知處所，", "子細思量成底事，露凝風擺作塵埃。"]'),
('yuding-21','和禪月大師見贈','羅隱','唐','御定全唐诗','yuding','','[]','高僧惠我七言詩，頓豁塵心展白眉。秀似穀中花媚日，',40,'御定全唐詩/json/657.json','["高僧惠我七言詩，頓豁塵心展白眉。秀似穀中花媚日，", "漂蕩秦吳十餘載，因循猶恨識師遲。"]'),
('yuding-22','謁文宣王廟','羅隱','唐','御定全唐诗','yuding','','[]','晚來乘興謁先師，松柏淒淒人不知。九仞蕭牆堆瓦礫，',40,'御定全唐詩/json/657.json','["晚來乘興謁先師，松柏淒淒人不知。九仞蕭牆堆瓦礫，", "儻使小儒名稍立，豈教吾道受棲遲。"]'),
('yuding-23','代文宣王答','羅隱','唐','御定全唐诗','yuding','','[]','三教之中儒最尊，止戈為武武尊文。吾今尚自披蓑笠，',40,'御定全唐詩/json/657.json','["三教之中儒最尊，止戈為武武尊文。吾今尚自披蓑笠，", "若教顏閔英靈在，終不羞他李老君。"]'),
('yuding-24','重送朗州張員外','羅隱','唐','御定全唐诗','yuding','','[]','朱輪此去正春風，且駐青雲聽斷蓬。一榻早年容孺子，',40,'御定全唐詩/json/657.json','["朱輪此去正春風，且駐青雲聽斷蓬。一榻早年容孺子，", "酬德酬恩兩無路，謾勞惆悵鳳城東。"]'),
('yuding-25','廣陵秋夜讀進士常修三篇因題','羅隱','唐','御定全唐诗','yuding','','[]','入蜀歸吳三首詩，藏於笥篋重于師。劍關夜讀相如聽，',40,'御定全唐詩/json/657.json','["入蜀歸吳三首詩，藏於笥篋重于師。劍關夜讀相如聽，", "明年二月春風裏，江島閒人慰所思。"]'),
('yuding-26','逼試投所知','羅隱','唐','御定全唐诗','yuding','','[]','桃在仙翁舊苑傍，暖煙輕靄撲人香。十年此地頻偷眼，',40,'御定全唐詩/json/657.json','["桃在仙翁舊苑傍，暖煙輕靄撲人香。十年此地頻偷眼，", "尋思仙骨終難得，始與回頭問玉皇。"]'),
('yuding-27','漢江上作','羅隱','唐','御定全唐诗','yuding','','[]','漢江波浪淥於苔，每到江邊病眼開。半雨半風終日恨，',40,'御定全唐詩/json/657.json','["漢江波浪淥於苔，每到江邊病眼開。半雨半風終日恨，", "對此空慚聖明代，忍教纓上有塵埃。"]'),
('yuding-28','秋夜寄進士顧榮','羅隱','唐','御定全唐诗','yuding','','[]','秋河耿耿夜沉沉，往事三更盡到心。多病謾勞窺聖代，',40,'御定全唐詩/json/657.json','["秋河耿耿夜沉沉，往事三更盡到心。多病謾勞窺聖代，", "空羨良朋盡高價，可憐東箭與南金。"]'),
('yuding-29','寄渭北徐從事','羅隱','唐','御定全唐诗','yuding','','[]','暖雲慵墮柳垂條，驄馬徐郎過渭橋。官秩舊參荀秘監，',40,'御定全唐詩/json/657.json','["暖雲慵墮柳垂條，驄馬徐郎過渭橋。官秩舊參荀秘監，", "莫恨東風促行李，不多時節卻歸朝。"]'),
('yuding-30','徐寇南逼感事獻江南知己次韻','羅隱','唐','御定全唐诗','yuding','','[]','酒闌離思浩無窮，西望維揚憶數公。萬里飄零身未了，',40,'御定全唐詩/json/657.json','["酒闌離思浩無窮，西望維揚憶數公。萬里飄零身未了，", "今日便成盧子諒，滿襟珠淚墮霜風。"]'),
('yuding-31','寄三衢孫員外','羅隱','唐','御定全唐诗','yuding','','[]','小敷文伯見何時，南望三衢渴複饑。天子未能崇典誥，',40,'御定全唐詩/json/657.json','["小敷文伯見何時，南望三衢渴複饑。天子未能崇典誥，", "儘是數旬陪奉處，使君爭肯不相思。"]'),
('yuding-32','淮南送盧端公歸台','羅隱','唐','御定全唐诗','yuding','','[]','鳳鸞勢逸九霄寬，北去南來任羽翰。朱紱兩參王儉府，',40,'御定全唐詩/json/657.json','["鳳鸞勢逸九霄寬，北去南來任羽翰。朱紱兩參王儉府，", "應笑張綱謾生事，埋輪不得在長安。"]'),
('yuding-33','煬帝陵','羅隱','唐','御定全唐诗','yuding','','[]','入郭登橋出郭船，紅樓日日柳年年。',32,'御定全唐詩/json/657.json','["入郭登橋出郭船，紅樓日日柳年年。", "君王忍把平陳業，只博雷塘數畝田。"]'),
('yuding-34','馬嵬坡','羅隱','唐','御定全唐诗','yuding','','[]','佛屋前頭野草春，貴妃輕骨此為塵。',32,'御定全唐詩/json/657.json','["佛屋前頭野草春，貴妃輕骨此為塵。", "從來絕色知難得，不破中原未是人。"]'),
('yuding-35','柳','羅隱','唐','御定全唐诗','yuding','','[]','灞岸晴來送別頻，相偎相倚不勝春。',32,'御定全唐詩/json/657.json','["灞岸晴來送別頻，相偎相倚不勝春。", "自家飛絮猶無定，爭解垂絲絆路人。"]'),
('yuding-36','隋堤柳','羅隱','唐','御定全唐诗','yuding','','[]','夾路依依千里遙，路人回首認隋朝。',32,'御定全唐詩/json/657.json','["夾路依依千里遙，路人回首認隋朝。", "春風未借宣華意，猶費工夫長綠條。"]'),
('yuding-37','孟浩然墓','羅隱','唐','御定全唐诗','yuding','','[]','數步荒榛接舊蹊，寒江漠漠草淒淒。',32,'御定全唐詩/json/657.json','["數步荒榛接舊蹊，寒江漠漠草淒淒。", "鹿門黃土無多少，恰到書生塚便低。"]'),
('yuding-38','秦紀','羅隱','唐','御定全唐诗','yuding','','[]','長策東鞭及海隅，黿鼉奔走鬼神趨。',32,'御定全唐詩/json/657.json','["長策東鞭及海隅，黿鼉奔走鬼神趨。", "憐君未到沙丘日，肯信人間有死無。"]'),
('yuding-39','仙掌','羅隱','唐','御定全唐诗','yuding','','[]','掌前流水駐無塵，掌下軒車日日新。',32,'御定全唐詩/json/657.json','["掌前流水駐無塵，掌下軒車日日新。", "謾向山頭高舉手，何曾招得路行人。"]'),
('yuding-0','詠月','羅隱','唐','御定全唐诗','yuding','','[]','湖上風高動白蘋，暫延清景此逡巡。來年違別成何事，',40,'御定全唐詩/json/658.json','["湖上風高動白蘋，暫延清景此逡巡。來年違別成何事，", "嫦娥老大應惆悵，倚泣蒼蒼桂一輪。"]'),
('yuding-1','宿荊州江陵驛','羅隱','唐','御定全唐诗','yuding','','[]','西游象闕愧知音，東下荊溪稱越吟。風動芰荷香四散，',40,'御定全唐詩/json/658.json','["西游象闕愧知音，東下荊溪稱越吟。風動芰荷香四散，", "薜荔衣裳木蘭楫，異時煙雨好追尋。"]'),
('yuding-2','撫州別阮兵曹','羅隱','唐','御定全唐诗','yuding','','[]','雪晴天外見諸峰，幽軋行輪有去蹤。內史宅邊今獨恨，',40,'御定全唐詩/json/658.json','["雪晴天外見諸峰，幽軋行輪有去蹤。內史宅邊今獨恨，", "若不他時更青眼，未知誰肯薦臨邛。"]'),
('yuding-3','新安投所知','羅隱','唐','御定全唐诗','yuding','','[]','少年容易舍樵漁，曾辱明公薦子虛。漢殿夜寒時不食，',40,'御定全唐詩/json/658.json','["少年容易舍樵漁，曾辱明公薦子虛。漢殿夜寒時不食，", "長劍一尋歌一奏，此心爭肯為鱸魚。"]'),
('yuding-4','江邊有寄','羅隱','唐','御定全唐诗','yuding','','[]','江邊舊業半雕殘，每軫歸心即萬端。狂折野梅山店暖，',40,'御定全唐詩/json/658.json','["江邊舊業半雕殘，每軫歸心即萬端。狂折野梅山店暖，", "同病同憂更何事，為君提筆劃漁竿。"]'),
('yuding-5','送友人歸夷門','羅隱','唐','御定全唐诗','yuding','','[]','二年流落大樑城，每送君歸即有情。別路算來成底事，',40,'御定全唐詩/json/658.json','["二年流落大樑城，每送君歸即有情。別路算來成底事，", "至竟男兒分應定，不須惆悵穀中鶯。"]'),
('yuding-6','湘中見進士喬詡','羅隱','唐','御定全唐诗','yuding','','[]','吳公台下別經秋，破虜城邊暫駐留。一笑有情堪解夢，',40,'御定全唐詩/json/658.json','["吳公台下別經秋，破虜城邊暫駐留。一笑有情堪解夢，", "且酌松醪依舊醉，誰能相見向春愁。"]'),
('yuding-7','上霅川裴郎中','羅隱','唐','御定全唐诗','yuding','','[]','貴提金印出咸秦，瀟灑江城兩度春。一派水清疑見膽，',40,'御定全唐詩/json/658.json','["貴提金印出咸秦，瀟灑江城兩度春。一派水清疑見膽，", "自是受恩心未足，卻垂雙翅羨吳均。"]'),
('yuding-8','錢塘江潮','羅隱','唐','御定全唐诗','yuding','','[]','怒聲洶洶勢悠悠，羅刹江邊地欲浮。漫道往來存大信，',40,'御定全唐詩/json/658.json','["怒聲洶洶勢悠悠，羅刹江邊地欲浮。漫道往來存大信，", "至竟朝昏誰主掌，好騎赬鯉問陽侯。"]'),
('yuding-9','送人赴職任褒中','羅隱','唐','御定全唐诗','yuding','','[]','物態時情難重陳，夫君此去莫傷春。男兒只要有知己，',40,'御定全唐詩/json/658.json','["物態時情難重陳，夫君此去莫傷春。男兒只要有知己，", "海棠花謝東風老，應念京都共苦辛。"]'),
('yuding-10','臨川投穆中丞','羅隱','唐','御定全唐诗','yuding','','[]','試將生計問蓬根，心委寒灰首戴盆。翅弱未知三島路，',40,'御定全唐詩/json/658.json','["試將生計問蓬根，心委寒灰首戴盆。翅弱未知三島路，", "家在碧江歸不得，十年魚艇長苔痕。"]'),
('yuding-11','早春送張坤歸大樑','羅隱','唐','御定全唐诗','yuding','','[]','蕭蕭羸馬正塵埃，又送輶軒向吹台。別酒莫辭今夜醉，',40,'御定全唐詩/json/658.json','["蕭蕭羸馬正塵埃，又送輶軒向吹台。別酒莫辭今夜醉，", "為謝東門抱關吏，不堪惆悵滿離杯。"]'),
('yuding-12','東歸途中作','羅隱','唐','御定全唐诗','yuding','','[]','松橘蒼黃覆釣磯，早年生計近年違。老知風月終堪恨，',40,'御定全唐詩/json/658.json','["松橘蒼黃覆釣磯，早年生計近年違。老知風月終堪恨，", "買臣嚴助精靈在，應笑無成一布衣。"]'),
('yuding-13','送進士臧濆下第後歸池州','羅隱','唐','御定全唐诗','yuding','','[]','賦成無處換黃金，卻向春風動越吟。天子愛才雖仄席，',40,'御定全唐詩/json/658.json','["賦成無處換黃金，卻向春風動越吟。天子愛才雖仄席，", "珍重彩衣歸正好，莫將閒事系升沈。"]'),
('yuding-14','湘中贈范鄖','羅隱','唐','御定全唐诗','yuding','','[]','丹桂無心彼此諳，二年疏懶共江潭。愁知酒醆終難舍，',40,'御定全唐詩/json/658.json','["丹桂無心彼此諳，二年疏懶共江潭。愁知酒醆終難舍，", "勞歌一曲霜風暮，擊折湘妃白玉簪。"]'),
('yuding-15','寄張侍郎','羅隱','唐','御定全唐诗','yuding','','[]','衰羸豈合話荊州，爭奈思多不自由。無路重趨桓典馬，',40,'御定全唐詩/json/658.json','["衰羸豈合話荊州，爭奈思多不自由。無路重趨桓典馬，", "一種人間太平日，獨教零落憶滄洲。"]'),
('yuding-16','渚宮秋思','羅隱','唐','御定全唐诗','yuding','','[]','楚城日暮煙靄深，楚人駐馬還登臨。襄王台下水無賴，',40,'御定全唐詩/json/658.json','["楚城日暮煙靄深，楚人駐馬還登臨。襄王台下水無賴，", "欲招屈宋當時魄，蘭敗荷枯不可尋。"]'),
('yuding-17','閒居早秋','羅隱','唐','御定全唐诗','yuding','','[]','槐杪清蟬煙雨餘，蕭蕭涼葉墮衣裾。噪槎烏散沈蒼嶺，',40,'御定全唐詩/json/658.json','["槐杪清蟬煙雨餘，蕭蕭涼葉墮衣裾。噪槎烏散沈蒼嶺，", "六宮誰買相如賦，團扇恩情日日疏。"]'),
('yuding-18','建康','羅隱','唐','御定全唐诗','yuding','','[]','潮平遠岸草侵沙，東晉衰來最可嗟。庾舅已能窺帝室，',40,'御定全唐詩/json/658.json','["潮平遠岸草侵沙，東晉衰來最可嗟。庾舅已能窺帝室，", "欲起九原看一遍，秦淮聲急日西斜。"]'),
('yuding-19','送舒州宿松縣傅少府','羅隱','唐','御定全唐诗','yuding','','[]','江蘺漠漠樹重重，東過清淮到宿松。縣好也知臨浣水，',40,'御定全唐詩/json/658.json','["江蘺漠漠樹重重，東過清淮到宿松。縣好也知臨浣水，", "留取餘杯待張翰，明年歸棹一從容。"]'),
('yuding-20','經故洛陽城','羅隱','唐','御定全唐诗','yuding','','[]','敗垣危堞跡依稀，試駐羸驂吊落暉。跋扈以成梁冀在，',40,'御定全唐詩/json/658.json','["敗垣危堞跡依稀，試駐羸驂吊落暉。跋扈以成梁冀在，", "千載昆陽好功業，與君門下作恩威。"]'),
('yuding-21','夏州胡常侍','羅隱','唐','御定全唐诗','yuding','','[]','百尺高臺勃勃州，大刀長戟漢諸侯。征鴻過盡邊雲闊，',40,'御定全唐詩/json/658.json','["百尺高臺勃勃州，大刀長戟漢諸侯。征鴻過盡邊雲闊，", "仍聞隴蜀由多事，深喜將軍未白頭。"]'),
('yuding-22','寄進士盧休','羅隱','唐','御定全唐诗','yuding','','[]','半年池口恨萍蓬，今日思量已夢中。遊子馬蹄難重到，',40,'御定全唐詩/json/658.json','["半年池口恨萍蓬，今日思量已夢中。遊子馬蹄難重到，", "從此客程君不見，麥秋梅雨遍江東。"]'),
('yuding-23','贈先輩令狐補闕','羅隱','唐','御定全唐诗','yuding','','[]','中間聲跡早熏然，阻避鈞衡過十年。碧海浪高終濟物，',40,'御定全唐詩/json/658.json','["中間聲跡早熏然，阻避鈞衡過十年。碧海浪高終濟物，", "應念淒涼洞庭客，夜深雙淚憶漁船。"]'),
('yuding-24','送秦州從事','羅隱','唐','御定全唐诗','yuding','','[]','一枝何足解人愁，拋卻還隨定遠侯。紫陌紅塵今別恨，',40,'御定全唐詩/json/658.json','["一枝何足解人愁，拋卻還隨定遠侯。紫陌紅塵今別恨，", "若到邊庭有來使，試批書尾話梁州。"]'),
('yuding-25','湖州裴郎中赴闕後投簡寄友生','羅隱','唐','御定全唐诗','yuding','','[]','錦帳郎官塞詔年，汀洲曾駐木蘭船。禰衡酒醒春瓶倒，',40,'御定全唐詩/json/658.json','["錦帳郎官塞詔年，汀洲曾駐木蘭船。禰衡酒醒春瓶倒，", "使君入拜吾徒在，宣室他時豈偶然。"]'),
('yuding-26','秋日泊平望驛寄太常裴郎中','羅隱','唐','御定全唐诗','yuding','','[]','蘋洲重到杳難期，西倚郵亭憶往時。北海尊中常有酒，',40,'御定全唐詩/json/658.json','["蘋洲重到杳難期，西倚郵亭憶往時。北海尊中常有酒，", "聞說江南舊歌曲，至今猶自唱吳姬。"]'),
('yuding-27','西塞山','羅隱','唐','御定全唐诗','yuding','','[]','吳塞當時指此山，吳都亡後綠孱顏。嶺梅乍暖殘妝恨，',40,'御定全唐詩/json/658.json','["吳塞當時指此山，吳都亡後綠孱顏。嶺梅乍暖殘妝恨，", "會將一副寒蓑笠，來與漁翁作往還。"]'),
('yuding-28','秋日汴河客舍酬友人','羅隱','唐','御定全唐诗','yuding','','[]','梁宋追遊早歲同，偶然違別事皆空。年如流水催何急，',40,'御定全唐詩/json/658.json','["梁宋追遊早歲同，偶然違別事皆空。年如流水催何急，", "煩君更枉騷人句，白鳳靈蛇滿袖中。"]'),
('yuding-29','東歸','羅隱','唐','御定全唐诗','yuding','','[]','仙桂高高似有神，貂裘敝盡取無因。難將白髮期公道，',40,'御定全唐詩/json/658.json','["仙桂高高似有神，貂裘敝盡取無因。難將白髮期公道，", "盈盤紫蟹千卮酒，添得臨岐淚滿巾。"]'),
('yuding-30','廣陵李僕射借示近詩因投獻','羅隱','唐','御定全唐诗','yuding','','[]','朝論國計暮論兵，餘力猶隨鳳藻生。語繼盤盂拋俗格，',40,'御定全唐詩/json/658.json','["朝論國計暮論兵，餘力猶隨鳳藻生。語繼盤盂拋俗格，", "天柄已持堯典在，更堪回首問緣情。"]'),
('yuding-31','三衢哭孫員外','羅隱','唐','御定全唐诗','yuding','','[]','燕戀雕梁馬戀軒，此心從此更何言。直將塵外三生命，',40,'御定全唐詩/json/658.json','["燕戀雕梁馬戀軒，此心從此更何言。直將塵外三生命，", "忍看明發衣襟上，珠淚痕中見酒痕。"]'),
('yuding-32','篋中得故王郎中書','羅隱','唐','御定全唐诗','yuding','','[]','鳳裏前年別望郎，丁甯唯恐滯吳鄉。勸疏杯酒知妨事，',40,'御定全唐詩/json/658.json','["鳳裏前年別望郎，丁甯唯恐滯吳鄉。勸疏杯酒知妨事，", "九原自此無因見，反復遺蹤淚萬行。"]'),
('yuding-33','淚','羅隱','唐','御定全唐诗','yuding','','[]','逼臉橫頤咽複勻，也曾讒毀也傷神。',32,'御定全唐詩/json/658.json','["逼臉橫頤咽複勻，也曾讒毀也傷神。", "自從魯國潸然後，不是奸人即婦人。"]'),
('yuding-34','子規','羅隱','唐','御定全唐诗','yuding','','[]','銅梁路遠草青青，此恨那堪枕上聽。',32,'御定全唐詩/json/658.json','["銅梁路遠草青青，此恨那堪枕上聽。", "一種有冤猶可報，不如銜石疊滄溟。"]'),
('yuding-35','姑蘇台','羅隱','唐','御定全唐诗','yuding','','[]','讓高泰伯開基日，賢見延陵複命時。',32,'御定全唐詩/json/658.json','["讓高泰伯開基日，賢見延陵複命時。", "未會子孫因底事，解崇台榭為西施。"]'),
('yuding-36','王浚墓','羅隱','唐','御定全唐诗','yuding','','[]','男兒未必盡英雄，但到時來即命通。',32,'御定全唐詩/json/658.json','["男兒未必盡英雄，但到時來即命通。", "若使吳都猶王氣，將軍何處立殊功。"]'),
('yuding-37','京中晚望','羅隱','唐','御定全唐诗','yuding','','[]','心如野鹿跡如萍，謾向人間性一靈。',32,'御定全唐詩/json/658.json','["心如野鹿跡如萍，謾向人間性一靈。", "往事不知多少夢，夜來和酒一時醒。"]'),
('yuding-38','寄竇澤處士二首','羅隱','唐','御定全唐诗','yuding','','[]','蘭亭醉客舊知聞，欲問平安隔海雲。',64,'御定全唐詩/json/658.json','["蘭亭醉客舊知聞，欲問平安隔海雲。", "不是金陵錢太尉，世間誰肯更容身。", "鼇背樓臺拂白榆，此中槎客亦踟躊。", "牢山道士無仙骨，卻向人間作酒徒。"]'),
('yuding-0','省試秋風生桂枝','羅隱','唐','御定全唐诗','yuding','','[]','涼吹從何起，中宵景象清。漫隨雲葉動，高傍桂枝生。',72,'御定全唐詩/json/659.json','["涼吹從何起，中宵景象清。漫隨雲葉動，高傍桂枝生。", "漠漠看無際，蕭蕭別有聲。遠吹斜漢轉，低拂白榆輕。", "寥泬工夫大，乾坤歲序更。因悲遠歸客，長望一枝榮。"]'),
('yuding-1','思故人','羅隱','唐','御定全唐诗','yuding','','[]','故人不可見，聊複拂鳴琴。鵲繞風枝急，螢藏露草深。',48,'御定全唐詩/json/659.json','["故人不可見，聊複拂鳴琴。鵲繞風枝急，螢藏露草深。", "平生四方志，此夜五湖心。惆悵友朋盡，洋洋漫好音。"]'),
('yuding-2','寄陸龜蒙','羅隱','唐','御定全唐诗','yuding','','[]','龍樓李丞相，昔歲仰高文。黃閣尋無主，青山竟未焚。',48,'御定全唐詩/json/659.json','["龍樓李丞相，昔歲仰高文。黃閣尋無主，青山竟未焚。", "夜船乘海月，秋寺伴江雲。卻恐塵埃裏，浮名點汙君。"]'),
('yuding-3','題方幹詩','羅隱','唐','御定全唐诗','yuding','','[]','中間李建州，夏汭偶同遊。顧我論佳句，推君最上流。',48,'御定全唐詩/json/659.json','["中間李建州，夏汭偶同遊。顧我論佳句，推君最上流。", "九霄無鶴板，雙鬢老漁舟。世難方如此，何當浣旅愁。"]'),
('yuding-4','秋江','羅隱','唐','御定全唐诗','yuding','','[]','秋江待晚潮，客思旆旌搖。細雨翻蘆葉，高風卻柳條。',48,'御定全唐詩/json/659.json','["秋江待晚潮，客思旆旌搖。細雨翻蘆葉，高風卻柳條。", "兵戈村落破，饑儉虎狼驕。吾土兼連此，離魂望裏消。"]'),
('yuding-5','寄制誥李舍人','羅隱','唐','御定全唐诗','yuding','','[]','梁王握豹韜，雪裏見枚皋。上客趨丹陛，遊人歎二毛。',48,'御定全唐詩/json/659.json','["梁王握豹韜，雪裏見枚皋。上客趨丹陛，遊人歎二毛。", "門閑知待詔，星動想濡毫。一首長楊賦，應嫌索價高。"]'),
('yuding-6','秋日懷孟夷庚','羅隱','唐','御定全唐诗','yuding','','[]','秋日黃陂下，孤舟憶共誰。江山三楚分，風雨二妃祠。',48,'御定全唐詩/json/659.json','["秋日黃陂下，孤舟憶共誰。江山三楚分，風雨二妃祠。", "知己秦貂沒，流年賈鵩悲。中原正兵馬，相見是何時。"]'),
('yuding-7','送李右丞分司','羅隱','唐','御定全唐诗','yuding','','[]','分漕得洛川，讜議更昭然。在省曾批敕，中台肯避權。',48,'御定全唐詩/json/659.json','["分漕得洛川，讜議更昭然。在省曾批敕，中台肯避權。", "所悲時漸薄，共賀道由全。賣與清平代，相兼直幾錢。"]'),
('yuding-8','郴江遷客','羅隱','唐','御定全唐诗','yuding','','[]','不是逢清世，何由見皂囊。事雖危虎尾，名勝泊鵷行。',48,'御定全唐詩/json/659.json','["不是逢清世，何由見皂囊。事雖危虎尾，名勝泊鵷行。", "毒霧郴江闊，愁雲楚驛長。歸時有詩賦，一為吊沉湘。"]'),
('yuding-9','感舊','羅隱','唐','御定全唐诗','yuding','','[]','劍佩孫弘閣，戈鋋太尉營。重言虛有位，孤立竟無成。',48,'御定全唐詩/json/659.json','["劍佩孫弘閣，戈鋋太尉營。重言虛有位，孤立竟無成。", "丘隴笳簫咽，池台歲月平。此恩何以報，歸處是柴荊。"]'),
('yuding-10','鷹','羅隱','唐','御定全唐诗','yuding','','[]','越海霜天暮，辭韜野草幹。俊通司隸職，嚴奉武夫官。',48,'御定全唐詩/json/659.json','["越海霜天暮，辭韜野草幹。俊通司隸職，嚴奉武夫官。", "眼惡藏蜂在，心粗逐物殫。近來脂膩足，驅遣不妨難。"]'),
('yuding-11','秋日寄狄補闕','羅隱','唐','御定全唐诗','yuding','','[]','紅塵擾擾間，立馬看南山。謾道經年往，何妨逐日閑。',48,'御定全唐詩/json/659.json','["紅塵擾擾間，立馬看南山。謾道經年往，何妨逐日閑。", "病中霜葉赤，愁裏鬢毛斑。不為良知在，驅車已出關。"]'),
('yuding-12','寄易定公乘億侍郎','羅隱','唐','御定全唐诗','yuding','','[]','謝舞仍宮柳，高奇世少雙。侍中生不到，園令死須降。',48,'御定全唐詩/json/659.json','["謝舞仍宮柳，高奇世少雙。侍中生不到，園令死須降。", "班秩通烏府，樽罍奉碧幢。昭王有餘烈，試為禱迷邦。"]'),
('yuding-13','寄大理徐郎中','羅隱','唐','御定全唐诗','yuding','','[]','佐棘竟誰同，因思證聖中。事雖忘顯報，理合有陰功。',48,'御定全唐詩/json/659.json','["佐棘竟誰同，因思證聖中。事雖忘顯報，理合有陰功。", "官序詵枝老，幽塵範甑空。幾時潘好禮，重與話清風。"]'),
('yuding-14','寄蘇拾遺','羅隱','唐','御定全唐诗','yuding','','[]','早歲長楊賦，當年諫獵書。格高時輩伏，言數宦情疏。',48,'御定全唐詩/json/659.json','["早歲長楊賦，當年諫獵書。格高時輩伏，言數宦情疏。", "慷慨傳丹桂，艱難保舊居。退朝觀槁草，能望馬相如。"]'),
('yuding-15','寄許融','羅隱','唐','御定全唐诗','yuding','','[]','多病仍疏拙，唯君與我同。帝鄉年共老，江徼業俱空。',48,'御定全唐詩/json/659.json','["多病仍疏拙，唯君與我同。帝鄉年共老，江徼業俱空。", "燕冷辭華屋，蛩涼恨曉叢。白雲高幾許，全屬采芝翁。"]'),
('yuding-16','寄禮部鄭員外','羅隱','唐','御定全唐诗','yuding','','[]','欒郤門風大，裴王禮樂優。班資冠雞舌，人品壓龍頭。',48,'御定全唐詩/json/659.json','["欒郤門風大，裴王禮樂優。班資冠雞舌，人品壓龍頭。", "夜直爐香細，晴編疏草稠。近聞潘散騎，三十二悲秋。"]'),
('yuding-17','菊','羅隱','唐','御定全唐诗','yuding','','[]','籬落歲雲暮，數枝聊自芳。雪裁纖蕊密，金拆小苞香。',48,'御定全唐詩/json/659.json','["籬落歲雲暮，數枝聊自芳。雪裁纖蕊密，金拆小苞香。", "千載白衣酒，一生青女霜。春叢莫輕薄，彼此有行藏。"]'),
('yuding-18','台城','羅隱','唐','御定全唐诗','yuding','','[]','水國春常在，台城夜未寒。麗華承寵渥，江令捧杯盤。',48,'御定全唐詩/json/659.json','["水國春常在，台城夜未寒。麗華承寵渥，江令捧杯盤。", "宴罷明堂爛，詩成寶炬殘。兵來吾有計，金井玉鉤欄。"]'),
('yuding-19','舊游','羅隱','唐','御定全唐诗','yuding','','[]','良時不復再，漸老更難言。遠水猶經眼，高樓似斷魂。',48,'御定全唐詩/json/659.json','["良時不復再，漸老更難言。遠水猶經眼，高樓似斷魂。", "依依宋玉宅，歷歷長卿村。今日空江畔，相於只酒樽。"]'),
('yuding-20','寄虔州薛大夫','羅隱','唐','御定全唐诗','yuding','','[]','祝融峰下別，三載夢魂勞。地轉南康重，官兼亞相高。',48,'御定全唐詩/json/659.json','["祝融峰下別，三載夢魂勞。地轉南康重，官兼亞相高。", "海鵬終負日，神馬背眠槽。會得窺成績，幽窗染兔毫。"]'),
('yuding-21','蘇小小墓','羅隱','唐','御定全唐诗','yuding','','[]','魂兮檇李城，猶未有人耕。好月當年事，殘花觸處情。',48,'御定全唐詩/json/659.json','["魂兮檇李城，猶未有人耕。好月當年事，殘花觸處情。", "向誰曾豔冶，隨分得聲名。應侍吳王宴，蘭橈暗送迎。"]'),
('yuding-22','寒食日早出城東','羅隱','唐','御定全唐诗','yuding','','[]','青門欲曙天，車馬已喧闐。禁柳疏風雨，牆花拆露鮮。',48,'御定全唐詩/json/659.json','["青門欲曙天，車馬已喧闐。禁柳疏風雨，牆花拆露鮮。", "向誰誇麗景，只是歎流年。不得高飛便，回頭望紙鳶。"]'),
('yuding-23','秋日懷賈隨進士','羅隱','唐','御定全唐诗','yuding','','[]','邊寇日騷動，故人音信稀。長纓慚賈誼，孤憤憶韓非。',48,'御定全唐詩/json/659.json','["邊寇日騷動，故人音信稀。長纓慚賈誼，孤憤憶韓非。", "曉匣魚腸冷，春園鴨掌肥。知君安未得，聊且示忘機。"]'),
('yuding-24','亂後逢友人','羅隱','唐','御定全唐诗','yuding','','[]','滄海去未得，倚舟聊問津。生靈寇盜盡，方鎮改更貧。',48,'御定全唐詩/json/659.json','["滄海去未得，倚舟聊問津。生靈寇盜盡，方鎮改更貧。", "夢裏舊行處，眼前新貴人。從來事如此，君莫獨沾巾。"]'),
('yuding-25','殘花','羅隱','唐','御定全唐诗','yuding','','[]','已歎良時晚，仍悲別酒催。暖芳隨日薄，輕片逐風回。',48,'御定全唐詩/json/659.json','["已歎良時晚，仍悲別酒催。暖芳隨日薄，輕片逐風回。", "黛斂愁歌扇，妝殘泣鏡臺。繁陰莫矜衒，終是共塵埃。"]'),
('yuding-26','秋日富春江行','羅隱','唐','御定全唐诗','yuding','','[]','遠岸平如剪，澄江靜似鋪。紫鱗仙客馭，金顆李衡奴。',48,'御定全唐詩/json/659.json','["遠岸平如剪，澄江靜似鋪。紫鱗仙客馭，金顆李衡奴。", "冷疊群山闊，清涵萬象殊。嚴陵亦高見，歸臥是良圖。"]'),
('yuding-27','寄侯博士','羅隱','唐','御定全唐诗','yuding','','[]','規諫揚雄賦，邅回賈誼官。久貧還往少，孤立轉遷難。',48,'御定全唐詩/json/659.json','["規諫揚雄賦，邅回賈誼官。久貧還往少，孤立轉遷難。", "清鏡流年急，高槐旅舍寒。侏儒亦何有，飽食向長安。"]'),
('yuding-28','送沈光侍禦赴職閩中','羅隱','唐','御定全唐诗','yuding','','[]','未至應居右，全家出帝鄉。禮優逢苑雪，官重帶台霜。',48,'御定全唐詩/json/659.json','["未至應居右，全家出帝鄉。禮優逢苑雪，官重帶台霜。", "夜浦吳潮吼，春灘建水狂。延平有風雨，從此是騰驤。"]'),
('yuding-29','寄袁皓侍郎','羅隱','唐','御定全唐诗','yuding','','[]','東台失路岐，榮辱事堪悲。我寢牛衣敝，君居豸角危。',48,'御定全唐詩/json/659.json','["東台失路岐，榮辱事堪悲。我寢牛衣敝，君居豸角危。", "風塵慚上品，才業愧明時。千里芙蓉幕，何由話所思。"]'),
('yuding-30','寄金吾李蓀常侍','羅隱','唐','御定全唐诗','yuding','','[]','西班掌禁兵，蘭錡最分明。曉色嚴天仗，春寒避火城。',48,'御定全唐詩/json/659.json','["西班掌禁兵，蘭錡最分明。曉色嚴天仗，春寒避火城。", "安危雖已任，韜略即嘉聲。請問何功德，壺關寇始平。"]'),
('yuding-31','商于驛與於蘊玉話別','羅隱','唐','御定全唐诗','yuding','','[]','南朝徐庾流，洛下憶同遊。酒采閑坊菊，山登遠寺樓。',48,'御定全唐詩/json/659.json','["南朝徐庾流，洛下憶同遊。酒采閑坊菊，山登遠寺樓。", "相思勞寄夢，偶別已經秋。還被青青桂，催君不自由。"]'),
('yuding-32','封禪寺居','羅隱','唐','御定全唐诗','yuding','','[]','盛禮何由睹，嘉名偶寄居。周南太史淚，蠻徼長卿書。',48,'御定全唐詩/json/659.json','["盛禮何由睹，嘉名偶寄居。周南太史淚，蠻徼長卿書。", "砌竹搖風直，庭花泣露疏。誰能賦秋興，千里隔吾廬。"]'),
('yuding-33','錢','羅隱','唐','御定全唐诗','yuding','','[]','志士不敢道，貯之成禍胎。小人無事藝，假爾作梯媒。',48,'御定全唐詩/json/659.json','["志士不敢道，貯之成禍胎。小人無事藝，假爾作梯媒。", "解釋愁腸結，能分睡眼開。朱門狼虎性，一半逐君回。"]'),
('yuding-34','投寄韋右丞','羅隱','唐','御定全唐诗','yuding','','[]','赤壁徵文聘，中台拜郤詵。官資參令僕，曹署轄星辰。',72,'御定全唐詩/json/659.json','["赤壁徵文聘，中台拜郤詵。官資參令僕，曹署轄星辰。", "襆被從誰起，持綱自此新。舉朝明典教，封納詔書頻。", "禁樹曾摛藻，台烏舊避塵。便應酬倚注，何處話窮鱗。"]'),
('yuding-35','紅葉','羅隱','唐','御定全唐诗','yuding','','[]','不奈荒城畔，那堪晚照中。野晴霜浥綠，山冷雨催紅。',48,'御定全唐詩/json/659.json','["不奈荒城畔，那堪晚照中。野晴霜浥綠，山冷雨催紅。", "遊子灞陵道，美人長信宮。等閒居歲暮，搖落意無窮。"]'),
('yuding-36','期徐道者不至','羅隱','唐','御定全唐诗','yuding','','[]','遼鶴虛空語，冥鴻未易親。偶然來即是，必擬見無因。',48,'御定全唐詩/json/659.json','["遼鶴虛空語，冥鴻未易親。偶然來即是，必擬見無因。", "霜霰窮冬令，杯盤旅舍貧。只應薊子訓，醉後懶分身。"]'),
('yuding-37','歲除夜','羅隱','唐','御定全唐诗','yuding','','[]','官曆行將盡，村醪強自傾。厭寒思暖律，畏老惜殘更。',48,'御定全唐詩/json/659.json','["官曆行將盡，村醪強自傾。厭寒思暖律，畏老惜殘更。", "歲月已如此，寇戎猶未平。兒童不諳事，歌吹待天明。"]'),
('yuding-38','雪','羅隱','唐','御定全唐诗','yuding','','[]','盡道豐年瑞，豐年事若何。長安有貧者，為瑞不宜多。',24,'御定全唐詩/json/659.json','["盡道豐年瑞，豐年事若何。長安有貧者，為瑞不宜多。"]'),
('yuding-39','旅夢','羅隱','唐','御定全唐诗','yuding','','[]','旅夢思遷次，窮愁有歎嗟。子鵝京口遠，粳米會稽賒。',48,'御定全唐詩/json/659.json','["旅夢思遷次，窮愁有歎嗟。子鵝京口遠，粳米會稽賒。", "漏澀才成滴，燈寒不作花。出門聊一望，蟾桂向人斜。"]'),
('yuding-40','秋寄張坤','羅隱','唐','御定全唐诗','yuding','','[]','庭樹已黃落，閉門俱寂寥。未知棲托處，空羨聖明朝。',48,'御定全唐詩/json/659.json','["庭樹已黃落，閉門俱寂寥。未知棲托處，空羨聖明朝。", "酒醒鄉心闊，雲晴客思遙。吾徒自多感，顏子只簞瓢。"]'),
('yuding-41','傷華髮','羅隱','唐','御定全唐诗','yuding','','[]','舊國迢迢遠，清秋種種新。已衰曾軫慮，初見忽沾巾。',48,'御定全唐詩/json/659.json','["舊國迢迢遠，清秋種種新。已衰曾軫慮，初見忽沾巾。", "日薄梳兼懶，根危鑷恐頻。青銅不自見，只擬老他人。"]'),
('yuding-42','九江早秋','羅隱','唐','御定全唐诗','yuding','','[]','雨過晚涼生，樓中枕簟清。海風吹亂木，岩磬落孤城。',48,'御定全唐詩/json/659.json','["雨過晚涼生，樓中枕簟清。海風吹亂木，岩磬落孤城。", "百歲幾多日，四蹄無限程。西鄰莫高唱，俱是別離情。"]'),
('yuding-43','初秋寄友人','羅隱','唐','御定全唐诗','yuding','','[]','九華曾屏跡，罹亂與心違。是處堪終老，新秋又未歸。',48,'御定全唐詩/json/659.json','["九華曾屏跡，罹亂與心違。是處堪終老，新秋又未歸。", "病中芳草歇，愁裏白雲飛。樵侶兼同志，音書近亦稀。"]'),
('yuding-44','秋居有寄','羅隱','唐','御定全唐诗','yuding','','[]','端居湖岸東，生計有無中。魘處千般鬼，寒時百種風。',48,'御定全唐詩/json/659.json','["端居湖岸東，生計有無中。魘處千般鬼，寒時百種風。", "性靈從道拙，心事奈成空。多謝金台客，何當一笑同。"]'),
('yuding-45','雪霽','羅隱','唐','御定全唐诗','yuding','','[]','南山雪乍晴，寒氣轉崢嶸。鎖卻閑門出，隨他駿馬行。',48,'御定全唐詩/json/659.json','["南山雪乍晴，寒氣轉崢嶸。鎖卻閑門出，隨他駿馬行。", "一竿如有計，五鼎豈須烹。愁見天街草，青青又欲生。"]'),
('yuding-46','堠子','羅隱','唐','御定全唐诗','yuding','','[]','終日路岐旁，前程亦可量。未能慚面黑，只是恨頭方。',48,'御定全唐詩/json/659.json','["終日路岐旁，前程亦可量。未能慚面黑，只是恨頭方。", "雅旨逾千里，高文近兩行。君知不識字，第一莫形相。"]'),
('yuding-47','初夏寄顧紹宗','羅隱','唐','御定全唐诗','yuding','','[]','江上偶分袂，四回寒暑更。青山無路入，白髮滿頭生。',48,'御定全唐詩/json/659.json','["江上偶分袂，四回寒暑更。青山無路入，白髮滿頭生。", "郢浦雁尋過，鏡湖蟬又鳴。憐君未歸日，杯酒若為情。"]'),
('yuding-48','寄第五尊師','羅隱','唐','御定全唐诗','yuding','','[]','苕溪煙月久因循，野鶴衣裘獨繭綸。只說泊船無定處，',40,'御定全唐詩/json/659.json','["苕溪煙月久因循，野鶴衣裘獨繭綸。只說泊船無定處，", "欲訪先生問經訣，世間難得不由身。"]'),
('yuding-49','寄西華黃煉師','羅隱','唐','御定全唐诗','yuding','','[]','西華有路入中華，依約山川認永嘉。羽客昔時留筱簜，',40,'御定全唐詩/json/659.json','["西華有路入中華，依約山川認永嘉。羽客昔時留筱簜，", "盛事兩般君總得，老萊衣服戴顒家。"]'),
('yuding-50','所思','羅隱','唐','御定全唐诗','yuding','','[]','西上青雲未有期，東歸滄海一何遲。酒闌夢覺不稱意，',40,'御定全唐詩/json/659.json','["西上青雲未有期，東歸滄海一何遲。酒闌夢覺不稱意，", "鬥雞走狗五陵道，惆悵輸他輕薄兒。"]'),
('yuding-0','送支使蕭中丞赴闕','羅隱','唐','御定全唐诗','yuding','','[]','八年刀筆到京華，歸去青冥路未賒。今日風流卿相客，',40,'御定全唐詩/json/660.json','["八年刀筆到京華，歸去青冥路未賒。今日風流卿相客，", "從此常僚如有問，海邊麋鹿鬥邊槎。"]'),
('yuding-1','送人歸湘中兼寄舊知','羅隱','唐','御定全唐诗','yuding','','[]','青溪煙雨九華山，亂後應同夢寐間。萬里分飛休掩袂，',40,'御定全唐詩/json/660.json','["青溪煙雨九華山，亂後應同夢寐間。萬里分飛休掩袂，", "為謝伏波筵上客，幾時金印擬西還。"]'),
('yuding-2','自貽','羅隱','唐','御定全唐诗','yuding','','[]','衰老應難更進趨，藥畦經卷自朝晡。縱無顯效亦藏拙，',40,'御定全唐詩/json/660.json','["衰老應難更進趨，藥畦經卷自朝晡。縱無顯效亦藏拙，", "如何只見丁家鶴，依舊遼東歎綠蕪。"]'),
('yuding-3','暇日感懷因寄同院吳蛻拾遺','羅隱','唐','御定全唐诗','yuding','','[]','璧池清秩訪燕台，曾捧瀛洲劄翰來。今日二難俱大夜，',40,'御定全唐詩/json/660.json','["璧池清秩訪燕台，曾捧瀛洲劄翰來。今日二難俱大夜，", "猶幸小蘭同舍在，每因相見即銜哀。"]'),
('yuding-4','偶興','羅隱','唐','御定全唐诗','yuding','','[]','逐隊隨行二十春，曲江池畔避車塵。',32,'御定全唐詩/json/660.json','["逐隊隨行二十春，曲江池畔避車塵。", "如今贏得將衰老，閑看人間得意人。"]'),
('yuding-5','題鑿石山僧院','羅隱','唐','御定全唐诗','yuding','','[]','日夜潮聲送是非，一回登眺一忘機。',32,'御定全唐詩/json/660.json','["日夜潮聲送是非，一回登眺一忘機。", "憐師好事無人見，不把蘭芽染褐衣。"]'),
('yuding-6','圉城偶作','羅隱','唐','御定全唐诗','yuding','','[]','東望陳留日欲曛，每因刀筆想夫君。',32,'御定全唐詩/json/660.json','["東望陳留日欲曛，每因刀筆想夫君。", "自從郭泰碑銘後，只見黃金不見文。"]'),
('yuding-7','烏程','羅隱','唐','御定全唐诗','yuding','','[]','兩府攀陪十五年，郡中甘雨幕中蓮。',32,'御定全唐詩/json/660.json','["兩府攀陪十五年，郡中甘雨幕中蓮。", "一瓶猶是烏程酒，須對霜風度泫然。"]'),
('yuding-8','送楊煉師卻歸貞浩岩','羅隱','唐','御定全唐诗','yuding','','[]','宦途不復更經營，歸去東南任意行。別後幾回思會面，',40,'御定全唐詩/json/660.json','["宦途不復更經營，歸去東南任意行。別後幾回思會面，", "為謝佯狂吳道士，耳中時有鐵船聲。"]'),
('yuding-9','暇日投錢尚父','羅隱','唐','御定全唐诗','yuding','','[]','牛鬥星邊女宿間，棟樑虛敞麗江關。望高漢相東西閣，',40,'御定全唐詩/json/660.json','["牛鬥星邊女宿間，棟樑虛敞麗江關。望高漢相東西閣，", "自慚麋鹿無能事，未報深恩鬢已斑。"]'),
('yuding-10','覽晉史','羅隱','唐','御定全唐诗','yuding','','[]','齊王僚屬好男兒，偶覓東歸便得歸。滿目路岐拋似夢，',40,'御定全唐詩/json/660.json','["齊王僚屬好男兒，偶覓東歸便得歸。滿目路岐拋似夢，", "惆悵途中無限事，與君千載兩忘機。"]'),
('yuding-11','感別元帥尚父','羅隱','唐','御定全唐诗','yuding','','[]','玉函瑤檢下臺司，記得當時捧領時。半壁龍蛇蟠造化，',40,'御定全唐詩/json/660.json','["玉函瑤檢下臺司，記得當時捧領時。半壁龍蛇蟠造化，", "稚子不才身抱疾，日窺貞跡淚雙垂。"]'),
('yuding-12','尚父偶建小樓，特摛麗藻絕句不敢稱揚三首','羅隱','唐','御定全唐诗','yuding','','[]','結構叨馮柱石才，敢期幢蓋此裴回。',96,'御定全唐詩/json/660.json','["結構叨馮柱石才，敢期幢蓋此裴回。", "陽春曲調高誰和，盡日焚香倚隗台。", "玳簪珠履愧非才，時憑闌幹首重回。", "只待淮妖剪除後，別傾卮酒賀行台。", "闌檻初成愧楚才，不知星彩尚迂回。", "風流孔令陶鈞外，猶記山妖逼小台。"]'),
('yuding-13','題玄同先生草堂三首','羅隱','唐','御定全唐诗','yuding','','[]','杳杳諸天路，蒼蒼大滌山。景輿留不得，毛節去應閑。',144,'御定全唐詩/json/660.json','["杳杳諸天路，蒼蒼大滌山。景輿留不得，毛節去應閑。", "相府舊知己，教門新啟關。太平匡濟術，流落在人間。", "先生訣行日，曾奉數行書。意密尋難會，情深恨有餘。", "石橋春暖後，句漏藥成初。珍重雲兼鶴，從來不定居。", "常時憶討論，歷歷事猶存。酒向餘杭盡，雲從大滌昏。", "往來無道侶，歸去有台恩。自此玄言絕，長應閉洞門。"]'),
('yuding-14','城西作','羅隱','唐','御定全唐诗','yuding','','[]','從軍無一事，終日掩空齋。道薄交遊少，才疏進取乖。',48,'御定全唐詩/json/660.json','["從軍無一事，終日掩空齋。道薄交遊少，才疏進取乖。", "野禽鳴聒耳，庭草綠侵階。幸自同樗櫟，何妨愜所懷。"]'),
('yuding-15','冬暮城西晚眺','羅隱','唐','御定全唐诗','yuding','','[]','謬忝蓮華幕，虛沾柏署官。欹危長抱疾，衰老不禁寒。',48,'御定全唐詩/json/660.json','["謬忝蓮華幕，虛沾柏署官。欹危長抱疾，衰老不禁寒。", "時事已日過，世途行轉難。千崖兼萬壑，只向望中看。"]'),
('yuding-16','秋霽後','羅隱','唐','御定全唐诗','yuding','','[]','淨碧山光冷，圓明露點勻。渚蓮丹臉恨，堤柳翠眉顰。',48,'御定全唐詩/json/660.json','["淨碧山光冷，圓明露點勻。渚蓮丹臉恨，堤柳翠眉顰。", "蟬已送行客，雁應辭主人。蠅蚊漸無況，日晚自相親。"]'),
('yuding-17','茅齋','羅隱','唐','御定全唐诗','yuding','','[]','從事不從事，養生非養生。職為屍祿本，官是受恩名。',48,'御定全唐詩/json/660.json','["從事不從事，養生非養生。職為屍祿本，官是受恩名。", "時態已相失，歲華徒自驚。西齋一卮酒，衰老與誰傾。"]'),
('yuding-18','使者','羅隱','唐','御定全唐诗','yuding','','[]','使者銜中旨，崎嶇萬里行。人心猶未革，天意似難明。',48,'御定全唐詩/json/660.json','["使者銜中旨，崎嶇萬里行。人心猶未革，天意似難明。", "四海霍光第，六宮張奉營。陪臣無以報，西望不勝情。"]'),
('yuding-19','途中逢劉知遠','羅隱','唐','御定全唐诗','yuding','','[]','吳楚煙波裏，巢由季孟間。只言無事貴，不道致身閑。',48,'御定全唐詩/json/660.json','["吳楚煙波裏，巢由季孟間。只言無事貴，不道致身閑。", "別渚蓮根斷，歸心桂樹頑。空勞鐘璞意，塵世隔函關。"]'),
('yuding-20','遁跡','羅隱','唐','御定全唐诗','yuding','','[]','遁跡知安住，沾襟欲奈何。朝廷猶禮樂，郡邑忍干戈。',48,'御定全唐詩/json/660.json','["遁跡知安住，沾襟欲奈何。朝廷猶禮樂，郡邑忍干戈。", "華馬憑誰問，胡塵自此多。因思漢明帝，中夜憶廉頗。"]'),
('yuding-21','隴頭水','羅隱','唐','御定全唐诗','yuding','','[]','借問隴頭水，年年恨何事。全疑嗚咽聲，中有征人淚。',48,'御定全唐詩/json/660.json','["借問隴頭水，年年恨何事。全疑嗚咽聲，中有征人淚。", "自古無長策，況我非深智。何計謝潺湲，一宵空不寐。"]'),
('yuding-22','秦中富人','羅隱','唐','御定全唐诗','yuding','','[]','高高起華堂，區區引流水。糞土金玉珍，猶嫌未奢侈。',36,'御定全唐詩/json/660.json','["高高起華堂，區區引流水。糞土金玉珍，猶嫌未奢侈。", "陋巷滿蓬蒿，誰知有顏子。"]'),
('yuding-23','思歸行','羅隱','唐','御定全唐诗','yuding','','[]','不耕南畝田，為愛東堂桂。身同樹上花，一落又經歲。',48,'御定全唐詩/json/660.json','["不耕南畝田，為愛東堂桂。身同樹上花，一落又經歲。", "交親亦相薄，知己恩潛替。日開十二門，自是無歸計。"]'),
('yuding-24','即事中元甲子','羅隱','唐','御定全唐诗','yuding','','[]','三秦流血已成川，塞上黃雲戰馬閑。只有羸兵填渭水，',40,'御定全唐詩/json/660.json','["三秦流血已成川，塞上黃雲戰馬閑。只有羸兵填渭水，", "惆悵翠華猶未返，淚痕空滴劍文斑。"]'),
('yuding-25','魏城逢故人','羅隱','唐','御定全唐诗','yuding','','[]','一年兩度錦江遊，前值東風後值秋。芳草有情皆礙馬，',40,'御定全唐詩/json/660.json','["一年兩度錦江遊，前值東風後值秋。芳草有情皆礙馬，", "今日因君試回首，淡煙喬木隔綿州。"]'),
('yuding-26','游江夏口','羅隱','唐','御定全唐诗','yuding','','[]','醉別江東酒一杯，往年曾此駐塵埃。魚聽建業歌聲過，',40,'御定全唐詩/json/660.json','["醉別江東酒一杯，往年曾此駐塵埃。魚聽建業歌聲過，", "平生膽氣平生恨，今日江邊首懶回。"]'),
('yuding-27','春思','羅隱','唐','御定全唐诗','yuding','','[]','蕩漾春風淥似波，惹情搖恨去傞傞。燕翻永日音聲好，',40,'御定全唐詩/json/660.json','["蕩漾春風淥似波，惹情搖恨去傞傞。燕翻永日音聲好，", "可憐戶外桃兼李，仲蔚蓬蒿奈爾何。"]'),
('yuding-28','黃鶴驛寓題','羅隱','唐','御定全唐诗','yuding','','[]','野雲芳草繞離鞭，敢對青樓倚少年。秋色未催榆塞雁，',40,'御定全唐詩/json/660.json','["野雲芳草繞離鞭，敢對青樓倚少年。秋色未催榆塞雁，", "車馬同歸莫同恨，古人頭白盡林泉。"]'),
('yuding-29','安陸贈徐礪','羅隱','唐','御定全唐诗','yuding','','[]','靈蛇橋下水聲聲，曾向橋邊話別情。一榻偶依陳太守，',40,'御定全唐詩/json/660.json','["靈蛇橋下水聲聲，曾向橋邊話別情。一榻偶依陳太守，", "還把餘杯重相勸，不堪秋色背鄖城。"]'),
('yuding-30','寄鐘常侍','羅隱','唐','御定全唐诗','yuding','','[]','一從朱履步金台，蘖苦冰寒奉上臺。峻節不由人學得，',40,'御定全唐詩/json/660.json','["一從朱履步金台，蘖苦冰寒奉上臺。峻節不由人學得，", "應笑樟亭舊同舍，九州無驗滿爐灰。"]'),
('yuding-31','中秋夜不見月','羅隱','唐','御定全唐诗','yuding','','[]','陰雲薄暮上空虛，此夕清光已破除。',32,'御定全唐詩/json/660.json','["陰雲薄暮上空虛，此夕清光已破除。", "只恐異時開霽後，玉輪依舊養蟾蜍。"]'),
('yuding-32','魏博羅令公附卷有回','羅隱','唐','御定全唐诗','yuding','','[]','寒門雖得在諸宗，棲北巢南恨不同。馬上固慚消髀肉，',40,'御定全唐詩/json/660.json','["寒門雖得在諸宗，棲北巢南恨不同。馬上固慚消髀肉，", "深荷吾宗有知己，好將刀筆為英雄。"]'),
('yuding-33','寄處默師','羅隱','唐','御定全唐诗','yuding','','[]','甘露捲簾看雨腳，樟亭倚柱望潮頭。十年顧我醉中過，',40,'御定全唐詩/json/660.json','["甘露捲簾看雨腳，樟亭倚柱望潮頭。十年顧我醉中過，", "香爐煙靄虎溪月，終棹鐵船尋惠休。"]'),
('yuding-34','病中上錢尚父','羅隱','唐','御定全唐诗','yuding','','[]','左腳方行右臂攣，每慚名跡汙賓筵。縱饒吳土容衰病，',40,'御定全唐詩/json/660.json','["左腳方行右臂攣，每慚名跡汙賓筵。縱饒吳土容衰病，", "深恩重德無言處，回首浮生淚泫然。"]'),
('yuding-0','送梅處士歸甯國','羅隱','唐','御定全唐诗','yuding','','[]','十五年前即別君，別時天下未紛紜。亂罹且喜身俱在，',40,'御定全唐詩/json/661.json','["十五年前即別君，別時天下未紛紜。亂罹且喜身俱在，", "殷勤為謝逃名客，想望千秋嶺上雲。"]'),
('yuding-1','經故友所居','羅隱','唐','御定全唐诗','yuding','','[]','槐花漠漠向人黃，此地追遊跡已荒。清論不知莊叟達，',40,'御定全唐詩/json/661.json','["槐花漠漠向人黃，此地追遊跡已荒。清論不知莊叟達，", "日暮街東策羸馬，一聲橫笛似山陽。"]'),
('yuding-2','大樑從事居汜水','羅隱','唐','御定全唐诗','yuding','','[]','前年帝裏望行塵，記得仙家第四人。泉暖舊諳龍偃息，',40,'御定全唐詩/json/661.json','["前年帝裏望行塵，記得仙家第四人。泉暖舊諳龍偃息，", "知有篋中編集在，只應從此是經綸。"]'),
('yuding-3','杜處士新居','羅隱','唐','御定全唐诗','yuding','','[]','翠斂王孫草，荒誅宋玉茅。寇餘無故物，時薄少深交。',48,'御定全唐詩/json/661.json','["翠斂王孫草，荒誅宋玉茅。寇餘無故物，時薄少深交。", "迸筍穿行徑，饑雛出壞巢。小園吾亦有，多病近來拋。"]'),
('yuding-4','絕境','羅隱','唐','御定全唐诗','yuding','','[]','絕境非身事，流年但物華。水梳苔發直，風引蕙心斜。',48,'御定全唐詩/json/661.json','["絕境非身事，流年但物華。水梳苔發直，風引蕙心斜。", "凡客從題鳳，膚音未勝蛙。小船兼有槳，始與問漁家。"]'),
('yuding-5','雪中懷友人','羅隱','唐','御定全唐诗','yuding','','[]','臘酒複臘雪，故人今越鄉。所思誰把盞，端坐恨無航。',48,'御定全唐詩/json/661.json','["臘酒複臘雪，故人今越鄉。所思誰把盞，端坐恨無航。", "兔苑舊遊盡，龜台仙路長。未知鄒孟子，何以奉梁王。"]'),
('yuding-6','秋晚','羅隱','唐','御定全唐诗','yuding','','[]','宰邑慚良術，為文愧壯圖。縱饒長委命，爭奈漸非夫。',48,'御定全唐詩/json/661.json','["宰邑慚良術，為文愧壯圖。縱饒長委命，爭奈漸非夫。", "杯酒有時有，亂罹無處無。金庭在何域，回首一踟躕。"]'),
('yuding-7','升仙橋','羅隱','唐','御定全唐诗','yuding','','[]','危梁枕路岐，駐馬問前時。價自友朋得，名因婦女知。',48,'御定全唐詩/json/661.json','["危梁枕路岐，駐馬問前時。價自友朋得，名因婦女知。", "直須論運命，不得逞文詞。執戟君鄉里，榮華竟若為。"]'),
('yuding-8','姑蘇真娘墓','羅隱','唐','御定全唐诗','yuding','','[]','春草荒墳墓，萋萋向虎丘。死猶嫌寂寞，生肯不風流。',48,'御定全唐詩/json/661.json','["春草荒墳墓，萋萋向虎丘。死猶嫌寂寞，生肯不風流。", "皎鏡山泉冷，輕裾海霧秋。還應伴西子，香徑夜深遊。"]'),
('yuding-9','靈山寺','羅隱','唐','御定全唐诗','yuding','','[]','晚景聊攄抱，憑欄幾蕩魂。檻虛從四面，江闊奈孤根。',48,'御定全唐詩/json/661.json','["晚景聊攄抱，憑欄幾蕩魂。檻虛從四面，江闊奈孤根。", "幽徑薜蘿色，小山苔蘚痕。欲依師問道，何處系心猿。"]'),
('yuding-10','倚棹','羅隱','唐','御定全唐诗','yuding','','[]','倚棹聽鄰笛，沾衣認酒壚。自緣悲巨室，誰複為窮途。',48,'御定全唐詩/json/661.json','["倚棹聽鄰笛，沾衣認酒壚。自緣悲巨室，誰複為窮途。", "樹解將軍夢，城遺禦史烏。直應齊始了，傾酌向寒蕪。"]'),
('yuding-11','秋夕對月','羅隱','唐','御定全唐诗','yuding','','[]','夜月色可掬，倚樓聊解顏。未能分寇盜，徒欲滿關山。',48,'御定全唐詩/json/661.json','["夜月色可掬，倚樓聊解顏。未能分寇盜，徒欲滿關山。", "背冷金蟾滑，毛寒玉兔頑。姮娥謾偷藥，長寡老中閑。"]'),
('yuding-12','寄征士魏員外','羅隱','唐','御定全唐诗','yuding','','[]','家遁蘇門節，清貧粉署官。不矜朝命重，只恨路行難。',48,'御定全唐詩/json/661.json','["家遁蘇門節，清貧粉署官。不矜朝命重，只恨路行難。", "窗曉雞譚倦，庭秋蝶夢闌。羨君歸未得，還有釣魚竿。"]'),
('yuding-13','宿彭蠡館','羅隱','唐','御定全唐诗','yuding','','[]','孤館少行旅，解鞍增別愁。遠山矜薄暮，高柳怯清秋。',48,'御定全唐詩/json/661.json','["孤館少行旅，解鞍增別愁。遠山矜薄暮，高柳怯清秋。", "病裏見時態，醉中思舊遊。所懷今已矣，何必恨東流。"]'),
('yuding-14','螢','羅隱','唐','御定全唐诗','yuding','','[]','空庭夜未央，點點度西牆。抱影何微細，乘時忽發揚。',48,'御定全唐詩/json/661.json','["空庭夜未央，點點度西牆。抱影何微細，乘時忽發揚。", "不思因腐草，便擬倚孤光。若道能通照，車公業肯長。"]'),
('yuding-15','早秋宿葉墮所居','羅隱','唐','御定全唐诗','yuding','','[]','池荷葉正圓，長曆報時殫。曠野雲蒸熱，空庭雨始寒。',48,'御定全唐詩/json/661.json','["池荷葉正圓，長曆報時殫。曠野雲蒸熱，空庭雨始寒。", "蠅蚊猶得志，簟席若為安。浮世知誰是，勞歌共一歡。"]'),
('yuding-16','蝶','羅隱','唐','御定全唐诗','yuding','','[]','漢王刀筆精，寫爾逼天生。舞巧何妨急，飛高所恨輕。',48,'御定全唐詩/json/661.json','["漢王刀筆精，寫爾逼天生。舞巧何妨急，飛高所恨輕。", "野田黃雀慮，山館主人情。此物那堪作，莊周夢不成。"]'),
('yuding-17','春居','羅隱','唐','御定全唐诗','yuding','','[]','春風百卉搖，舊國路迢迢。偶病成疏散，因貧得寂寥。',48,'御定全唐詩/json/661.json','["春風百卉搖，舊國路迢迢。偶病成疏散，因貧得寂寥。", "倚簾高柳弱，乘露小桃夭。春色常無處，村醪更一瓢。"]'),
('yuding-18','輕飆','羅隱','唐','御定全唐诗','yuding','','[]','輕飆掠晚莎，秋物慘關河。戰壘平時少，齋壇上處多。',48,'御定全唐詩/json/661.json','["輕飆掠晚莎，秋物慘關河。戰壘平時少，齋壇上處多。", "楚雖屈子重，漢亦憶廉頗。不及雲台議，空山老薜蘿。"]'),
('yuding-19','燕','羅隱','唐','御定全唐诗','yuding','','[]','不必嫌漂露，何妨養羽毛。漢妃金屋遠，盧女杏梁高。',48,'御定全唐詩/json/661.json','["不必嫌漂露，何妨養羽毛。漢妃金屋遠，盧女杏梁高。", "野迥雙飛急，煙晴對語勞。猶勝黃雀在，棲息是蓬蒿。"]'),
('yuding-20','陝西晚思','羅隱','唐','御定全唐诗','yuding','','[]','長途已自窮，此去更西東。樹色榮衰裏，人心往返中。',48,'御定全唐詩/json/661.json','["長途已自窮，此去更西東。樹色榮衰裏，人心往返中。", "別情流水急，歸夢故山空。莫忘交遊分，從來事一同。"]'),
('yuding-21','除夜寄張達','羅隱','唐','御定全唐诗','yuding','','[]','梅花已著眼，竹葉況粘唇。只此留殘歲，那堪憶故人。',48,'御定全唐詩/json/661.json','["梅花已著眼，竹葉況粘唇。只此留殘歲，那堪憶故人。", "亂罹書不遠，衰病日相親。江浦思歸意，明朝又一春。"]'),
('yuding-22','寄酬鄴王羅令公五首','羅隱','唐','御定全唐诗','yuding','','[]','營室東回蔭斥丘，少年承襲擁青油。坐調金鼎尊明主，',200,'御定全唐詩/json/661.json','["營室東回蔭斥丘，少年承襲擁青油。坐調金鼎尊明主，", "西園舊跡今應在，衰老無因奉勝遊。", "脈散源分曆幾朝，縱然官宦只卑僚。正憂末派淪滄海，", "良時難得吾宗少，應念寒門更寂寥。", "敢將衰弱附強宗，細算還緣血脈同。湘浦煙波無舊跡，", "珍重珠璣兼繡段，草玄堂下寄揚雄。", "水雲開霽立高亭，依約黎陽對福星。只見篇章矜鏤管，", "鶴發四垂煙閣遠，此生何處拜儀形。", "錦笈朱囊連複連，紫鸞飛下浙江邊。綃從海室奪煙霧，", "戴灣老圃根基薄，虛費工夫八十年。"]'),
('yuding-23','春日投錢塘元帥尚父二首','羅隱','唐','御定全唐诗','yuding','','[]','正憂衰老辱金台，敢望昭王顧問來。門外旌旗屯虎豹，',80,'御定全唐詩/json/661.json','["正憂衰老辱金台，敢望昭王顧問來。門外旌旗屯虎豹，", "若比紫髯分鼎足，未聞餘力有瓊瑰。", "征東幕府十三州，敢望非才忝上游。官秩已叨吳品職，", "一句黃河千載事，麥城王粲謾登樓。"]'),
('yuding-24','錢塘府亭','羅隱','唐','御定全唐诗','yuding','','[]','新恩別啟館娃宮，還拜吳王向此中。九牧土田周制在，',40,'御定全唐詩/json/661.json','["新恩別啟館娃宮，還拜吳王向此中。九牧土田周制在，", "更有寵光人未見，問安調膳盡三公。"]'),
('yuding-25','野狐泉','羅隱','唐','御定全唐诗','yuding','','[]','潏潏寒光濺路塵，相傳妖物此潛身。',32,'御定全唐詩/json/661.json','["潏潏寒光濺路塵，相傳妖物此潛身。", "又應改換皮毛後，何處人間作好人。"]'),
('yuding-26','宿紀南驛','羅隱','唐','御定全唐诗','yuding','','[]','策蹇南游憶楚朝，陰風淅淅樹蕭蕭。',32,'御定全唐詩/json/661.json','["策蹇南游憶楚朝，陰風淅淅樹蕭蕭。", "不知無忌奸邪骨，又作何山野葛苗。"]'),
('yuding-27','贈無相禪師','羅隱','唐','御定全唐诗','yuding','','[]','人人盡道事空王，心裏忙於市井忙。',32,'御定全唐詩/json/661.json','["人人盡道事空王，心裏忙於市井忙。", "惟有馬當山上客，死門生路兩相忘。"]'),
('yuding-28','遣興','羅隱','唐','御定全唐诗','yuding','','[]','青雲路不通，歸計奈長蒙。老恐醫方誤，窮憂酒醆空。',48,'御定全唐詩/json/661.json','["青雲路不通，歸計奈長蒙。老恐醫方誤，窮憂酒醆空。", "何堪罹亂後，更入是非中。長短遭譏笑，回頭避釣翁。"]'),
('yuding-29','江夏酬高崇節','羅隱','唐','御定全唐诗','yuding','','[]','臘雪都堂試，春風汴水行。十年雖抱疾，何處不無情。',48,'御定全唐詩/json/661.json','["臘雪都堂試，春風汴水行。十年雖抱疾，何處不無情。", "群盜正當路，此游應隔生。勞君問流落，山下已躬耕。"]'),
('yuding-30','鶯聲','羅隱','唐','御定全唐诗','yuding','','[]','井上梧桐暗，花間霧露晞。一枝晴複暖，百囀是兼非。',48,'御定全唐詩/json/661.json','["井上梧桐暗，花間霧露晞。一枝晴複暖，百囀是兼非。", "金屋夢初覺，玉關人未歸。不堪閑日聽，因爾又沾衣。"]'),
('yuding-31','仿玉台體','羅隱','唐','御定全唐诗','yuding','','[]','青樓枕路隅，壁甃複椒塗。晚夢通簾柙，春寒逼酒壚。',48,'御定全唐詩/json/661.json','["青樓枕路隅，壁甃複椒塗。晚夢通簾柙，春寒逼酒壚。", "解吟憐芍藥，難見恨菖蒲。試問年多少，鄰姬亦姓胡。"]'),
('yuding-0','夜泊義興戲呈邑宰','羅隱','唐','御定全唐诗','yuding','','[]','溪畔維舟問戴星，此中三害有圖經。',32,'御定全唐詩/json/662.json','["溪畔維舟問戴星，此中三害有圖經。", "長橋可避南山遠，卻恐難防是最靈。"]'),
('yuding-1','聽琵琶','羅隱','唐','御定全唐诗','yuding','','[]','香筵酒散思朝散，偶向梧桐暗處聞。',32,'御定全唐詩/json/662.json','["香筵酒散思朝散，偶向梧桐暗處聞。", "大底曲中皆有恨，滿樓人自不知君。"]'),
('yuding-2','經耒陽杜工部墓','羅隱','唐','御定全唐诗','yuding','','[]','紫菊馨香覆楚醪，奠君江畔雨蕭騷。旅魂自是才相累，',40,'御定全唐詩/json/662.json','["紫菊馨香覆楚醪，奠君江畔雨蕭騷。旅魂自是才相累，", "屈原宋玉鄰君處，幾駕青螭緩郁陶。"]'),
('yuding-3','題袁溪張逸人所居','羅隱','唐','御定全唐诗','yuding','','[]','蒲梢獵獵燕差差，數裏溪光日落時。芳樹文君機上錦，',40,'御定全唐詩/json/662.json','["蒲梢獵獵燕差差，數裏溪光日落時。芳樹文君機上錦，", "若使浮名拘絆得，世間何處有男兒。"]'),
('yuding-4','升平公主舊第','羅隱','唐','御定全唐诗','yuding','','[]','乘鳳仙人降此時，玉篇才罷到文詞。兩輪水磑光明照，',40,'御定全唐詩/json/662.json','["乘鳳仙人降此時，玉篇才罷到文詞。兩輪水磑光明照，", "壇場客散香街暝，惆悵齊竽取次吹。"]'),
('yuding-5','寄黔中王從事','羅隱','唐','御定全唐诗','yuding','','[]','故人刀筆事軍書，南轉黔江半月餘。別後鄉關情幾許，',40,'御定全唐詩/json/662.json','["故人刀筆事軍書，南轉黔江半月餘。別後鄉關情幾許，", "今日舉觴君莫問，生涯牢落鬢蕭疏。"]'),
('yuding-6','關亭春望','羅隱','唐','御定全唐诗','yuding','','[]','關畔春雲拂馬頭，馬前春事共悠悠。風搖岸柳長條困，',40,'御定全唐詩/json/662.json','["關畔春雲拂馬頭，馬前春事共悠悠。風搖岸柳長條困，", "未知至竟將何用，渭水涇川一向流。"]'),
('yuding-7','寄徐濟進士','羅隱','唐','御定全唐诗','yuding','','[]','往年疏懶共江湖，月滿花香記得無。霜壓楚蓮秋後折，',40,'御定全唐詩/json/662.json','["往年疏懶共江湖，月滿花香記得無。霜壓楚蓮秋後折，", "出得函關抽得手，從來不及阮元瑜。"]'),
('yuding-8','寄韋贍','羅隱','唐','御定全唐诗','yuding','','[]','石城蓑笠阻心期，落盡山花有所思。羸馬二年蓬轉後，',40,'御定全唐詩/json/662.json','["石城蓑笠阻心期，落盡山花有所思。羸馬二年蓬轉後，", "禪智闌幹市橋酒，縱然相見只相悲。"]'),
('yuding-9','霅溪晚泊寄裴庶子','羅隱','唐','御定全唐诗','yuding','','[]','溪風如扇雨如絲，閒步閑吟柳惲詩。杯酒疏狂非曩日，',40,'御定全唐詩/json/662.json','["溪風如扇雨如絲，閒步閑吟柳惲詩。杯酒疏狂非曩日，", "滿眼雲山莫相笑，與君俱是受深知。"]'),
('yuding-10','送姚安之赴任秋浦','羅隱','唐','御定全唐诗','yuding','','[]','官罷春坊地象雷，片帆高指貴池開。五侯水暖魚鱗去，',40,'御定全唐詩/json/662.json','["官罷春坊地象雷，片帆高指貴池開。五侯水暖魚鱗去，", "到頭稱意須年少，贏得時光向酒杯。"]'),
('yuding-11','寄喬逸人','羅隱','唐','御定全唐诗','yuding','','[]','南經湘浦北揚州，別後風帆幾度遊。春酒誰家禁爛漫，',40,'御定全唐詩/json/662.json','["南經湘浦北揚州，別後風帆幾度遊。春酒誰家禁爛漫，", "長短此行須入手，更饒君占一年秋。"]'),
('yuding-12','塞外','羅隱','唐','御定全唐诗','yuding','','[]','塞外偷兒塞內兵，聖君宵旰望升平。碧幢未作朝廷計，',40,'御定全唐詩/json/662.json','["塞外偷兒塞內兵，聖君宵旰望升平。碧幢未作朝廷計，", "漢王第宅秦田土，今日將軍已自榮。"]'),
('yuding-13','裴庶子除太僕卿因賀','羅隱','唐','御定全唐诗','yuding','','[]','楚珪班序未為輕，莫惜良途副聖明。宮省舊推皇甫謐，',40,'御定全唐詩/json/662.json','["楚珪班序未為輕，莫惜良途副聖明。宮省舊推皇甫謐，", "應笑馬安虛巧宦，四回遷轉始為卿。"]'),
('yuding-14','詠史','羅隱','唐','御定全唐诗','yuding','','[]','蠹簡遺編試一尋，寂寥前事似如今。徐陵筆硯珊瑚架，',40,'御定全唐詩/json/662.json','["蠹簡遺編試一尋，寂寥前事似如今。徐陵筆硯珊瑚架，", "九原郝泚何由起，虛誤西蕃八尺金。"]'),
('yuding-15','中元夜泊淮口','羅隱','唐','御定全唐诗','yuding','','[]','木葉回飄水面平，偶因孤棹已三更。秋涼霧露侵燈下，',40,'御定全唐詩/json/662.json','["木葉回飄水面平，偶因孤棹已三更。秋涼霧露侵燈下，", "錦帆天子狂魂魄，應過揚州看月明。"]'),
('yuding-16','寄池州鄭員外','羅隱','唐','御定全唐诗','yuding','','[]','獸繞朱輪酒滿船，郡城蕭灑貴池邊。衣同萊子曾分筆，',40,'御定全唐詩/json/662.json','["獸繞朱輪酒滿船，郡城蕭灑貴池邊。衣同萊子曾分筆，", "陵陽百姓將何福，社舞村歌又一年。"]'),
('yuding-17','歸夢','羅隱','唐','御定全唐诗','yuding','','[]','陸海波濤漸漸深，一回歸夢抵千金。路傍草色休多事，',40,'御定全唐詩/json/662.json','["陸海波濤漸漸深，一回歸夢抵千金。路傍草色休多事，", "貪財敗陣誰相悉，鮑叔如今不可尋。"]'),
('yuding-18','送溪州使君','羅隱','唐','御定全唐诗','yuding','','[]','兵寇傷殘國力衰，就中南土藉良醫。鳳銜泥詔辭丹闕，',40,'御定全唐詩/json/662.json','["兵寇傷殘國力衰，就中南土藉良醫。鳳銜泥詔辭丹闕，", "灞橋酒醆黔巫月，從此江心兩所思。"]'),
('yuding-19','送霅川鄭員外','羅隱','唐','御定全唐诗','yuding','','[]','明時塞詔列分麾，東擁朱輪出帝畿。銅虎貴提天子印，',40,'御定全唐詩/json/662.json','["明時塞詔列分麾，東擁朱輪出帝畿。銅虎貴提天子印，", "知有掖垣南步在，可能須待政成歸。"]'),
('yuding-20','酬寄右司李員外','羅隱','唐','御定全唐诗','yuding','','[]','當年憶見桂枝春，自此清途未四旬。左省望高推健筆，',40,'御定全唐詩/json/662.json','["當年憶見桂枝春，自此清途未四旬。左省望高推健筆，", "猶把隨和向泥滓，應憐疏散任天真。"]'),
('yuding-21','蓮塘驛','羅隱','唐','御定全唐诗','yuding','','[]','蓮塘館東初日明，蓮塘館西行人行。隔林啼鳥似相應，',40,'御定全唐詩/json/662.json','["蓮塘館東初日明，蓮塘館西行人行。隔林啼鳥似相應，", "莫言來去只如此，君看鬢邊霜幾莖。"]'),
('yuding-22','甘露寺火後','羅隱','唐','御定全唐诗','yuding','','[]','六朝勝事已塵埃，猶有閒人悵望來。只道鬼神能護物，',40,'御定全唐詩/json/662.json','["六朝勝事已塵埃，猶有閒人悵望來。只道鬼神能護物，", "還識平泉故侯否，一生蹤跡比樓臺。"]'),
('yuding-23','春日登上元石頭故城','羅隱','唐','御定全唐诗','yuding','','[]','萬里傷心極目春，東南王氣只逡巡。野花相笑落滿地，',40,'御定全唐詩/json/662.json','["萬里傷心極目春，東南王氣只逡巡。野花相笑落滿地，", "太平寺主惟輕薄，卻把三公與賊臣。"]'),
('yuding-24','送宣武徐巡官','羅隱','唐','御定全唐诗','yuding','','[]','傲睨公卿二十年，東來西去只悠然。白知關畔元非馬，',40,'御定全唐詩/json/662.json','["傲睨公卿二十年，東來西去只悠然。白知關畔元非馬，", "臨行不惜刀圭便，愁殺長安買笑錢。"]'),
('yuding-25','冬暮寄裴郎中','羅隱','唐','御定全唐诗','yuding','','[]','曉發星星入鏡宜，早年容易近年悲。敢言得事時將晚，',40,'御定全唐詩/json/662.json','["曉發星星入鏡宜，早年容易近年悲。敢言得事時將晚，", "仙郎舊有黃金約，瀝膽隳肝更禱祈。"]'),
('yuding-26','中元甲子以辛醜駕幸蜀四首','羅隱','唐','御定全唐诗','yuding','','[]','子儀不起渾瑊亡，西幸誰人從武皇。四海為家雖未遠，',160,'御定全唐詩/json/662.json','["子儀不起渾瑊亡，西幸誰人從武皇。四海為家雖未遠，", "應感兩朝巡狩跡，綠槐端正驛荒涼。", "爪牙柱石兩俱銷，一點渝塵九土搖。敢恨甲兵為棄物，", "跪望嵕山重啟告，可能餘烈不勝妖。", "邪氣奔屯瑞氣移，清平過盡到艱危。縱饒犬彘迷常理，", "可憐一曲還京樂，重對紅蕉教蜀兒。", "白丁攘臂犯長安，翠輦蒼黃路屈盤。丹鳳有情塵外遠，", "不將不侯何計是，釣魚船上淚闌幹。"]'),
('yuding-27','題潤州妙善前石羊','羅隱','唐','御定全唐诗','yuding','','[]','紫髯桑蓋此沈吟，很石猶存事可尋。漢鼎未安聊把手，',40,'御定全唐詩/json/662.json','["紫髯桑蓋此沈吟，很石猶存事可尋。漢鼎未安聊把手，", "還有市鄽沽酒客，雀喧鳩聚話蹄涔。"]'),
('yuding-28','登宛陵條風樓寄竇常侍','羅隱','唐','御定全唐诗','yuding','','[]','亂罹時節懶登臨，試借條風半日吟。只有遠山含暖律，',40,'御定全唐詩/json/662.json','["亂罹時節懶登臨，試借條風半日吟。只有遠山含暖律，", "自笑疏慵似麋鹿，也教臺上費黃金。"]'),
('yuding-29','台城','羅隱','唐','御定全唐诗','yuding','','[]','晚雲陰映下空城，六代累累夕照明。玉井已幹龍不起，',40,'御定全唐詩/json/662.json','["晚雲陰映下空城，六代累累夕照明。玉井已幹龍不起，", "深谷作陵山作海，茂弘流輩莫傷情。"]'),
('yuding-30','甘露寺看雪上周相公','羅隱','唐','御定全唐诗','yuding','','[]','篩寒灑白亂溟蒙，禱請功兼造化功。光薄乍迷京口月，',40,'御定全唐詩/json/662.json','["篩寒灑白亂溟蒙，禱請功兼造化功。光薄乍迷京口月，", "一種為祥君看取，半禳災沴半年豐。"]'),
('yuding-31','寄京闕陸郎中昆仲','羅隱','唐','御定全唐诗','yuding','','[]','柏台蘭署四周旋，賓榻何妨雁影連。才見玳簪欹細柳，',40,'御定全唐詩/json/662.json','["柏台蘭署四周旋，賓榻何妨雁影連。才見玳簪欹細柳，", "爭奈亂罹人漸少，麥城新賦許誰傳。"]'),
('yuding-32','偶題','羅隱','唐','御定全唐诗','yuding','','[]','鐘陵醉別十餘春，重見雲英掌上身。',32,'御定全唐詩/json/662.json','["鐘陵醉別十餘春，重見雲英掌上身。", "我未成名君未嫁，可能俱是不如人。"]'),
('yuding-33','故都','羅隱','唐','御定全唐诗','yuding','','[]','江南江北兩風流，一作迷津一拜侯。',32,'御定全唐詩/json/662.json','["江南江北兩風流，一作迷津一拜侯。", "至竟不如隋煬帝，破家猶得到揚州。"]'),
('yuding-34','董仲舒','羅隱','唐','御定全唐诗','yuding','','[]','災變儒生不合聞，謾將刀筆指乾坤。',32,'御定全唐詩/json/662.json','["災變儒生不合聞，謾將刀筆指乾坤。", "偶然留得陰陽術，閉卻南門又北門。"]'),
('yuding-35','獻尚父大王','羅隱','唐','御定全唐诗','yuding','','[]','數年鐵甲定東甌，夜渡江山瞻鬥牛。',32,'御定全唐詩/json/662.json','["數年鐵甲定東甌，夜渡江山瞻鬥牛。", "今日朱方平殄後，虎符龍節十三州。"]'),
('yuding-36','蜂','羅隱','唐','御定全唐诗','yuding','','[]','不論平地與山尖，無限風光盡被占。',32,'御定全唐詩/json/662.json','["不論平地與山尖，無限風光盡被占。", "采得百花成蜜後，為誰辛苦為誰甜。"]'),
('yuding-37','簾二首','羅隱','唐','御定全唐诗','yuding','','[]','疊影重紋映畫堂，玉鉤銀燭共熒煌。',64,'御定全唐詩/json/662.json','["疊影重紋映畫堂，玉鉤銀燭共熒煌。", "會應得見神仙在，休下真珠十二行。", "翡翠佳名世共稀，玉堂高下巧相宜。", "殷勤為囑纖纖手，卷上銀鉤莫放垂。"]'),
('yuding-0','送顧雲下第','羅隱','唐','御定全唐诗','yuding','','[]','行行杯酒莫辭頻，怨歎勞歌兩未伸。漢帝后宮猶識字，',40,'御定全唐詩/json/663.json','["行行杯酒莫辭頻，怨歎勞歌兩未伸。漢帝后宮猶識字，", "百歲都來多幾日，不堪相別又傷春。"]'),
('yuding-1','村橋','羅隱','唐','御定全唐诗','yuding','','[]','村橋酒旆月明樓，偶逐漁舟系葉舟。莫學魯人疑海鳥，',40,'御定全唐詩/json/663.json','["村橋酒旆月明樓，偶逐漁舟系葉舟。莫學魯人疑海鳥，", "除卻思量太平在，肯拋疏散換公侯。"]'),
('yuding-2','送劉校書之新安寄吳常侍','羅隱','唐','御定全唐诗','yuding','','[]','野雲如火照行塵，會績溪邊去問津。才子省銜非幕客，',40,'御定全唐詩/json/663.json','["野雲如火照行塵，會績溪邊去問津。才子省銜非幕客，", "他日酒筵應見問，鹿裘漁艇隔朱輪。"]'),
('yuding-3','官池秋夕','羅隱','唐','御定全唐诗','yuding','','[]','池邊月影閑婆娑，池上醉來成短歌。芙渠抵死怨珠露，',40,'御定全唐詩/json/663.json','["池邊月影閑婆娑，池上醉來成短歌。芙渠抵死怨珠露，", "松醪作酒蘭為棹，十載煙塵奈爾何。"]'),
('yuding-4','奉使宛陵別二三從事','羅隱','唐','御定全唐诗','yuding','','[]','梁王雪裏有深知，偶別家鄉隔路岐。官品共傳勝曩日，',40,'御定全唐詩/json/663.json','["梁王雪裏有深知，偶別家鄉隔路岐。官品共傳勝曩日，", "還有釣魚蓑笠在，不堪風雨失歸期。"]'),
('yuding-5','金陵思古','羅隱','唐','御定全唐诗','yuding','','[]','杜秋在時花解言，杜秋死後花更繁。柔姿曼態葬何處，',40,'御定全唐詩/json/663.json','["杜秋在時花解言，杜秋死後花更繁。柔姿曼態葬何處，", "綺筵金縷無消息，一陣征帆過海門。"]'),
('yuding-6','送王使君赴蘇台','羅隱','唐','御定全唐诗','yuding','','[]','東南一望可長籲，猶憶王孫領虎符。兩地干戈連越絕，',40,'御定全唐詩/json/663.json','["東南一望可長籲，猶憶王孫領虎符。兩地干戈連越絕，", "料得伍員兼旅寓，不妨招取好揶揄。"]'),
('yuding-7','憶九華','羅隱','唐','御定全唐诗','yuding','','[]','九華巉崒蔭柴扉，長憶前時此息機。黃菊倚風村酒熟，',40,'御定全唐詩/json/663.json','["九華巉崒蔭柴扉，長憶前時此息機。黃菊倚風村酒熟，", "回首佳期恨多少，夜闌霜露又沾衣。"]'),
('yuding-8','送裴饒歸會稽','羅隱','唐','御定全唐诗','yuding','','[]','金庭路指剡川隈，珍重良朋自此來。兩鬢不堪悲歲月，',40,'御定全唐詩/json/663.json','["金庭路指剡川隈，珍重良朋自此來。兩鬢不堪悲歲月，", "笑殺山陰雪中客，等閒乘興又須回。"]'),
('yuding-9','送程尊師之晉陵','羅隱','唐','御定全唐诗','yuding','','[]','棟間雲出認行軒，郊外陰陰夏木繁。高道乍為張翰侶，',40,'御定全唐詩/json/663.json','["棟間雲出認行軒，郊外陰陰夏木繁。高道乍為張翰侶，", "莫見時危便乘興，人來何處不桃源。"]'),
('yuding-10','吳門晚泊寄句曲道友','羅隱','唐','御定全唐诗','yuding','','[]','采香徑在人不留，采香徑下停葉舟。桃花李花鬥紅白，',40,'御定全唐詩/json/663.json','["采香徑在人不留，采香徑下停葉舟。桃花李花鬥紅白，", "未知到了關身否，笑殺雷平許遠遊。"]'),
('yuding-11','貴池曉望','羅隱','唐','御定全唐诗','yuding','','[]','稂莠參天剪未平，且乘孤棹且行行。計疏狡兔無三窟，',40,'御定全唐詩/json/663.json','["稂莠參天剪未平，且乘孤棹且行行。計疏狡兔無三窟，", "前溪好泊誰為主，昨夜沙禽占月明。"]'),
('yuding-12','寄崔慶孫','羅隱','唐','御定全唐诗','yuding','','[]','故人何處又留連，月冷風高鏡水邊。文陣解圍才昨日，',40,'御定全唐詩/json/663.json','["故人何處又留連，月冷風高鏡水邊。文陣解圍才昨日，", "還擬山陰一乘興，雪寒難得渡江船。"]'),
('yuding-13','寄楊秘書','羅隱','唐','御定全唐诗','yuding','','[]','蕭蕭簷雪打窗聲，因憶江東阮步兵。兩信海潮書不達，',40,'御定全唐詩/json/663.json','["蕭蕭簷雪打窗聲，因憶江東阮步兵。兩信海潮書不達，", "會待與君開秫甕，滿船般載鏡中行。"]'),
('yuding-14','酬章處士見寄','羅隱','唐','御定全唐诗','yuding','','[]','中原甲馬未曾安，今日逢君事萬端。亂後幾回鄉夢隔，',40,'御定全唐詩/json/663.json','["中原甲馬未曾安，今日逢君事萬端。亂後幾回鄉夢隔，", "何必新詩更相戲，小樓吟罷暮天寒。"]'),
('yuding-15','送丁明府赴紫溪任','羅隱','唐','御定全唐诗','yuding','','[]','金徽玉軫肯躇躕，偶滯良途半月餘。樓上酒闌梅拆後，',40,'御定全唐詩/json/663.json','["金徽玉軫肯躇躕，偶滯良途半月餘。樓上酒闌梅拆後，", "縣譜莫辭留舊本，異時量度更何如。"]'),
('yuding-16','寄前宣州竇常侍','羅隱','唐','御定全唐诗','yuding','','[]','往年西謁謝玄暉，樽酒留歡醉始歸。曲檻柳濃鶯未老，',40,'御定全唐詩/json/663.json','["往年西謁謝玄暉，樽酒留歡醉始歸。曲檻柳濃鶯未老，", "今日亂罹尋不得，滿蓑風雨釣魚磯。"]'),
('yuding-17','秦望山僧院','羅隱','唐','御定全唐诗','yuding','','[]','巉巉危岫倚滄洲，聞說秦皇亦此遊。霸主卷衣才二世，',40,'御定全唐詩/json/663.json','["巉巉危岫倚滄洲，聞說秦皇亦此遊。霸主卷衣才二世，", "各是病來俱未了，莫將煩惱問湯休。"]'),
('yuding-18','送光祿崔卿赴闕','羅隱','唐','御定全唐诗','yuding','','[]','一年極目望西轅，此日殷勤聖主恩。上國已留虞寄命，',40,'御定全唐詩/json/663.json','["一年極目望西轅，此日殷勤聖主恩。上國已留虞寄命，", "鵷侶寂寥曹署冷，更堪嗚咽問田園。"]'),
('yuding-19','寄程尊師','羅隱','唐','御定全唐诗','yuding','','[]','鶴信雖然到五湖，煙波迢遞路崎嶇。玉書分薄花生眼，',40,'御定全唐詩/json/663.json','["鶴信雖然到五湖，煙波迢遞路崎嶇。玉書分薄花生眼，", "未知朽敗凡間骨，中授先生指教無。"]'),
('yuding-20','定遠樓','羅隱','唐','御定全唐诗','yuding','','[]','前年上將定妖氛，曾築岩城駐大軍。近日關防雖弛柝，',40,'御定全唐詩/json/663.json','["前年上將定妖氛，曾築岩城駐大軍。近日關防雖弛柝，", "唯恐亂來良吏少，不知誰解敘功勳。"]'),
('yuding-21','送程尊師東遊有寄','羅隱','唐','御定全唐诗','yuding','','[]','華蓋峰前擬卜耕，主人無奈又閑行。且憑鶴駕尋滄海，',40,'御定全唐詩/json/663.json','["華蓋峰前擬卜耕，主人無奈又閑行。且憑鶴駕尋滄海，", "勸君莫忘歸時節，芝似螢光處處生。"]'),
('yuding-22','江亭別裴饒','羅隱','唐','御定全唐诗','yuding','','[]','行杯且待怨歌終，多病憐君事事同。衰鬢別來光景裏，',40,'御定全唐詩/json/663.json','["行杯且待怨歌終，多病憐君事事同。衰鬢別來光景裏，", "日晚長亭問西使，不堪車馬尚萍蓬。"]'),
('yuding-23','江南寄所知周僕射','羅隱','唐','御定全唐诗','yuding','','[]','曾陪公子醉西園，峴首碑前事懶言。世亂共嗟王粲老，',40,'御定全唐詩/json/663.json','["曾陪公子醉西園，峴首碑前事懶言。世亂共嗟王粲老，", "飛蓋寂寥清宴罷，不知簪履更誰存。"]'),
('yuding-24','錢唐見芮逢','羅隱','唐','御定全唐诗','yuding','','[]','蔡倫池北雁峰前，罹亂相兼十九年。所喜故人猶會面，',40,'御定全唐詩/json/663.json','["蔡倫池北雁峰前，罹亂相兼十九年。所喜故人猶會面，", "今日與君贏得在，戴家灣裏兩皤然。"]'),
('yuding-25','江都','羅隱','唐','御定全唐诗','yuding','','[]','淮王高宴動江都，曾憶狂生亦坐隅。九裏樓臺牽翡翠，',40,'御定全唐詩/json/663.json','["淮王高宴動江都，曾憶狂生亦坐隅。九裏樓臺牽翡翠，", "惆悵晉陽星拆後，世間兵革地荒蕪。"]'),
('yuding-26','湖上歲暮感懷有寄友人','羅隱','唐','御定全唐诗','yuding','','[]','雪天螢席幾辛勤，同志當時四五人。蘭版地寒俱受露，',40,'御定全唐詩/json/663.json','["雪天螢席幾辛勤，同志當時四五人。蘭版地寒俱受露，", "唯有廣都龐令在，白頭樽酒憶交親。"]'),
('yuding-27','送張綰游鐘陵','羅隱','唐','御定全唐诗','yuding','','[]','南憶龍沙兩岸行，當時天下尚清平。醉眠野寺花方落，',40,'御定全唐詩/json/663.json','["南憶龍沙兩岸行，當時天下尚清平。醉眠野寺花方落，", "西山十二真人在，從此煩君語姓名。"]'),
('yuding-28','送z6光大師','羅隱','唐','御定全唐诗','yuding','','[]','禹祠分首戴灣逢，健筆尋知達九重。聖主賜衣憐絕藝，',40,'御定全唐詩/json/663.json','["禹祠分首戴灣逢，健筆尋知達九重。聖主賜衣憐絕藝，", "一種苦心師得了，不須回首笑龍鍾。"]'),
('yuding-29','息夫人廟','羅隱','唐','御定全唐诗','yuding','','[]','百雉摧殘連野青，廟門猶見昔朝廷。一生雖抱楚王恨，',40,'御定全唐詩/json/663.json','["百雉摧殘連野青，廟門猶見昔朝廷。一生雖抱楚王恨，", "玉顏渾似羞來客，依舊無言照畫屏。"]'),
('yuding-30','漂母塚','羅隱','唐','御定全唐诗','yuding','','[]','寂寂荒墳一水濱，蘆洲絕島自相親。青娥已落淮邊月，',40,'御定全唐詩/json/663.json','["寂寂荒墳一水濱，蘆洲絕島自相親。青娥已落淮邊月，", "雖然寂寞千秋魄，猶是韓侯舊主人。"]'),
('yuding-31','感懷','羅隱','唐','御定全唐诗','yuding','','[]','石徑松軒亦自由，謾隨浮世逐飄流。駑駘路結前程恨，',40,'御定全唐詩/json/663.json','["石徑松軒亦自由，謾隨浮世逐飄流。駑駘路結前程恨，", "雖教小事相催逼，未到青雲擬白頭。"]'),
('yuding-32','扇上畫牡丹','羅隱','唐','御定全唐诗','yuding','','[]','為愛紅芳滿砌階，教人扇上畫將來。葉隨彩筆參差長，',40,'御定全唐詩/json/663.json','["為愛紅芳滿砌階，教人扇上畫將來。葉隨彩筆參差長，", "根生無地如仙桂，疑是姮娥月裏栽。"]'),
('yuding-33','書懷','羅隱','唐','御定全唐诗','yuding','','[]','釣船拋卻異鄉來，擬向何門用不才。',32,'御定全唐詩/json/663.json','["釣船拋卻異鄉來，擬向何門用不才。", "日晚獨登樓上望，馬蹄車轍滿塵埃。"]'),
('yuding-34','七夕','羅隱','唐','御定全唐诗','yuding','','[]','月帳星房次第開，兩情惟恐曙光催。',32,'御定全唐詩/json/663.json','["月帳星房次第開，兩情惟恐曙光催。", "時人不用穿針待，沒得心情送巧來。"]'),
('yuding-35','柳','羅隱','唐','御定全唐诗','yuding','','[]','一簇青煙鎖玉樓，半垂闌畔半垂溝。',32,'御定全唐詩/json/663.json','["一簇青煙鎖玉樓，半垂闌畔半垂溝。", "明年更有新條在，繞亂春風卒未休。"]'),
('yuding-36','羅敷水','羅隱','唐','御定全唐诗','yuding','','[]','雉聲角角野田春，試駐征車問水濱。',32,'御定全唐詩/json/663.json','["雉聲角角野田春，試駐征車問水濱。", "數樹枯桑雖不語，思量應合識秦人。"]'),
('yuding-37','京中正月七日立春','羅隱','唐','御定全唐诗','yuding','','[]','一二三四五六七，萬木生芽是今日。',32,'御定全唐詩/json/663.json','["一二三四五六七，萬木生芽是今日。", "遠天歸雁拂雲飛，近水遊魚迸冰出。"]'),
('yuding-38','貴游','羅隱','唐','御定全唐诗','yuding','','[]','館陶園外雨初晴，繡轂香車入鳳城。',32,'御定全唐詩/json/663.json','["館陶園外雨初晴，繡轂香車入鳳城。", "八尺家僮三尺棰，何知高祖要蒼生。"]'),
('yuding-39','嚴陵灘','羅隱','唐','御定全唐诗','yuding','','[]','中都九鼎勤英髦，漁釣牛蓑且遁逃。',32,'御定全唐詩/json/663.json','["中都九鼎勤英髦，漁釣牛蓑且遁逃。", "世祖升遐夫子死，原陵不及釣台高。"]'),
('yuding-0','虛白堂前牡丹相傳雲太傅手植在錢塘','羅隱','唐','御定全唐诗','yuding','','[]','欲詢往事奈無言，六十年來托此根。香暖幾飄袁虎扇，',40,'御定全唐詩/json/664.json','["欲詢往事奈無言，六十年來托此根。香暖幾飄袁虎扇，", "莫背闌幹便相笑，與君俱受主人恩。"]'),
('yuding-1','縣齋秋晚酬友人朱瓚見寄','羅隱','唐','御定全唐诗','yuding','','[]','中和節後捧瓊瑰，坐讀行吟數月來。只歎雕龍方擅價，',40,'御定全唐詩/json/664.json','["中和節後捧瓊瑰，坐讀行吟數月來。只歎雕龍方擅價，", "惆悵報君無玉案，水天東望一裴回。"]'),
('yuding-2','第五將軍于餘杭天柱宮入道因題寄','羅隱','唐','御定全唐诗','yuding','','[]','交梨火棗味何如，聞說苕川已下車。瓦榼尚攜京口酒，',40,'御定全唐詩/json/664.json','["交梨火棗味何如，聞說苕川已下車。瓦榼尚攜京口酒，", "卻恐武皇還望祀，軟輪征入問玄虛。"]'),
('yuding-3','寄無相禪師','羅隱','唐','御定全唐诗','yuding','','[]','老住西峰第幾層，為師回首憶南能。有緣有相應非佛，',40,'御定全唐詩/json/664.json','["老住西峰第幾層，為師回首憶南能。有緣有相應非佛，", "何如一衲塵埃外，日日香煙夜夜燈。"]'),
('yuding-4','秋日有寄','羅隱','唐','御定全唐诗','yuding','','[]','丹青未合便回頭，見盡人間事始休。只有百神朝寶鏡，',40,'御定全唐詩/json/664.json','["丹青未合便回頭，見盡人間事始休。只有百神朝寶鏡，", "東去西來人不會，上卿蹤跡本玄洲。"]'),
('yuding-5','送前南昌崔令替任映攝新城縣','羅隱','唐','御定全唐诗','yuding','','[]','五年苛政甚蟲螟，深喜夫君已戴星。大族不唯專禮樂，',40,'御定全唐詩/json/664.json','["五年苛政甚蟲螟，深喜夫君已戴星。大族不唯專禮樂，", "二月春風何處好，亞夫營畔柳青青。"]'),
('yuding-6','下第作','羅隱','唐','御定全唐诗','yuding','','[]','年年模樣一般般，何似東歸把釣竿。岩谷謾勞思雨露，',40,'御定全唐詩/json/664.json','["年年模樣一般般，何似東歸把釣竿。岩谷謾勞思雨露，", "至竟窮途也須達，不能長與世人看。"]'),
('yuding-7','丁亥歲作','羅隱','唐','御定全唐诗','yuding','','[]','病想醫門渴望梅，十年心地僅成灰。早知世事長如此，',40,'御定全唐詩/json/664.json','["病想醫門渴望梅，十年心地僅成灰。早知世事長如此，", "滿城桃李君看取，一一還從舊處開。"]'),
('yuding-8','北邙山','羅隱','唐','御定全唐诗','yuding','','[]','一種山前路入秦，嵩山堪愛此傷神。魏明未死虛留意，',40,'御定全唐詩/json/664.json','["一種山前路入秦，嵩山堪愛此傷神。魏明未死虛留意，", "羨他緱嶺吹簫客，閑訪雲頭看俗塵。"]'),
('yuding-9','重過三衢哭孫員外','羅隱','唐','御定全唐诗','yuding','','[]','爛柯山下忍重到，雙檜樓前日欲殘。華屋未移春照灼，',40,'御定全唐詩/json/664.json','["爛柯山下忍重到，雙檜樓前日欲殘。華屋未移春照灼，", "一慟旁人莫相笑，知音衰盡路行難。"]'),
('yuding-10','送蘄州裴員外','羅隱','唐','御定全唐诗','yuding','','[]','六枝仙桂最先春，蕭灑高辭九陌塵。兩晉家聲須有主，',40,'御定全唐詩/json/664.json','["六枝仙桂最先春，蕭灑高辭九陌塵。兩晉家聲須有主，", "蘄水蒼生莫相羨，早看歸去掌絲綸。"]'),
('yuding-11','重九日廣陵道中','羅隱','唐','御定全唐诗','yuding','','[]','秋山抱病何處登，前時韋曲今廣陵。廣陵大醉不解悶，',40,'御定全唐詩/json/664.json','["秋山抱病何處登，前時韋曲今廣陵。廣陵大醉不解悶，", "卻驅羸馬向前去，牢落路岐非所能。"]'),
('yuding-12','東歸別所知','羅隱','唐','御定全唐诗','yuding','','[]','芙蓉宮闕二妃壇，兩處因依五歲寒。鄒律有風吹不變，',40,'御定全唐詩/json/664.json','["芙蓉宮闕二妃壇，兩處因依五歲寒。鄒律有風吹不變，", "卻羨淮南好雞犬，也能終始逐劉安。"]'),
('yuding-13','旅舍書懷寄所知二首','羅隱','唐','御定全唐诗','yuding','','[]','思量前事不堪尋，牢落餘情滿素琴。四海豈無騰躍路，',80,'御定全唐詩/json/664.json','["思量前事不堪尋，牢落餘情滿素琴。四海豈無騰躍路，", "寂寞誰應吊空館，異鄉時節獨沾襟。", "簟卷兩床琴瑟秋，暫憑前計奈相尤。塵飄馬尾甘蓬轉，", "可憐別恨無人見，獨背殘陽下寺樓。"]'),
('yuding-14','西京道中','羅隱','唐','御定全唐诗','yuding','','[]','半夜秋聲觸斷蓬，百年身事算成空。禰生詞賦拋江夏，',40,'御定全唐詩/json/664.json','["半夜秋聲觸斷蓬，百年身事算成空。禰生詞賦拋江夏，", "邊禽隴水休相笑，自有滄洲一棹風。"]'),
('yuding-15','粉','羅隱','唐','御定全唐诗','yuding','','[]','每持纖白助君時，霜自無憀雪自疑。郎若姓何應解傅，',40,'御定全唐詩/json/664.json','["每持纖白助君時，霜自無憀雪自疑。郎若姓何應解傅，", "最好玉京仙署裏，更和秋月照瓊枝。"]'),
('yuding-16','贈漁翁','羅隱','唐','御定全唐诗','yuding','','[]','葉艇悠揚鶴發垂，生涯空托一綸絲。是非不向眼前起，',40,'御定全唐詩/json/664.json','["葉艇悠揚鶴發垂，生涯空托一綸絲。是非不向眼前起，", "逍遙此意誰人會，應有青山淥水知。"]'),
('yuding-17','下第寄張坤','羅隱','唐','御定全唐诗','yuding','','[]','謾費精神掉五侯，破琴孤劍是身仇。九衢雙闕擬何去，',40,'御定全唐詩/json/664.json','["謾費精神掉五侯，破琴孤劍是身仇。九衢雙闕擬何去，", "思量不及張公子，經歲池江倚酒樓。"]'),
('yuding-18','東歸別常修','羅隱','唐','御定全唐诗','yuding','','[]','六載辛勤九陌中，卻尋歸路五湖東。名慚桂苑一枝綠，',40,'御定全唐詩/json/664.json','["六載辛勤九陌中，卻尋歸路五湖東。名慚桂苑一枝綠，", "唯慚鮑叔深知我，他日蒲帆百尺風。"]'),
('yuding-19','言','羅隱','唐','御定全唐诗','yuding','','[]','珪玷由來尚可磨，似簧終日複如何。成名成事皆因慎，',40,'御定全唐詩/json/664.json','["珪玷由來尚可磨，似簧終日複如何。成名成事皆因慎，", "猩猩鸚鵡無端解，長向人間被網羅。"]'),
('yuding-20','簡令生日','羅隱','唐','御定全唐诗','yuding','','[]','祥煙靄靄拂樓臺，慶積玄元節後來。已向青陽標四序，',40,'御定全唐詩/json/664.json','["祥煙靄靄拂樓臺，慶積玄元節後來。已向青陽標四序，", "自顧下儒何以祝，柱天功業濟時才。"]'),
('yuding-21','晚眺','羅隱','唐','御定全唐诗','yuding','','[]','憑古城邊眺晚晴，遠村高樹轉分明。天如鏡面都來靜，',40,'御定全唐詩/json/664.json','["憑古城邊眺晚晴，遠村高樹轉分明。天如鏡面都來靜，", "誰人得及莊居老，免被榮枯寵辱驚。"]'),
('yuding-22','野花','羅隱','唐','御定全唐诗','yuding','','[]','萬點紅芳血色殷，為無名字對空山。多因戲蝶尋香住，',40,'御定全唐詩/json/664.json','["萬點紅芳血色殷，為無名字對空山。多因戲蝶尋香住，", "結根必竟輸桃李，長向春城紫陌間。"]'),
('yuding-23','病驄馬','羅隱','唐','御定全唐诗','yuding','','[]','櫪上病驄蹄褭褭，江邊廢宅路迢迢。自經梅雨長垂耳，',48,'御定全唐詩/json/664.json','["櫪上病驄蹄褭褭，江邊廢宅路迢迢。自經梅雨長垂耳，", "曾聽禁漏驚街鼓，慣踏康莊怕小橋。夜半雄聲心尚壯，"]'),
('yuding-24','狄浦','羅隱','唐','御定全唐诗','yuding','','[]','晴川倚落暉，極目思依依。野色寒來淺，人家亂後稀。',48,'御定全唐詩/json/664.json','["晴川倚落暉，極目思依依。野色寒來淺，人家亂後稀。", "久貧身不達，多病意長違。還有漁舟在，時時夢裏歸。"]'),
('yuding-25','南康道中','羅隱','唐','御定全唐诗','yuding','','[]','弱冠負文翰，此中聽鹿鳴。使君延上榻，時輩仰前程。',48,'御定全唐詩/json/664.json','["弱冠負文翰，此中聽鹿鳴。使君延上榻，時輩仰前程。", "丹桂竟多故，白雲空有情。唯餘路旁淚，沾灑向塵纓。"]'),
('yuding-26','北固亭東望寄默師','羅隱','唐','御定全唐诗','yuding','','[]','高亭暮色中，往事更誰同。水謾矜天闊，山應到此窮。',48,'御定全唐詩/json/664.json','["高亭暮色中，往事更誰同。水謾矜天闊，山應到此窮。", "病憐京口酒，老怯海門風。唯有言堪解，何由見遠公。"]'),
('yuding-27','華清宮','羅隱','唐','御定全唐诗','yuding','','[]','樓殿層層佳氣多，開元時節好笙歌。',32,'御定全唐詩/json/664.json','["樓殿層層佳氣多，開元時節好笙歌。", "也知道德勝堯舜，爭奈楊妃解笑何。"]'),
('yuding-28','韓信廟','羅隱','唐','御定全唐诗','yuding','','[]','剪項移秦勢自雄，布衣還是負深功。',32,'御定全唐詩/json/664.json','["剪項移秦勢自雄，布衣還是負深功。", "寡妻稚女俱堪恨，卻把餘杯奠蒯通。"]'),
('yuding-29','韋公子','羅隱','唐','御定全唐诗','yuding','','[]','擊柱狂歌慘別顏，百年人事夢魂間。',32,'御定全唐詩/json/664.json','["擊柱狂歌慘別顏，百年人事夢魂間。", "李將軍自嘉聲在，不得封侯亦自閑。"]'),
('yuding-30','望思台','羅隱','唐','御定全唐诗','yuding','','[]','芳草台邊魂不歸，野煙喬木弄殘暉。',32,'御定全唐詩/json/664.json','["芳草台邊魂不歸，野煙喬木弄殘暉。", "可憐高祖清平業，留與閒人作是非。"]'),
('yuding-31','帝幸蜀','羅隱','唐','御定全唐诗','yuding','','[]','馬嵬山色翠依依，又見鑾輿幸蜀歸。',32,'御定全唐詩/json/664.json','["馬嵬山色翠依依，又見鑾輿幸蜀歸。", "泉下阿蠻應有語，這回休更怨楊妃。"]'),
('yuding-32','王夷甫','羅隱','唐','御定全唐诗','yuding','','[]','把得閒書坐水濱，讀來前事亦酸辛。',32,'御定全唐詩/json/664.json','["把得閒書坐水濱，讀來前事亦酸辛。", "莫言麈尾清譚柄，壞卻淳風是此人。"]'),
('yuding-33','鷺鷥','羅隱','唐','御定全唐诗','yuding','','[]','斜陽澹澹柳陰陰，風嫋寒絲映水深。',32,'御定全唐詩/json/664.json','["斜陽澹澹柳陰陰，風嫋寒絲映水深。", "不要向人誇素白，也知常有羨魚心。"]'),
('yuding-34','書淮陰侯傳','羅隱','唐','御定全唐诗','yuding','','[]','寒燈挑盡見遺塵，試瀝椒漿合有神。',32,'御定全唐詩/json/664.json','["寒燈挑盡見遺塵，試瀝椒漿合有神。", "莫恨高皇不終始，滅秦謀項是何人。"]'),
('yuding-35','青山廟','羅隱','唐','御定全唐诗','yuding','','[]','市簫聲咽跡崎嶇，雪恥酬恩此丈夫。',32,'御定全唐詩/json/664.json','["市簫聲咽跡崎嶇，雪恥酬恩此丈夫。", "霸主兩亡時亦異，不知魂魄更無歸。"]'),
('yuding-36','小松','羅隱','唐','御定全唐诗','yuding','','[]','已有清陰逼座隅，愛聲仙客肯過無。',32,'御定全唐詩/json/664.json','["已有清陰逼座隅，愛聲仙客肯過無。", "陵遷谷變須高節，莫向人間作大夫。"]'),
('yuding-37','竹','羅隱','唐','御定全唐诗','yuding','','[]','籬外清陰接藥闌，曉風交戛碧琅玕。子猷死後知音少，粉節霜筠謾歲寒。',32,'御定全唐詩/json/664.json','["籬外清陰接藥闌，曉風交戛碧琅玕。子猷死後知音少，粉節霜筠謾歲寒。"]'),
('yuding-38','謾天嶺','羅隱','唐','御定全唐诗','yuding','','[]','西去休言蜀道難，此中危峻已多端。',32,'御定全唐詩/json/664.json','["西去休言蜀道難，此中危峻已多端。", "到頭未會蒼蒼色，爭得禁他兩度謾。"]'),
('yuding-0','秋蟲賦','羅隱','唐','御定全唐诗','yuding','','[]','物之小兮，迎網而斃；物之大兮，兼網而逝。網也者，',24,'御定全唐詩/json/665.json','["物之小兮，迎網而斃；物之大兮，兼網而逝。網也者，"]'),
('yuding-1','蟋蟀詩','羅隱','唐','御定全唐诗','yuding','','[]','頑颸斃芳，吹愁夕長。屑戍有動，歌離吊夢。',160,'御定全唐詩/json/665.json','["頑颸斃芳，吹愁夕長。屑戍有動，歌離吊夢。", "如訴如言，緒引虛寬。周隙伺榻，繁咽夤緣。", "範睡蟬老，冠峨緌好。不冠不緌，爾奚以悲。", "蚊蚋有毒，食人肌肉。蒼蠅多端，黑白偷安。", "爾也出處，物兮莫累。壞舍啼衰，虛堂泣曙。", "勿徇喧嘩，鼠豈無牙。勿學萋菲，垣亦有耳。", "危條槁飛，抽恨咿咿。別帳缸冷，柔魂不定。", "美人在何，夜影流波。與子佇立，裴回思多。"]'),
('yuding-2','西川與蔡十九同別子超','羅隱','唐','御定全唐诗','yuding','','[]','相歡雖則不多時，相別那能不斂眉。蜀客賦高君解愛，',40,'御定全唐詩/json/665.json','["相歡雖則不多時，相別那能不斂眉。蜀客賦高君解愛，", "腸斷門前舊行處，不堪全屬五陵兒。"]'),
('yuding-3','龍泉東下卻寄孫員外','羅隱','唐','御定全唐诗','yuding','','[]','縠江東下幾多程，每泊孤舟即有情。山色已隨遊子遠，',40,'御定全唐詩/json/665.json','["縠江東下幾多程，每泊孤舟即有情。山色已隨遊子遠，", "百尺風帆兩行淚，不堪回首望崢嶸。"]'),
('yuding-4','牡丹','羅隱','唐','御定全唐诗','yuding','','[]','豔多煙重欲開難，紅蕊當心一抹檀。公子醉歸燈下見，',40,'御定全唐詩/json/665.json','["豔多煙重欲開難，紅蕊當心一抹檀。公子醉歸燈下見，", "日晚更將何所似，太真無力憑闌幹。"]'),
('yuding-5','巫山高','羅隱','唐','御定全唐诗','yuding','','[]','下壓重泉上千仞，香雲結夢西風緊。縱有精靈得往來，',48,'御定全唐詩/json/665.json','["下壓重泉上千仞，香雲結夢西風緊。縱有精靈得往來，", "暮灑朝行何所之，江邊日月情無盡。珠零冷露丹墮楓，"]'),
('yuding-6','江南行','羅隱','唐','御定全唐诗','yuding','','[]','江煙濕雨蛟綃軟，漠漠小山眉黛淺。水國多愁又有情，',48,'御定全唐詩/json/665.json','["江煙濕雨蛟綃軟，漠漠小山眉黛淺。水國多愁又有情，", "鴛鴦鸂鶒喚不起，平鋪綠水眠東風。西陵路邊月悄悄，"]'),
('yuding-7','空城雀','羅隱','唐','御定全唐诗','yuding','','[]','雀入官倉中，所食能損幾。所恨往復頻，官倉乃害爾。',48,'御定全唐詩/json/665.json','["雀入官倉中，所食能損幾。所恨往復頻，官倉乃害爾。", "魚網不在天，鳥網不張水。飲啄要自然，何必空城裏。"]'),
('yuding-8','芳樹','羅隱','唐','御定全唐诗','yuding','','[]','細萼慢逐風，暖香閑破鼻。青帝固有心，時時漏天意。',92,'御定全唐詩/json/665.json','["細萼慢逐風，暖香閑破鼻。青帝固有心，時時漏天意。", "去年高枝猶墮地，今年低枝已憔悴。吾所以見造化之權，", "人生長短同一軌，若使威可以制，力可以止，", "伊人強猛猶如此，顧我勞生何足恃。但願我開素袍，"]'),
('yuding-9','聽琴','羅隱','唐','御定全唐诗','yuding','','[]','寒雨蕭蕭落井梧，夜深何處怨啼烏。',32,'御定全唐詩/json/665.json','["寒雨蕭蕭落井梧，夜深何處怨啼烏。", "不知一盞臨邛酒，救得相如渴病無。"]'),
('yuding-10','大樑見喬詡','羅隱','唐','御定全唐诗','yuding','','[]','湘水春浮岸，淮燈夜滿橋。六年悲梗斷，兩地各萍漂。',192,'御定全唐詩/json/665.json','["湘水春浮岸，淮燈夜滿橋。六年悲梗斷，兩地各萍漂。", "刀筆依三事，篇章奏珥貂。跡卑甘汩沒，名散稱逍遙。", "好寺松為徑，空江桂作橈。野香花伴落，缸暖酒和燒。", "晉沼尋游鳳，秦冠竟歎鴞。骨凡雞犬薄，魂斷蕙蘭招。", "悵望添燕管，蹉跎厭魯瓢。敗桐方委爨，冤匣正沖霄。", "戰代安厘國，封崇孝景朝。千年非有限，一醉解無聊。", "漏永燈花暗，爐紅雪片銷。久遊家共遠，相對鬢俱凋。", "運命從難合，光陰奈不饒。到頭蓑笠契，兩信釣魚潮。"]'),
('yuding-11','寄洪正師','羅隱','唐','御定全唐诗','yuding','','[]','寄蹇渾成跡，經年滯杜南。價輕猶有二，足刖已過三。',48,'御定全唐詩/json/665.json','["寄蹇渾成跡，經年滯杜南。價輕猶有二，足刖已過三。", "雞肋曹公忿，豬肝仲叔慚。會應謀避地，依約近禪庵。"]'),
('yuding-12','聖真觀劉真師院十韻','羅隱','唐','御定全唐诗','yuding','','[]','簾下嚴君蔔，窗間少室峰。攝生門已盡，混跡世猶逢。',120,'御定全唐詩/json/665.json','["簾下嚴君蔔，窗間少室峰。攝生門已盡，混跡世猶逢。", "山藪師王烈，簪纓友戴顒。魚跳介象鱠，飯吐葛玄蜂。", "紫飽垂新椹，黃輕墮小松。塵埃金谷路，樓閣上陽鐘。", "野耗鳶肩寄，仙書鳥爪封。支床龜縱老，取箭鶴何慵。", "別久曾牽念，閑來肯壓重。尚餘青竹在，試為剪成龍。"]'),
('yuding-13','寄聶尊師','羅隱','唐','御定全唐诗','yuding','','[]','欲芟荊棘種交梨，指畫城中日恐遲。',32,'御定全唐詩/json/665.json','["欲芟荊棘種交梨，指畫城中日恐遲。", "安得紫青磨鏡石，與君閑處看榮衰。"]'),
('yuding-14','金山僧院','羅隱','唐','御定全唐诗','yuding','','[]','根盤蛟蜃路藤蘿，四面無塵輟棹過。',32,'御定全唐詩/json/665.json','["根盤蛟蜃路藤蘿，四面無塵輟棹過。", "得似吾師始惆悵，眼前終日有風波。"]'),
('yuding-15','酬高崇節','羅隱','唐','御定全唐诗','yuding','','[]','舊遊雖一夢，別緒忽千般。敗草湯陵晚，衰槐楚寺寒。',48,'御定全唐詩/json/665.json','["舊遊雖一夢，別緒忽千般。敗草湯陵晚，衰槐楚寺寒。", "數奇常自愧，時薄欲何干。猶賴君相勉，殷勤貢禹冠。"]'),
('yuding-16','送汝州李中丞十二韻','羅隱','唐','御定全唐诗','yuding','','[]','群盜方為梗，分符奏未寧。黃巾攻郡邑，白梃掠生靈。',144,'御定全唐詩/json/665.json','["群盜方為梗，分符奏未寧。黃巾攻郡邑，白梃掠生靈。", "塵土周畿暗，瘡痍汝水腥。一凶雖剪滅，數縣尚凋零。", "理必資寬猛，謀須藉典刑。與能才物論，慎選忽天庭。", "官品尊台秩，山河擁福星。虎知應去境，牛在肯全形。", "舊政窮人瘼，新銜展武經。關防秋草白，城壁晚峰青。", "破膽期來複，迷魂想待醒。魯山行縣後，聊為奠惟馨。"]'),
('yuding-17','淮南送節度盧端公將命之汴州端公常為汴州相公從事','羅隱','唐','御定全唐诗','yuding','','[]','吹台高倚圃田東，此去軺車事不同。珠履舊參蕭相國，',40,'御定全唐詩/json/665.json','["吹台高倚圃田東，此去軺車事不同。珠履舊參蕭相國，", "到彼的知宣室語，幾時征拜黑頭公。"]'),
('yuding-18','送盧端公歸台盧校書之夏縣','羅隱','唐','御定全唐诗','yuding','','[]','綿綿堤草拂征輪，龍虎俱辭楚水濱。只見勝之為禦史，',40,'御定全唐詩/json/665.json','["綿綿堤草拂征輪，龍虎俱辭楚水濱。只見勝之為禦史，", "一種西歸一般達，柏台霜冷夏城春。"]'),
('yuding-19','送朗州張員外','羅隱','唐','御定全唐诗','yuding','','[]','聖朝綸閣最延才，須牧生民始入來。鳳藻已期他日用，',40,'御定全唐詩/json/665.json','["聖朝綸閣最延才，須牧生民始入來。鳳藻已期他日用，", "腸斷秦原二三月，好花全為使君開。"]'),
('yuding-20','淮南送工部盧員外赴闕','羅隱','唐','御定全唐诗','yuding','','[]','始從豸角曳長裾，又吐雞香奏玉除。隋邸舊僚推謝掾，',40,'御定全唐詩/json/665.json','["始從豸角曳長裾，又吐雞香奏玉除。隋邸舊僚推謝掾，", "遙想到時秋欲盡，禁城涼冷露槐疏。"]'),
('yuding-21','淮南送司勳李郎中赴闕','羅隱','唐','御定全唐诗','yuding','','[]','中朝品秩重文章，雙筆依前賜望郎。五夜星辰歸帝座，',40,'御定全唐詩/json/665.json','["中朝品秩重文章，雙筆依前賜望郎。五夜星辰歸帝座，", "不必戀恩多感激，過淮應合見征黃。"]'),
('yuding-22','送陸郎中赴闕','羅隱','唐','御定全唐诗','yuding','','[]','幕下留連兩月強，爐邊侍史舊焚香。不關雨露偏垂意，',40,'御定全唐詩/json/665.json','["幕下留連兩月強，爐邊侍史舊焚香。不關雨露偏垂意，", "少瑜鏤管丘遲錦，從此西垣使鳳凰。"]'),
('yuding-23','途中送人東遊有寄','羅隱','唐','御定全唐诗','yuding','','[]','離驂莫惜暫逡巡，君向池陽我入秦。歲月易拋非曩日，',40,'御定全唐詩/json/665.json','["離驂莫惜暫逡巡，君向池陽我入秦。歲月易拋非曩日，", "此處故交誰見問，為言霜鬢壓風塵。"]'),
('yuding-24','過廢江甯縣','羅隱','唐','御定全唐诗','yuding','','[]','縣前水色細鱗鱗，一為夫君吊水濱。漫把文章矜後代，',40,'御定全唐詩/json/665.json','["縣前水色細鱗鱗，一為夫君吊水濱。漫把文章矜後代，", "我亦有心無處說，等閒停棹似迷津。"]'),
('yuding-25','邊夜','羅隱','唐','御定全唐诗','yuding','','[]','光景漂如水，生涯轉似萍。雁門窮朔路，牛鬥故鄉星。',48,'御定全唐詩/json/665.json','["光景漂如水，生涯轉似萍。雁門窮朔路，牛鬥故鄉星。", "句盡人誰切，歌終淚自零。夜闌回首算，何處不長亭。"]'),
('yuding-26','哭張博士太常','羅隱','唐','御定全唐诗','yuding','','[]','前輩倏雲歿，愧君曾比方。格卑雖不稱，言重亦難忘。',48,'御定全唐詩/json/665.json','["前輩倏雲歿，愧君曾比方。格卑雖不稱，言重亦難忘。", "諫草猶青瑣，悲風已白楊。只應移理窟，泉下對真長。"]'),
('yuding-27','淮口軍葬','羅隱','唐','御定全唐诗','yuding','','[]','一陣孤軍不復回，更無分別只荒堆。',32,'御定全唐詩/json/665.json','["一陣孤軍不復回，更無分別只荒堆。", "莫言賦分須如此，曾作文皇赤子來。"]'),
('yuding-28','燕昭王墓','羅隱','唐','御定全唐诗','yuding','','[]','戰國蒼茫難重尋，此中蹤跡想知音。強停別騎山花曉，',40,'御定全唐詩/json/665.json','["戰國蒼茫難重尋，此中蹤跡想知音。強停別騎山花曉，", "思量郭隗平生事，不殉昭王是負心。"]'),
('yuding-29','江南','羅隱','唐','御定全唐诗','yuding','','[]','玉樹歌聲澤國春，累累輜重憶亡陳。',32,'御定全唐詩/json/665.json','["玉樹歌聲澤國春，累累輜重憶亡陳。", "垂衣端拱渾閒事，忍把江山乞與人。"]'),
('yuding-30','江北','羅隱','唐','御定全唐诗','yuding','','[]','廢宮荒苑莫閒愁，成敗終須要徹頭。',32,'御定全唐詩/json/665.json','["廢宮荒苑莫閒愁，成敗終須要徹頭。", "一種風流一種死，朝歌爭得似揚州。"]'),
('yuding-31','早登新安縣樓','羅隱','唐','御定全唐诗','yuding','','[]','關城樹色齊，往事未全迷。塞路真人氣，封門壯士泥。',48,'御定全唐詩/json/665.json','["關城樹色齊，往事未全迷。塞路真人氣，封門壯士泥。", "草濃延蝶舞，花密教鶯啼。若以鳴為德，鸞皇不及雞。"]'),
('yuding-32','幹越亭','羅隱','唐','御定全唐诗','yuding','','[]','楚水蕭蕭多病身，強憑危檻送殘春。高城自有陵兼穀，',40,'御定全唐詩/json/665.json','["楚水蕭蕭多病身，強憑危檻送殘春。高城自有陵兼穀，", "琵琶洲遠江村闊，回首征途淚滿巾。"]'),
('yuding-33','南園題','羅隱','唐','御定全唐诗','yuding','','[]','搏擊路終迷，南園且灌畦。敢言逃俗態，自是樂幽棲。',120,'御定全唐詩/json/665.json','["搏擊路終迷，南園且灌畦。敢言逃俗態，自是樂幽棲。", "葉長春松闊，科圓早薤齊。雨沾虛檻冷，雪壓遠山低。", "竹好還成徑，桃夭亦有蹊。小窗奔野馬，閑甕養醯雞。", "水石心逾切，煙霄分已暌。病憐王猛畚，愚笑隗囂泥。", "澤國潮平岸，江村柳覆堤。到頭乘興是，誰手好提攜。"]'),
('yuding-34','人日新安道中見梅花','羅隱','唐','御定全唐诗','yuding','','[]','長途酒醒臘春寒，嫩蕊香英撲馬鞍。',32,'御定全唐詩/json/665.json','["長途酒醒臘春寒，嫩蕊香英撲馬鞍。", "不上壽陽公主面，憐君開得卻無端。"]'),
('yuding-35','許由廟','羅隱','唐','御定全唐诗','yuding','','[]','高掛風瓢濯漢濱，土階三尺愧清塵。',32,'御定全唐詩/json/665.json','["高掛風瓢濯漢濱，土階三尺愧清塵。", "可憐比屋堪封日，若到人間是眾人。"]'),
('yuding-36','題段太尉廟','羅隱','唐','御定全唐诗','yuding','','[]','近甸蒙塵日，南梁反正年。飄流茂陵碗，零落太官椽。',48,'御定全唐詩/json/665.json','["近甸蒙塵日，南梁反正年。飄流茂陵碗，零落太官椽。", "建纛非降楚，披圖異錄燕。堪嗟侍中血，不及禦衣前。"]'),
('yuding-37','湘妃廟','羅隱','唐','御定全唐诗','yuding','','[]','劉表荒碑斷水濱，廟前幽草閉殘春。已將怨淚流斑竹，',40,'御定全唐詩/json/665.json','["劉表荒碑斷水濱，廟前幽草閉殘春。已將怨淚流斑竹，", "九峰相似堪疑處，望見蒼梧不見人。"]'),
('yuding-38','八駿圖','羅隱','唐','御定全唐诗','yuding','','[]','穆滿當年物外程，電腰風腳一何輕。',32,'御定全唐詩/json/665.json','["穆滿當年物外程，電腰風腳一何輕。", "如今縱有驊騮在，不得長鞭不肯行。"]'),
('yuding-39','庭花','羅隱','唐','御定全唐诗','yuding','','[]','昨日芳豔濃，開尊幾同醉。今朝風雨惡，惆悵人生事。',48,'御定全唐詩/json/665.json','["昨日芳豔濃，開尊幾同醉。今朝風雨惡，惆悵人生事。", "南威病不起，西子老兼至。向晚寂無人，相偎墮紅淚。"]'),
('yuding-40','病中題主人庭鶴','羅隱','唐','御定全唐诗','yuding','','[]','遼水華亭舊所聞，病中毛羽最憐君。',32,'御定全唐詩/json/665.json','["遼水華亭舊所聞，病中毛羽最憐君。", "稻粱且足身兼健，何必青雲與白雲。"]'),
('yuding-41','蟬','羅隱','唐','御定全唐诗','yuding','','[]','天地工夫一不遺，與君聲調借君緌。風棲露飽今如此，應忘當年滓濁時。',32,'御定全唐詩/json/665.json','["天地工夫一不遺，與君聲調借君緌。風棲露飽今如此，應忘當年滓濁時。"]'),
('yuding-42','薛陽陶觱篥歌','羅隱','唐','御定全唐诗','yuding','','[]','平泉上相東征日，曾為陽陶歌觱篥。烏江太守會稽侯，',136,'御定全唐詩/json/665.json','["平泉上相東征日，曾為陽陶歌觱篥。烏江太守會稽侯，", "龍樓冷落夏口寒，從此風流為廢物。人間至藝難得主，", "西風九月草樹秋，萬喧沈寂登高樓。左篁揭指征羽吼，", "穿空激遠不可遏，仿佛似向伊水頭。伊水林泉今已矣，", "掃除桀黠似提帚，制壓群豪若穿鼻。九鼎調和各有門，", "勿惜喑嗚更一吹，與君共下難逢淚。"]'),
('yuding-43','酬丘光庭','羅隱','唐','御定全唐诗','yuding','','[]','正月十一日書劄，五月十六日到來。柳吟秦望咫尺地，',136,'御定全唐詩/json/665.json','["正月十一日書劄，五月十六日到來。柳吟秦望咫尺地，", "上言二年隔煙水，下有數幅真瓊瑰。行吟坐讀口不倦，", "鶴齡鴻算不復見，雨後蓑笠空莓苔。自從黃寇擾中土，", "朝廷濟濟百揆序，寧將對面容奸回。禍生有基妖有漸，", "懦夫早歲不量力，策蹇仰北高崔嵬。千門萬戶扃鎖密，", "榮衰貴賤目所睹，莫嫌頭白黃金台。"]'),
('yuding-44','投宣武鄭尚書二十韻','羅隱','唐','御定全唐诗','yuding','','[]','漢代簪纓盛，梁園雉堞雄。物情須重德，時論在明公。',241,'御定全唐詩/json/665.json','["漢代簪纓盛，梁園雉堞雄。物情須重德，時論在明公。", "族大逾開魏，神高本降嵩。世家惟蹇諤，官業即清通。", "翰苑論思外，綸闈嘯傲中。健豪驚彩鳳，高步出冥鴻。", "履歷雖吾道，行藏必聖聰。絳霄無系滯，浙水忽西東。", "庾監高樓月，袁郎滿扇風。四年將故事，兩地有全功。", "去去才須展，行行道益隆。避權辭憲署，仗節出南宮。", "雁影相承接，龍圖共始終。自然須作礪，不必恨臨戎。", "幕下蓮花盛，竿頭cG佩紅。騎兒逢郭伋，戰士得文翁。", "人地應無比，簟瓢奈屢空。因思一枝桂，已作斷根蓬。", "往事應歸捷，勞歌且責躬。殷勤信陵館，今日自途窮。"]'),
('yuding-45','投浙東王大夫二十韻','羅隱','唐','御定全唐诗','yuding','','[]','越嶺千峰秀，淮流一派長。暫憑開物手，來展濟時方。',240,'御定全唐詩/json/665.json','["越嶺千峰秀，淮流一派長。暫憑開物手，來展濟時方。", "舊跡蘭亭在，高風桂樹香。地清無等級，天闊任徊翔。", "麈尾談何勝，螭頭筆更狂。直曾批鳳詔，高已冠鵷行。", "嘯傲辭民部，雍容出帝鄉。趙堯推印綬，句踐與封疆。", "水占仙人吹，城留禦史床。嘉賓鄒潤甫，百姓賀知章。", "席暖飛鸚鵡，塵輕駐驌驦。夜歌珠斷續，晴舞雪悠揚。", "化向棠陰布，春隨棣萼芳。盛名韜不得，雄略晦彌彰。", "自愧三冬學，來窺數仞牆。感深惟刻骨，時去欲沾裳。", "想望魚燒尾，咨嗟鼠齧腸。可能因蹇拙，便合老滄浪。", "題柱心猶壯，移山志不忘。深慚百般病，今日問醫王。"]'),
('yuding-46','寄剡縣主簿','羅隱','唐','御定全唐诗','yuding','','[]','金庭養真地，珠篆會稽官。境勝堪長往，時危喜暫安。',48,'御定全唐詩/json/665.json','["金庭養真地，珠篆會稽官。境勝堪長往，時危喜暫安。", "洞連滄海闊，山擁赤城寒。他日拋塵土，因君擬煉丹。"]'),
('yuding-47','中秋不見月','羅隱','唐','御定全唐诗','yuding','','[]','風簾淅淅漏燈痕，一半秋光此夕分。',32,'御定全唐詩/json/665.json','["風簾淅淅漏燈痕，一半秋光此夕分。", "天為素娥孀怨苦，並教西北起浮雲。"]'),
('yuding-48','答宗人袞','羅隱','唐','御定全唐诗','yuding','','[]','昆侖水色九般流，飲即神仙憩即休。敢恨守株曾失意，',40,'御定全唐詩/json/665.json','["昆侖水色九般流，飲即神仙憩即休。敢恨守株曾失意，", "遙望北辰當上國，羨君歸棹五諸侯。"]'),
('yuding-49','早行','羅隱','唐','御定全唐诗','yuding','','[]','雨灑江聲風又吹，扁舟正與睡相宜。',32,'御定全唐詩/json/665.json','["雨灑江聲風又吹，扁舟正與睡相宜。", "無端戍鼓催前去，別卻青山向曉時。"]'),
('yuding-50','詠白菊','羅隱','唐','御定全唐诗','yuding','','[]','雖被風霜競欲催，皎然顏色不低摧。已疑素手能妝出，',40,'御定全唐詩/json/665.json','["雖被風霜競欲催，皎然顏色不低摧。已疑素手能妝出，", "尋思閉戶中宵見，應認寒窗雪一堆。"]'),
('yuding-51','晚泊宿松','羅隱','唐','御定全唐诗','yuding','','[]','解纜隨江流，晚泊古淮岸。歸雲送春和，繁星麗雲漢。',48,'御定全唐詩/json/665.json','["解纜隨江流，晚泊古淮岸。歸雲送春和，繁星麗雲漢。", "春深胡雁飛，人喧水禽散。仰君邈難親，沈思夜將旦。"]'),
('yuding-52','錢塘遇默師憶潤州舊游','羅隱','唐','御定全唐诗','yuding','','[]','歌敲玉唾壺，醉擊珊瑚枝。石羊妙善街，甘露平泉碑。',48,'御定全唐詩/json/665.json','["歌敲玉唾壺，醉擊珊瑚枝。石羊妙善街，甘露平泉碑。", "捫苔想豪傑，剔蘚看文詞。歸來北固山，水檻光參差。"]'),
('yuding-53','江南別','羅隱','唐','御定全唐诗','yuding','','[]','去年今夜江南別，鴛鴦翅冷飛蓬爇。今年今夜江北邊，',24,'御定全唐詩/json/665.json','["去年今夜江南別，鴛鴦翅冷飛蓬爇。今年今夜江北邊，"]'),
('yuding-54','四頂山','羅隱','唐','御定全唐诗','yuding','','[]','勝景天然別，精神入畫圖。一山分四頂，三面瞰平湖。',48,'御定全唐詩/json/665.json','["勝景天然別，精神入畫圖。一山分四頂，三面瞰平湖。", "過夏僧無熱，淩冬草不枯。遊人來至此，願剃發和須。"]'),
('yuding-55','姥山','羅隱','唐','御定全唐诗','yuding','','[]','臨塘古廟一神仙，繡幌花容色儼然。為逐朝雲來此地，',40,'御定全唐詩/json/665.json','["臨塘古廟一神仙，繡幌花容色儼然。為逐朝雲來此地，", "借問邑人沈水事，已經秦漢幾千年。"]'),
('yuding-56','岐王宅','羅隱','唐','御定全唐诗','yuding','','[]','朱邸平臺隔禁闈，貴游陳跡尚依稀。雲低雍畤祈年去，',40,'御定全唐詩/json/665.json','["朱邸平臺隔禁闈，貴游陳跡尚依稀。雲低雍畤祈年去，", "承平舊物惟君盡，猶寫雕鞍伴六飛。"]'),
('yuding-57','長明燈','羅隱','唐','御定全唐诗','yuding','','[]','破暗長明世代深，煙和香氣兩沉沉。不知初點人何在，',40,'御定全唐詩/json/665.json','["破暗長明世代深，煙和香氣兩沉沉。不知初點人何在，", "孤光自有龍神護，雀戲蛾飛不敢侵。"]'),
('yuding-58','堋口逢人','羅隱','唐','御定全唐诗','yuding','','[]','艱難別離久，中外往還深。已改當時發，空餘舊日心。',24,'御定全唐詩/json/665.json','["艱難別離久，中外往還深。已改當時發，空餘舊日心。"]'),
('yuding-59','遇邊使','羅隱','唐','御定全唐诗','yuding','','[]','累年無的信，每夜望邊城。袖掩千行淚，書封一尺金。',24,'御定全唐詩/json/665.json','["累年無的信，每夜望邊城。袖掩千行淚，書封一尺金。"]'),
('yuding-60','移住別友','羅隱','唐','御定全唐诗','yuding','','[]','自到西川住，惟君別有情。常逢對門遠，又隔一重城。',24,'御定全唐詩/json/665.json','["自到西川住，惟君別有情。常逢對門遠，又隔一重城。"]'),
('yuding-61','宮詞','羅隱','唐','御定全唐诗','yuding','','[]','巧畫蛾眉獨出群，當時人道便承恩。',32,'御定全唐詩/json/665.json','["巧畫蛾眉獨出群，當時人道便承恩。", "經年不見君王面，落日黃昏空掩門。"]'),
('yuding-62','涇溪','羅隱','唐','御定全唐诗','yuding','','[]','涇溪石險人競懼，終歲不聞傾覆人。',32,'御定全唐詩/json/665.json','["涇溪石險人競懼，終歲不聞傾覆人。", "卻是平流無石處，時時聞說有沈淪。"]'),
('yuding-63','題杜甫集','羅隱','唐','御定全唐诗','yuding','','[]','楚水悠悠浸楚亭，楚南天地兩無情。',32,'御定全唐詩/json/665.json','["楚水悠悠浸楚亭，楚南天地兩無情。", "忍交孫武重泉下，不見時人說用兵。"]'),
('yuding-64','感弄猴人賜朱紱','羅隱','唐','御定全唐诗','yuding','','[]','十二三年就試期，五湖煙月奈相違。',32,'御定全唐詩/json/665.json','["十二三年就試期，五湖煙月奈相違。", "何如買取胡孫弄，一笑君王便著緋。"]'),
('yuding-65','題磻溪垂釣圖','羅隱','唐','御定全唐诗','yuding','','[]','呂望當年展廟謨，直鉤釣國更誰如。',32,'御定全唐詩/json/665.json','["呂望當年展廟謨，直鉤釣國更誰如。", "若教生在西湖上，也是須供使宅魚。"]'),
('yuding-66','春風','羅隱','唐','御定全唐诗','yuding','','[]','也知有意吹噓切，爭奈人間善惡分。',32,'御定全唐詩/json/665.json','["也知有意吹噓切，爭奈人間善惡分。", "但是秕糠微細物，等閒抬舉到青雲。"]'),
('yuding-67','竹下殘雪','羅隱','唐','御定全唐诗','yuding','','[]','牆下濃陰對此君，小山尖險玉為群。',32,'御定全唐詩/json/665.json','["牆下濃陰對此君，小山尖險玉為群。", "夜來解凍風雖急，不向寒城減一分。"]'),
('yuding-68','杏花','羅隱','唐','御定全唐诗','yuding','','[]','暖氣潛催次第春，梅花已謝杏花新。',32,'御定全唐詩/json/665.json','["暖氣潛催次第春，梅花已謝杏花新。", "半開半落閑園裏，何異榮枯世上人。"]'),
('yuding-69','鎮海軍所貢','羅隱','唐','御定全唐诗','yuding','','[]','簷前飛雪扇前塵，千里移添上苑春。',32,'御定全唐詩/json/665.json','["簷前飛雪扇前塵，千里移添上苑春。", "他日丁甯柿林院，莫宣恩澤與閒人。"]'),
('yuding-70','席上歌水調','羅隱','唐','御定全唐诗','yuding','','[]','餘聲宛宛拂庭梅，通濟渠邊去又回。',32,'御定全唐詩/json/665.json','["餘聲宛宛拂庭梅，通濟渠邊去又回。", "若使煬皇魂魄在，為君應合過江來。"]'),
('yuding-71','題新榜','羅隱','唐','御定全唐诗','yuding','','[]','黃土原邊狡兔肥，犬如流電馬如飛。',32,'御定全唐詩/json/665.json','["黃土原邊狡兔肥，犬如流電馬如飛。", "灞陵老將無功業，猶憶當時夜獵歸。"]'),
('yuding-72','句','羅隱','唐','御定全唐诗','yuding','','[]','夏窗七葉連陰暗。（《游城南記》：杜佑有別墅，',232,'御定全唐詩/json/665.json','["夏窗七葉連陰暗。（《游城南記》：杜佑有別墅，", "賴家橋上潏河邊。（隱又有城南雜感詩，其題有景星觀、", "姚家園、葉家林及此句，今雜感詩亡）", "細看月輪真有意，已知青桂近嫦娥。（《曾公類苑》：", "裴筠娶簫楚公女，便擢進士，隱詩云云）", "一個禰衡容不得，思量黃祖謾英雄。（《吳越備史》：", "隱初見錢鏐，懼不見，用遂以所為夏口詩標於卷末云云，", "張華謾出如丹語，不及劉侯一紙書。（《鑒戒錄》雲：", "鄭畋女喜隱此詩）", "山雨霏微宿上亭，雨中因想雨淋鈴。", "老僧齋罷關門睡，不管波濤四面生。（金山僧院。", "《詩話總龜》）"]'),
('yuding-0','比紅兒詩','羅虯','唐','御定全唐诗','yuding','','[]','姓字看侵尺五天，芳菲占斷百花鮮。',384,'御定全唐詩/json/666.json','["姓字看侵尺五天，芳菲占斷百花鮮。", "馬嵬好笑當時事，虛賺明皇幸蜀川。", "金穀園中花正繁，墜樓從道感深恩。", "齊奴卻是來東市，不為紅兒死更冤。", "陷卻平陽為小憐，周師百萬戰長川。", "更教乞與紅兒貌，舉國山川不值錢。", "一曲都緣張麗華，六宮齊唱後庭花。", "若教比並紅兒貌，枉破當年國與家。", "樂營門外柳如陰，中有佳人畫閣深。", "若是五陵公子見，買時應不啻千金。", "青絲高綰石榴裙，腸斷當筵酒半醺。", "置向漢宮圖畫裏，入胡應不數昭君。", "斜憑欄杆醉態新，斂眸微盻不勝春。", "當時若遇東昏主，金葉蓮花是此人。", "匼匝千山與萬山，碧桃花下景長閑。", "神仙得似紅兒貌，應免劉郎憶世間。", "越山重疊越溪斜，西子休憐解浣紗。", "得似紅兒今日貌，肯教將去與夫差。", "詔下人間覓好花，月眉雲髻選人家。", "紅兒若向當時見，系臂先封第一紗。", "鋒鏑縱橫不敢看，淚垂玉箸正汍瀾。", "應緣近似紅兒貌，始得深宮奉五官。", "金縷濃熏百和香，臉紅眉黛入時妝。", "當時便向喬家見，未敢將心在窈娘。"]'),
('yuding-1','句','羅虯','唐','御定全唐诗','yuding','','[]','窗前遠岫懸生碧，簾外殘霞掛熟紅。',16,'御定全唐詩/json/666.json','["窗前遠岫懸生碧，簾外殘霞掛熟紅。"]'),
('yuding-0','星精亭','鄭損','唐','御定全唐诗','yuding','','[]','星沈萬古痕，孤絕勢無鄰。地窄少留竹，空多剩占雲。',48,'御定全唐詩/json/667.json','["星沈萬古痕，孤絕勢無鄰。地窄少留竹，空多剩占雲。", "釣篷和雨看，樵斧帶霜聞。莫惜尋常到，清風不負人。"]'),
('yuding-1','釣閣','鄭損','唐','御定全唐诗','yuding','','[]','小閣愜幽尋，周遭萬竹森。誰知一沼內，亦有五湖心。',48,'御定全唐詩/json/667.json','["小閣愜幽尋，周遭萬竹森。誰知一沼內，亦有五湖心。", "釣直魚應笑，身閑樂自深。晚來春醉熟，香餌任浮沈。"]'),
('yuding-2','玉聲亭','鄭損','唐','御定全唐诗','yuding','','[]','世間泉石本無價，那更天然落景中。漢佩琮琤寒溜雨，',40,'御定全唐詩/json/667.json','["世間泉石本無價，那更天然落景中。漢佩琮琤寒溜雨，", "借問主人能住久，後來好事有誰同。"]'),
('yuding-3','藝堂','鄭損','唐','御定全唐诗','yuding','','[]','堂開凍石千年翠，藝講秋膠百步威。揖讓未能忘典禮，',40,'御定全唐詩/json/667.json','["堂開凍石千年翠，藝講秋膠百步威。揖讓未能忘典禮，", "莫怪尊前頻浩歎，男兒志願與時違。"]'),
('yuding-4','星精石','鄭損','唐','御定全唐诗','yuding','','[]','突險呀空龍虎蹲，由來英氣蓄寒根。蒼苔點染雲生靨，',40,'御定全唐詩/json/667.json','["突險呀空龍虎蹲，由來英氣蓄寒根。蒼苔點染雲生靨，", "孤岩恰恰容幽構，可愛江南釋子園。"]'),
('yuding-5','泛香亭','鄭損','唐','御定全唐诗','yuding','','[]','流杯處處稱佳致，何似斯亭出自然。山溜穿雲來幾裏，',40,'御定全唐詩/json/667.json','["流杯處處稱佳致，何似斯亭出自然。山溜穿雲來幾裏，", "莫怪坐中難得醉，醒人心骨有潺湲。"]'),
('yuding-6','巴州寒食晚眺','張禕','唐','御定全唐诗','yuding','','[]','東望青天周與秦，杏花榆葉故園春。',32,'御定全唐詩/json/667.json','["東望青天周與秦，杏花榆葉故園春。", "野寺一傾寒食酒，晚來風景重愁人。"]'),
('yuding-7','題擊甌樓','張禕','唐','御定全唐诗','yuding','','[]','駐旌元帥遺風在，擊缶高人逸興酣。',32,'御定全唐詩/json/667.json','["駐旌元帥遺風在，擊缶高人逸興酣。", "水轉巴文清溜急，山連蒙岫翠光涵。"]'),
('yuding-8','題司空圖壁','盧攜','唐','御定全唐诗','yuding','','[]','姓氏司空貴，官班禦史卑。老夫如且在，不用歎屯奇。',24,'御定全唐詩/json/667.json','["姓氏司空貴，官班禦史卑。老夫如且在，不用歎屯奇。"]'),
('yuding-9','愁詩','李廷璧','唐','御定全唐诗','yuding','','[]','到來難遣去難留，著骨黏心萬事休。潘嶽愁絲生鬢裏，',40,'御定全唐詩/json/667.json','["到來難遣去難留，著骨黏心萬事休。潘嶽愁絲生鬢裏，", "更有相思不相見，酒醒燈背月如鉤。"]'),
('yuding-10','題菖蒲廢觀','許三畏','唐','御定全唐诗','yuding','','[]','本是安期燒藥處，今來改作坐禪宮。數僧梵響滿樓月，',40,'御定全唐詩/json/667.json','["本是安期燒藥處，今來改作坐禪宮。數僧梵響滿樓月，", "我來不見修真客，卻得真如問遠公。"]'),
('yuding-11','致孫狀元訴醵罰錢','盧嗣業','唐','御定全唐诗','yuding','','[]','未識都知面，頻輸複分錢。苦心事筆硯，得志助花鈿。',48,'御定全唐詩/json/667.json','["未識都知面，頻輸複分錢。苦心事筆硯，得志助花鈿。", "徒步求秋賦，持杯給暮饘。力微多謝病，非不奉同年。"]'),
('yuding-12','紅薔薇','牛嶠','唐','御定全唐诗','yuding','','[]','曉啼珠露渾無力，繡簇羅襦不著行。',32,'御定全唐詩/json/667.json','["曉啼珠露渾無力，繡簇羅襦不著行。", "若綴壽陽公主額，六宮爭肯學梅妝。"]'),
('yuding-13','楊柳枝五首','牛嶠','唐','御定全唐诗','yuding','','[]','解凍風來末上青，解垂羅袖拜卿卿。',160,'御定全唐詩/json/667.json','["解凍風來末上青，解垂羅袖拜卿卿。", "無端嫋娜臨官路，舞送行人過一生。", "吳王宮裏色偏深，一簇纖條萬縷金。", "不憤錢塘蘇小小，引郎松下結同心。", "橋北橋南千萬條，恨伊張緒不相饒。", "金羈白馬臨風望，認得羊家靜婉腰。", "狂雪隨風撲馬飛，惹煙無力被春欺。", "莫交移入靈和殿，宮女三千又妒伊。", "嫋翠籠煙拂暖波，舞裙新染曲塵羅。", "章華台畔隋堤上，傍得春風爾許多。"]'),
('yuding-14','及第後宿平康裏詩','鄭合','唐','御定全唐诗','yuding','','[]','春來無處不閑行，楚潤相看別有情。',32,'御定全唐詩/json/667.json','["春來無處不閑行，楚潤相看別有情。", "好是五更殘酒醒，時時聞喚狀頭聲。"]'),
('yuding-15','賀裴廷裕蜀中登第詩','李搏','唐','御定全唐诗','yuding','','[]','銅梁千里曙雲開，仙籙新從紫府來。天上已張新羽翼，',40,'御定全唐詩/json/667.json','["銅梁千里曙雲開，仙籙新從紫府來。天上已張新羽翼，", "應笑戎藩刀筆吏，至今泥滓曝魚鰓。"]'),
('yuding-16','複謔廷裕','李搏','唐','御定全唐诗','yuding','','[]','曾隨風水化凡鱗，安上門前一字新。',32,'御定全唐詩/json/667.json','["曾隨風水化凡鱗，安上門前一字新。", "聞道蜀江風景好，不知何似杏園春。"]'),
('yuding-17','吊賈島','李克恭','唐','御定全唐诗','yuding','','[]','一一玄微縹緲成，盡吟方便爽神情。宣宗謫去為閒事，',40,'御定全唐詩/json/667.json','["一一玄微縹緲成，盡吟方便爽神情。宣宗謫去為閒事，", "如何未隔四十載，不遇論量向此生。"]'),
('yuding-18','君山','程賀','唐','御定全唐诗','yuding','','[]','曾游方外見麻姑，說道君山此本無。',32,'御定全唐詩/json/667.json','["曾游方外見麻姑，說道君山此本無。", "雲是昆侖山頂石，海風吹落洞庭湖。"]'),
('yuding-19','東歸詩','盧尚卿','唐','御定全唐诗','yuding','','[]','九重丹詔下塵埃，深鎖文闈罷選才。桂樹放教遮月長，',40,'御定全唐詩/json/667.json','["九重丹詔下塵埃，深鎖文闈罷選才。桂樹放教遮月長，", "今日灞陵橋上過，路人應笑臘前回。"]'),
('yuding-20','題玉芝雙奉院','顧在鎔','唐','御定全唐诗','yuding','','[]','入門如洞府，花木與時稀。夜坐山當戶，秋吟葉滿衣。',48,'御定全唐詩/json/667.json','["入門如洞府，花木與時稀。夜坐山當戶，秋吟葉滿衣。", "犬隨童子出，鳥避俗人飛。至藥應將熟，年年火氣微。"]'),
('yuding-21','宿麻平驛','顧在鎔','唐','御定全唐诗','yuding','','[]','及到怡情處，暫忘登陟勞。青山看不厭，明月坐來高。',48,'御定全唐詩/json/667.json','["及到怡情處，暫忘登陟勞。青山看不厭，明月坐來高。", "犬為孤村吠，猿因冷木號。微吟還獨酌，多興憶同袍。"]'),
('yuding-22','題光福上方塔','顧在鎔','唐','御定全唐诗','yuding','','[]','蒼島孤生白浪中，倚天高塔勢翻空。煙凝遠岫列寒翠，',40,'御定全唐詩/json/667.json','["蒼島孤生白浪中，倚天高塔勢翻空。煙凝遠岫列寒翠，", "六時金磬落何處，偏傍蘆葦驚釣翁。"]'),
('yuding-23','枯木詩辭召命作','翁洮','唐','御定全唐诗','yuding','','[]','枯木傍溪崖，由來歲月賒。有根盤水石，無葉接煙霞。',48,'御定全唐詩/json/667.json','["枯木傍溪崖，由來歲月賒。有根盤水石，無葉接煙霞。", "二月苔為色，三冬雪作花。不因星使至，誰識是靈槎。"]'),
('yuding-24','贈進士王雄','翁洮','唐','御定全唐诗','yuding','','[]','河清海晏少波濤，幾載垂鉤不得鼇。空向人間修諫草，',40,'御定全唐詩/json/667.json','["河清海晏少波濤，幾載垂鉤不得鼇。空向人間修諫草，", "何事明廷有徐庶，總教三徑臥蓬蒿。"]'),
('yuding-25','漁者','翁洮','唐','御定全唐诗','yuding','','[]','一葉飄然任浪吹，雨蓑煙笠肯忘機。只貪濁水張羅眾，',40,'御定全唐詩/json/667.json','["一葉飄然任浪吹，雨蓑煙笠肯忘機。只貪濁水張羅眾，", "到頭得喪終須達，誰道漁樵有是非。"]'),
('yuding-26','上子男壽昌宰','翁洮','唐','御定全唐诗','yuding','','[]','陶公為政卓潘齊，入縣看花柳滿堤。百里江山聊展驥，',40,'御定全唐詩/json/667.json','["陶公為政卓潘齊，入縣看花柳滿堤。百里江山聊展驥，", "只恐攀轅留不住，明時霄漢有丹梯。"]'),
('yuding-27','贈方幹先生','翁洮','唐','御定全唐诗','yuding','','[]','由來箕踞任天真，別有詩名出世塵。不愛春宮分桂樹，',40,'御定全唐詩/json/667.json','["由來箕踞任天真，別有詩名出世塵。不愛春宮分桂樹，", "獨向若耶溪上住，誰知不是釣鼇人。"]'),
('yuding-28','贈進士李德新接海棠梨','翁洮','唐','御定全唐诗','yuding','','[]','蜀人猶說種難成，何事江東見接生。席上若微桃李伴，',40,'御定全唐詩/json/667.json','["蜀人猶說種難成，何事江東見接生。席上若微桃李伴，", "一種呈妍今得地，劍峰梨嶺謾縱橫。"]'),
('yuding-29','春日題航頭橋','翁洮','唐','御定全唐诗','yuding','','[]','故園橋上絕埃塵，此日憑欄興自新。雲影晚將仙掌曙，',40,'御定全唐詩/json/667.json','["故園橋上絕埃塵，此日憑欄興自新。雲影晚將仙掌曙，", "莫怪馬卿題姓字，終朝雲雨化龍津。"]'),
('yuding-30','和方幹題李頻莊','翁洮','唐','御定全唐诗','yuding','','[]','高情度日非無事，自是高情不覺喧。海氣暗蒸蓮葉沼，',48,'御定全唐詩/json/667.json','["高情度日非無事，自是高情不覺喧。海氣暗蒸蓮葉沼，", "閑伴白雲收桂子，每尋流水劚桐孫。猶憑律呂傳心曲，"]'),
('yuding-31','葦叢','翁洮','唐','御定全唐诗','yuding','','[]','得地自成叢，那因種植功。有花皆吐雪，無韻不含風。',48,'御定全唐詩/json/667.json','["得地自成叢，那因種植功。有花皆吐雪，無韻不含風。", "倒影翹沙鳥，幽根立水蟲。蕭蕭寒雨夜，江漢思無窮。"]'),
('yuding-32','春','翁洮','唐','御定全唐诗','yuding','','[]','漠漠煙花處處通，遊人南北思無窮。林間鳥奏笙簧月，',40,'御定全唐詩/json/667.json','["漠漠煙花處處通，遊人南北思無窮。林間鳥奏笙簧月，", "此時誰羨神仙客，車馬悠揚九陌中。"]'),
('yuding-33','夏','翁洮','唐','御定全唐诗','yuding','','[]','觸目皆因長養功，浮生何處問窮通。柳長北闕絲千縷，',40,'御定全唐詩/json/667.json','["觸目皆因長養功，浮生何處問窮通。柳長北闕絲千縷，", "身心已在喧闐處，惟羨滄浪把釣翁。"]'),
('yuding-34','秋','翁洮','唐','御定全唐诗','yuding','','[]','宋玉高吟思萬重，澄澄寰宇振金風。雲閑日月浮虛白，',40,'御定全唐詩/json/667.json','["宋玉高吟思萬重，澄澄寰宇振金風。雲閑日月浮虛白，", "侯門處處槐花□，獻賦何時遇至公。"]'),
('yuding-35','冬','翁洮','唐','御定全唐诗','yuding','','[]','寂寂棲心向杳冥，苦吟寒律句偏清。雲凝止水魚龍蟄，',40,'御定全唐詩/json/667.json','["寂寂棲心向杳冥，苦吟寒律句偏清。雲凝止水魚龍蟄，", "歸飛未得東風力，魂斷三山九萬程。"]'),
('yuding-36','過洞庭','李嶼','唐','御定全唐诗','yuding','','[]','浩渺注橫流，千潭合萬湫。半洪侵楚翼，一汊屬吳頭。',120,'御定全唐詩/json/667.json','["浩渺注橫流，千潭合萬湫。半洪侵楚翼，一汊屬吳頭。", "動軸當新霽，漫空正仲秋。勢翻荊口迮，聲擁岳陽浮。", "遠脈滋衡嶽，微涼散橘洲。星辰連影動，嵐翠逐隅收。", "漸落分行雁，旋添趁伴舟。升騰人莫測，安穩路何憂。", "氣與塵中別，言堪象外搜。此身如粗了，來把一竿休。"]'),
('yuding-37','嚴塘經亂書事','鄭啟','唐','御定全唐诗','yuding','','[]','塵生宮闕霧濛濛，萬騎龍飛幸蜀中。在野傅岩君不夢，',80,'御定全唐詩/json/667.json','["塵生宮闕霧濛濛，萬騎龍飛幸蜀中。在野傅岩君不夢，", "星落夜原妖氣滿，漢家麟閣待英雄。", "梁園皓色月如珪，清景傷時一慘淒。未見山前歸牧馬，", "正是四郊多壘日，波濤早晚靜鯨鯢。"]'),
('yuding-38','鄧表山','鄭啟','唐','御定全唐诗','yuding','','[]','白日三清此上時，觀開山下彩雲飛。仙壇丹灶靈猶在，',40,'御定全唐詩/json/667.json','["白日三清此上時，觀開山下彩雲飛。仙壇丹灶靈猶在，", "松花落盡無消息，半夜疏鐘徹翠微。"]'),
('yuding-39','記知聞近過關試','韓儀','唐','御定全唐诗','yuding','','[]','短行軸了付三銓，休把新銜惱必先。',32,'御定全唐詩/json/667.json','["短行軸了付三銓，休把新銜惱必先。", "今日便稱前進士，好留春色與明年。"]'),
('yuding-40','郊居','溫憲','唐','御定全唐诗','yuding','','[]','村前村後樹，寓賞有餘情。青麥路初斷，紫花田未耕。',48,'御定全唐詩/json/667.json','["村前村後樹，寓賞有餘情。青麥路初斷，紫花田未耕。", "雉聲聞不到，山勢望猶橫。寂寞春風裏，吟酣信馬行。"]'),
('yuding-41','杏花','溫憲','唐','御定全唐诗','yuding','','[]','團雪上晴梢，紅明映碧寥。店香風起夜，村白雨休朝。',48,'御定全唐詩/json/667.json','["團雪上晴梢，紅明映碧寥。店香風起夜，村白雨休朝。", "靜落猶和蒂，繁開正蔽條。澹然閑賞久，無以破妖嬈。"]'),
('yuding-42','春鳩','溫憲','唐','御定全唐诗','yuding','','[]','村南微雨新，平綠淨無塵。散睡桑條暖，閑鳴屋脊春。',48,'御定全唐詩/json/667.json','["村南微雨新，平綠淨無塵。散睡桑條暖，閑鳴屋脊春。", "遠聞和曉夢，相應在諸鄰。行樂花時節，追飛見亦頻。"]'),
('yuding-43','題崇慶寺壁','溫憲','唐','御定全唐诗','yuding','','[]','十口溝隍待一身，半年千里絕音塵。',32,'御定全唐詩/json/667.json','["十口溝隍待一身，半年千里絕音塵。", "鬢毛如雪心如死，猶作長安下第人。"]'),
('yuding-44','報顏標','姚岩傑','唐','御定全唐诗','yuding','','[]','為報顏公識我麼，我心唯只與天和。眼前俗物關情少，',40,'御定全唐詩/json/667.json','["為報顏公識我麼，我心唯只與天和。眼前俗物關情少，", "聖朝若為蒼生計，也合公車到薜蘿。"]'),
('yuding-0','途中除夜','高蟾','唐','御定全唐诗','yuding','','[]','南北浮萍跡，年華又暗催。殘燈和臘盡，曉角帶春來。',48,'御定全唐詩/json/668.json','["南北浮萍跡，年華又暗催。殘燈和臘盡，曉角帶春來。", "鬢欲漸侵雪，心仍未肯灰。金門舊知己，誰為脫塵埃。"]'),
('yuding-1','長門怨','高蟾','唐','御定全唐诗','yuding','','[]','天上何勞萬古春，君前誰是百年人。魂銷尚愧金爐燼，',40,'御定全唐詩/json/668.json','["天上何勞萬古春，君前誰是百年人。魂銷尚愧金爐燼，", "可憐明鏡來相向，何似恩光朝夕新。"]'),
('yuding-2','秋日寄華陽山人','高蟾','唐','御定全唐诗','yuding','','[]','雲木送秋何草草，風波凝冷太星星。銀鞍公子魂俱斷，',40,'御定全唐詩/json/668.json','["雲木送秋何草草，風波凝冷太星星。銀鞍公子魂俱斷，", "人間不見清涼事，猶向溪翁乞畫屏。"]'),
('yuding-3','感事','高蟾','唐','御定全唐诗','yuding','','[]','濁河從北下，清洛向東流。清濁皆如此，何人不白頭。',24,'御定全唐詩/json/668.json','["濁河從北下，清洛向東流。清濁皆如此，何人不白頭。"]'),
('yuding-4','楚思','高蟾','唐','御定全唐诗','yuding','','[]','疊浪與雲急，翠蘭和意香。風流化為雨，日暮下巫陽。',24,'御定全唐詩/json/668.json','["疊浪與雲急，翠蘭和意香。風流化為雨，日暮下巫陽。"]'),
('yuding-5','雪中','高蟾','唐','御定全唐诗','yuding','','[]','金閣倚雲開，朱軒犯雪來。三冬辛苦樣，天意似難栽。',24,'御定全唐詩/json/668.json','["金閣倚雲開，朱軒犯雪來。三冬辛苦樣，天意似難栽。"]'),
('yuding-6','道中有感','高蟾','唐','御定全唐诗','yuding','','[]','一醉六十日，一裘三十年。年華經幾日，日日掉征鞭。',24,'御定全唐詩/json/668.json','["一醉六十日，一裘三十年。年華經幾日，日日掉征鞭。"]'),
('yuding-7','宋汴道中','高蟾','唐','御定全唐诗','yuding','','[]','平野有千里，居人無一家。甲兵年正少，日久戍天涯。',24,'御定全唐詩/json/668.json','["平野有千里，居人無一家。甲兵年正少，日久戍天涯。"]'),
('yuding-8','秋思','高蟾','唐','御定全唐诗','yuding','','[]','天地太蕭索，山川何渺茫。不堪星斗柄，猶把歲寒量。',24,'御定全唐詩/json/668.json','["天地太蕭索，山川何渺茫。不堪星斗柄，猶把歲寒量。"]'),
('yuding-9','即事','高蟾','唐','御定全唐诗','yuding','','[]','三年離水石，一旦隱樵漁。為問青雲上，何人識卷舒。',24,'御定全唐詩/json/668.json','["三年離水石，一旦隱樵漁。為問青雲上，何人識卷舒。"]'),
('yuding-10','漁家','高蟾','唐','御定全唐诗','yuding','','[]','野水千年在，閑花一夕空。近來浮世狹，何似釣船中。',24,'御定全唐詩/json/668.json','["野水千年在，閑花一夕空。近來浮世狹，何似釣船中。"]'),
('yuding-11','關中','高蟾','唐','御定全唐诗','yuding','','[]','風雨去愁晚，關河歸思涼。西遊無紫氣，一夕九回腸。',24,'御定全唐詩/json/668.json','["風雨去愁晚，關河歸思涼。西遊無紫氣，一夕九回腸。"]'),
('yuding-12','歸思','高蟾','唐','御定全唐诗','yuding','','[]','紫府歸期斷，芳洲別思迢。黃金作人世，只被歲寒消。',24,'御定全唐詩/json/668.json','["紫府歸期斷，芳洲別思迢。黃金作人世，只被歲寒消。"]'),
('yuding-13','下第出春明門','高蟾','唐','御定全唐诗','yuding','','[]','曾和秋雨驅愁入，卻向春風領恨回。',32,'御定全唐詩/json/668.json','["曾和秋雨驅愁入，卻向春風領恨回。", "深謝灞陵堤畔柳，與人頭上拂塵埃。"]'),
('yuding-14','華清宮','高蟾','唐','御定全唐诗','yuding','','[]','何事金輿不再遊，翠鬟丹臉豈勝愁。',32,'御定全唐詩/json/668.json','["何事金輿不再遊，翠鬟丹臉豈勝愁。", "重門深鎖禁鐘後，月滿驪山宮樹秋。"]'),
('yuding-15','秋日北固晚望二首','高蟾','唐','御定全唐诗','yuding','','[]','風含遠思翛翛晚，日照高情的的秋。',64,'御定全唐詩/json/668.json','["風含遠思翛翛晚，日照高情的的秋。", "何事滿江惆悵水，年年無語向東流。", "澤國路岐當面苦，江城砧杵入心寒。", "不知白髮誰醫得，為問無情歲月看。"]'),
('yuding-16','送張道士','高蟾','唐','御定全唐诗','yuding','','[]','因將歲月離三島，閑貯風煙在一壺。',32,'御定全唐詩/json/668.json','["因將歲月離三島，閑貯風煙在一壺。", "為問金烏頭白後，人間流水卻回無。"]'),
('yuding-17','吳門春雨','高蟾','唐','御定全唐诗','yuding','','[]','吳甸落花春漫漫，吳宮芳樹晚沉沉。',32,'御定全唐詩/json/668.json','["吳甸落花春漫漫，吳宮芳樹晚沉沉。", "王孫不耐如絲雨，罥斷春風一寸心。"]'),
('yuding-18','旅夕','高蟾','唐','御定全唐诗','yuding','','[]','風散古陂驚宿雁，月臨荒戍起啼鴉。',32,'御定全唐詩/json/668.json','["風散古陂驚宿雁，月臨荒戍起啼鴉。", "不堪吟斷無人見，時複寒燈落一花。"]'),
('yuding-19','瓜洲夜泊','高蟾','唐','御定全唐诗','yuding','','[]','偶為芳草無情客，況是青山有事身。',32,'御定全唐詩/json/668.json','["偶為芳草無情客，況是青山有事身。", "一夕瓜洲渡頭宿，天風吹盡廣陵塵。"]'),
('yuding-20','金陵晚望','高蟾','唐','御定全唐诗','yuding','','[]','曾伴浮雲歸晚翠，猶陪落日泛秋聲。',32,'御定全唐詩/json/668.json','["曾伴浮雲歸晚翠，猶陪落日泛秋聲。", "世間無限丹青手，一片傷心畫不成。"]'),
('yuding-21','晚思','高蟾','唐','御定全唐诗','yuding','','[]','虞泉冬恨由來短，楊葉春期分外長。',32,'御定全唐詩/json/668.json','["虞泉冬恨由來短，楊葉春期分外長。", "惆悵浮生不知處，明朝依舊出滄浪。"]'),
('yuding-22','長信宮二首','高蟾','唐','御定全唐诗','yuding','','[]','天上夢魂何杳杳，日宮消息太沉沉。',64,'御定全唐詩/json/668.json','["天上夢魂何杳杳，日宮消息太沉沉。", "君恩不似黃金井，一處團圓萬丈深。", "天上鳳凰休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('yuding-23','長安旅懷','高蟾','唐','御定全唐诗','yuding','','[]','馬嘶九陌年年苦，人語千門日日新。',32,'御定全唐詩/json/668.json','["馬嘶九陌年年苦，人語千門日日新。", "唯有終南寂無事，寒光不入帝鄉塵。"]'),
('yuding-24','春','高蟾','唐','御定全唐诗','yuding','','[]','天柱幾條支白日，天門幾扇鎖明時。',64,'御定全唐詩/json/668.json','["天柱幾條支白日，天門幾扇鎖明時。", "陽春發處無根蒂，憑仗東風分外吹。", "明月斷魂清靄靄，平蕪歸思綠迢迢。", "人生莫遣頭如雪，縱得春風亦不消。"]'),
('yuding-25','秋','高蟾','唐','御定全唐诗','yuding','','[]','陽羨溪聲冷駭人，洞庭山翠晚凝神。',32,'御定全唐詩/json/668.json','["陽羨溪聲冷駭人，洞庭山翠晚凝神。", "天將金玉為風露，曾為高秋幾度貧。"]'),
('yuding-26','灞陵亭','高蟾','唐','御定全唐诗','yuding','','[]','一條歸夢朱弦直，一片離心白羽輕。',32,'御定全唐詩/json/668.json','["一條歸夢朱弦直，一片離心白羽輕。", "明日灞陵新霽後，馬頭煙樹綠相迎。"]'),
('yuding-27','偶作二首','高蟾','唐','御定全唐诗','yuding','','[]','丁當玉佩三更雨，平帖金閨一覺雲。',64,'御定全唐詩/json/668.json','["丁當玉佩三更雨，平帖金閨一覺雲。", "明日薄情何處去，風流春水不知君。", "霞衣重疊紅蟬暖，雲髻蔥籠紫鳳寒。", "天上少年分散後，一條煙水若為看。"]'),
('yuding-28','永夕','高蟾','唐','御定全唐诗','yuding','','[]','雲鴻宿處江村冷，獨狖啼時海國陰。',32,'御定全唐詩/json/668.json','["雲鴻宿處江村冷，獨狖啼時海國陰。", "不會殘燈無一事，覺來猶有向隅心。"]'),
('yuding-29','落花','高蟾','唐','御定全唐诗','yuding','','[]','一葉落時空下淚，三春歸盡複何情。',32,'御定全唐詩/json/668.json','["一葉落時空下淚，三春歸盡複何情。", "無人共得東風語，半日尊前計不成。"]'),
('yuding-30','下第後上永崇高侍郎','高蟾','唐','御定全唐诗','yuding','','[]','天上碧桃和露種，日邊紅杏倚雲栽。',32,'御定全唐詩/json/668.json','["天上碧桃和露種，日邊紅杏倚雲栽。", "芙蓉生在秋江上，不向東風怨未開。"]'),
('yuding-31','句','高蟾','唐','御定全唐诗','yuding','','[]','君恩秋後葉，日日向人疏。',30,'御定全唐詩/json/668.json','["君恩秋後葉，日日向人疏。", "知古齋主精校2000。01。22。", "j"]'),
('yuding-0','城南偶題','章碣','唐','御定全唐诗','yuding','','[]','誰家朱閣道邊開，竹拂欄幹滿壁苔。野水不知何處去，',40,'御定全唐詩/json/669.json','["誰家朱閣道邊開，竹拂欄幹滿壁苔。野水不知何處去，", "可惜登臨好光景，五門須聽鼓聲回。"]'),
('yuding-1','贈邊將','章碣','唐','御定全唐诗','yuding','','[]','千千鐵騎擁塵紅，去去平吞萬里空。宛轉龍蟠金劍雪，',40,'御定全唐詩/json/669.json','["千千鐵騎擁塵紅，去去平吞萬里空。宛轉龍蟠金劍雪，", "只有河源與遼海，如今全屬指麾中。"]'),
('yuding-2','桃源','章碣','唐','御定全唐诗','yuding','','[]','絕壁相欹是洞門，昔人從此入仙源。數株花下逢珠翠，',40,'御定全唐詩/json/669.json','["絕壁相欹是洞門，昔人從此入仙源。數株花下逢珠翠，", "山前空有無情水，猶繞當時碧樹村。"]'),
('yuding-3','曲江','章碣','唐','御定全唐诗','yuding','','[]','日照香塵逐馬蹄，風吹浪濺幾回堤。無窮羅綺填花徑，',40,'御定全唐詩/json/669.json','["日照香塵逐馬蹄，風吹浪濺幾回堤。無窮羅綺填花徑，", "只緣頻燕蓬洲客，引得遊人去似迷。"]'),
('yuding-4','送韋岫郎中典泗州','章碣','唐','御定全唐诗','yuding','','[]','玉皇恩詔別星班，去壓徐方分野間。有鳥盡巢垂汴柳，',40,'御定全唐詩/json/669.json','["玉皇恩詔別星班，去壓徐方分野間。有鳥盡巢垂汴柳，", "想憶朝天獨吟坐，旋飛新作過秦關。"]'),
('yuding-5','贈婺州蘇員外','章碣','唐','御定全唐诗','yuding','','[]','帝念瓊枝欲並芳，星分婺女寄仙郎。鸞從闕下雖辭侶，',40,'御定全唐詩/json/669.json','["帝念瓊枝欲並芳，星分婺女寄仙郎。鸞從闕下雖辭侶，", "即看龍虎西歸去，便佐羲軒活萬方。"]'),
('yuding-6','寄友人','章碣','唐','御定全唐诗','yuding','','[]','謝家山水屬君家，曾共持鉤擲歲華。竹裏竹雞眠蘚石，',40,'御定全唐詩/json/669.json','["謝家山水屬君家，曾共持鉤擲歲華。竹裏竹雞眠蘚石，", "昨日西風動歸思，滿船涼葉在天涯。"]'),
('yuding-7','雨','章碣','唐','御定全唐诗','yuding','','[]','低著煙花漠漠輕，正堪吟坐掩柴扃。亂沾細網垂窮巷，',40,'御定全唐詩/json/669.json','["低著煙花漠漠輕，正堪吟坐掩柴扃。亂沾細網垂窮巷，", "霽來還有風流事，重染南山一遍青。"]'),
('yuding-8','觀錫宴','章碣','唐','御定全唐诗','yuding','','[]','傾朝朱紫正駢闐，紅杏青莎映廣筵。不道樓臺無錦繡，',40,'御定全唐詩/json/669.json','["傾朝朱紫正駢闐，紅杏青莎映廣筵。不道樓臺無錦繡，", "日暮驊騮相擁去，幾人沉醉失金鞭。"]'),
('yuding-9','城東即事','章碣','唐','御定全唐诗','yuding','','[]','閑尋香陌鳳城東，時暫開襟向遠風。玉笛一聲芳草外，',40,'御定全唐詩/json/669.json','["閑尋香陌鳳城東，時暫開襟向遠風。玉笛一聲芳草外，", "回首漢宮煙靄裏，天河金閣未央宮。"]'),
('yuding-10','夏日湖上即事寄晉陵蕭明府','章碣','唐','御定全唐诗','yuding','','[]','亭午羲和駐火輪，開門嘉樹庇湖濆。行來賓客奇茶味，',40,'御定全唐詩/json/669.json','["亭午羲和駐火輪，開門嘉樹庇湖濆。行來賓客奇茶味，", "陶家豈是無詩酒，公退堪驚日已曛。"]'),
('yuding-11','對月','章碣','唐','御定全唐诗','yuding','','[]','殘霞卷盡出東溟，萬古難消一片冰。公子踏開香徑蘚，',40,'御定全唐詩/json/669.json','["殘霞卷盡出東溟，萬古難消一片冰。公子踏開香徑蘚，", "別有洞天三十六，水晶台殿冷層層。"]'),
('yuding-12','浙西送杜晦侍禦入關','章碣','唐','御定全唐诗','yuding','','[]','紫詔征賢發帝聰，繡衣行處撲香風。鶚歸秦樹幽禽散，',40,'御定全唐詩/json/669.json','["紫詔征賢發帝聰，繡衣行處撲香風。鶚歸秦樹幽禽散，", "鞭鞘所拂三千里，多少諸侯合避驄。"]'),
('yuding-13','寄江東道友','章碣','唐','御定全唐诗','yuding','','[]','野亭歌罷指西秦，避俗爭名興各新。碧帶黃麻呈縹緲，',40,'御定全唐詩/json/669.json','["野亭歌罷指西秦，避俗爭名興各新。碧帶黃麻呈縹緲，", "可惜人間好聲勢，片帆羸馬不相親。"]'),
('yuding-14','下第有懷','章碣','唐','御定全唐诗','yuding','','[]','故鄉朝夕有人還，欲作家書下筆難。滅燭何曾妨夜坐，',40,'御定全唐詩/json/669.json','["故鄉朝夕有人還，欲作家書下筆難。滅燭何曾妨夜坐，", "但使他年遇公道，月輪長在桂珊珊。"]'),
('yuding-15','春日經湖上友人別業','章碣','唐','御定全唐诗','yuding','','[]','何處狂歌破積愁，攜觴共下木蘭舟。綠泉濺石銀屏濕，',40,'御定全唐詩/json/669.json','["何處狂歌破積愁，攜觴共下木蘭舟。綠泉濺石銀屏濕，", "一年一電逡巡事，不合花前不醉遊。"]'),
('yuding-16','長安春日','章碣','唐','御定全唐诗','yuding','','[]','春日皇家瑞景遲，東風無力雨微微。六宮羅綺同時泊，',40,'御定全唐詩/json/669.json','["春日皇家瑞景遲，東風無力雨微微。六宮羅綺同時泊，", "輸他得路蓬洲客，紅綠山頭爛醉歸。"]'),
('yuding-17','陪浙西王侍郎夜宴','章碣','唐','御定全唐诗','yuding','','[]','深鎖雷門宴上才，旋看歌舞旋傳杯。黃金鸂鶒當筵睡，',40,'御定全唐詩/json/669.json','["深鎖雷門宴上才，旋看歌舞旋傳杯。黃金鸂鶒當筵睡，", "小儒末座頻傾耳，只怕城頭畫角催。"]'),
('yuding-18','春別','章碣','唐','御定全唐诗','yuding','','[]','擲下離觴指亂山，趨程不待鳳笙殘。花邊馬嚼金銜去，',40,'御定全唐詩/json/669.json','["擲下離觴指亂山，趨程不待鳳笙殘。花邊馬嚼金銜去，", "殷勤莫厭貂裘重，恐犯三邊五月寒。"]'),
('yuding-19','送謝進士還閩','章碣','唐','御定全唐诗','yuding','','[]','百越風煙接巨鼇，還鄉心壯不知勞。雷霆入地建溪險，',40,'御定全唐詩/json/669.json','["百越風煙接巨鼇，還鄉心壯不知勞。雷霆入地建溪險，", "名場聲利喧喧在，莫向林泉改鬢毛。"]'),
('yuding-20','焚書坑','章碣','唐','御定全唐诗','yuding','','[]','竹帛煙銷帝業虛，關河空鎖祖龍居。',32,'御定全唐詩/json/669.json','["竹帛煙銷帝業虛，關河空鎖祖龍居。", "坑灰未冷山東亂，劉項元來不讀書。"]'),
('yuding-21','東都望幸','章碣','唐','御定全唐诗','yuding','','[]','懶修珠翠上高臺，眉月連娟恨不開。',32,'御定全唐詩/json/669.json','["懶修珠翠上高臺，眉月連娟恨不開。", "縱使東巡也無益，君王自領美人來。"]'),
('yuding-22','旅舍早起','章碣','唐','御定全唐诗','yuding','','[]','跡暗心多感，神疲夢不遊。驚舟同厭夜，獨樹對悲秋。',48,'御定全唐詩/json/669.json','["跡暗心多感，神疲夢不遊。驚舟同厭夜，獨樹對悲秋。", "晚角和人戰，殘星入漢流。門前早行子，敲鐙唱離憂。"]'),
('yuding-23','癸卯歲毗陵登高會中貽同志','章碣','唐','御定全唐诗','yuding','','[]','流落常嗟勝會稀，故人相遇菊花時。鳳笙龍笛數巡酒，',40,'御定全唐詩/json/669.json','["流落常嗟勝會稀，故人相遇菊花時。鳳笙龍笛數巡酒，", "長楊羽獵須留本，開濟重為闕下期。"]'),
('yuding-24','上元夜建元寺觀燈呈智通上人','章碣','唐','御定全唐诗','yuding','','[]','建元看別上元燈，處處回廊鬥火層。珠玉亂拋高殿佛，',40,'御定全唐詩/json/669.json','["建元看別上元燈，處處回廊鬥火層。珠玉亂拋高殿佛，", "無限喧闐留不得，月華西下露華凝。"]'),
('yuding-25','《變體詩','章碣','唐','御定全唐诗','yuding','','[]','東南路盡吳江畔，正是窮愁暮雨天。鷗鷺不嫌斜兩岸，',40,'御定全唐詩/json/669.json','["東南路盡吳江畔，正是窮愁暮雨天。鷗鷺不嫌斜兩岸，", "今古若論英達算，鴟夷高興固無邊。"]'),
('yuding-0','長安書懷','秦韜玉','唐','御定全唐诗','yuding','','[]','涼風吹雨滴寒更，鄉思欺人撥不平。長有歸心懸馬首，',40,'御定全唐詩/json/670.json','["涼風吹雨滴寒更，鄉思欺人撥不平。長有歸心懸馬首，", "早晚身閑著蓑去，橘香深處釣船橫。"]'),
('yuding-1','檜樹','秦韜玉','唐','御定全唐诗','yuding','','[]','翠雲交乾瘦輪囷，嘯雨吟風幾百春。深蓋屈盤青麈尾，',40,'御定全唐詩/json/670.json','["翠雲交乾瘦輪囷，嘯雨吟風幾百春。深蓋屈盤青麈尾，", "歲月如波事如夢，竟留蒼翠待何人。"]'),
('yuding-2','讀五侯傳','秦韜玉','唐','御定全唐诗','yuding','','[]','漢亡金鏡道將衰，便有奸臣競佐時。專國只誇兄弟貴，',40,'御定全唐詩/json/670.json','["漢亡金鏡道將衰，便有奸臣競佐時。專國只誇兄弟貴，", "朱紫盈門自稱貴，可嗟區宇盡瘡痍。"]'),
('yuding-3','春雪','秦韜玉','唐','御定全唐诗','yuding','','[]','雲重寒空思寂寥，玉塵如糝滿春朝。片才著地輕輕陷，',40,'御定全唐詩/json/670.json','["雲重寒空思寂寥，玉塵如糝滿春朝。片才著地輕輕陷，", "誰家醉卷珠簾看，弦管堂深暖易調。"]'),
('yuding-4','貧女','秦韜玉','唐','御定全唐诗','yuding','','[]','蓬門未識綺羅香，擬托良媒益自傷。誰愛風流高格調，',40,'御定全唐詩/json/670.json','["蓬門未識綺羅香，擬托良媒益自傷。誰愛風流高格調，", "苦恨年年壓金線，為他人作嫁衣裳。"]'),
('yuding-5','題竹','秦韜玉','唐','御定全唐诗','yuding','','[]','削玉森森幽思清，院家高興尚分明。捲簾陰薄漏山色，',40,'御定全唐詩/json/670.json','["削玉森森幽思清，院家高興尚分明。捲簾陰薄漏山色，", "卻驚九陌輪蹄外，獨有溪煙數十莖。"]'),
('yuding-6','鸚鵡','秦韜玉','唐','御定全唐诗','yuding','','[]','每聞別雁競悲鳴，卻歎金籠寄此生。早是翠襟爭愛惜，',40,'御定全唐詩/json/670.json','["每聞別雁競悲鳴，卻歎金籠寄此生。早是翠襟爭愛惜，", "幸自禰衡人未識，賺他作賦被時輕。"]'),
('yuding-7','寄李處士','秦韜玉','唐','御定全唐诗','yuding','','[]','呂望甘羅道已彰，只憑時數為門張。世途必竟皆應定，',40,'御定全唐詩/json/670.json','["呂望甘羅道已彰，只憑時數為門張。世途必竟皆應定，", "因君指似封侯骨，漸擬回頭別醉鄉。"]'),
('yuding-8','對花','秦韜玉','唐','御定全唐诗','yuding','','[]','長與韶光暗有期，可憐蜂蝶卻先知。誰家促席臨低樹，',40,'御定全唐詩/json/670.json','["長與韶光暗有期，可憐蜂蝶卻先知。誰家促席臨低樹，", "向人雖道渾無語，笑勸王孫到醉時。"]'),
('yuding-9','寄懷','秦韜玉','唐','御定全唐诗','yuding','','[]','總藏心劍事儒風，大道如今已渾同。會致名津搜俊彥，',40,'御定全唐詩/json/670.json','["總藏心劍事儒風，大道如今已渾同。會致名津搜俊彥，", "若使重生太平日，也應回首哭途窮。"]'),
('yuding-10','題刑部李郎中山亭','秦韜玉','唐','御定全唐诗','yuding','','[]','儂家雲水本相知，每到高齋強展眉。瘦竹嚲煙遮板閣，',40,'御定全唐詩/json/670.json','["儂家雲水本相知，每到高齋強展眉。瘦竹嚲煙遮板閣，", "不是主人多野興，肯開青眼重漁師。"]'),
('yuding-11','八月十五日夜同衛諫議看月','秦韜玉','唐','御定全唐诗','yuding','','[]','常時月好賴新晴，不似年年此夜生。初出海濤疑尚濕，',40,'御定全唐詩/json/670.json','["常時月好賴新晴，不似年年此夜生。初出海濤疑尚濕，", "豈獨座中堪仰望，孤高應到鳳凰城。"]'),
('yuding-12','亭台','秦韜玉','唐','御定全唐诗','yuding','','[]','雕楹累棟架崔嵬，院宇生煙次第開。為向西窗添月色，',40,'御定全唐詩/json/670.json','["雕楹累棟架崔嵬，院宇生煙次第開。為向西窗添月色，", "清境漸深官轉重，春時長是別人來。"]'),
('yuding-13','邊將','秦韜玉','唐','御定全唐诗','yuding','','[]','劍光如電馬如風，百捷長輕是掌中。無定河邊蕃將死，',40,'御定全唐詩/json/670.json','["劍光如電馬如風，百捷長輕是掌中。無定河邊蕃將死，", "自指燕山最高石，不知誰為勒殊功。"]'),
('yuding-14','塞下','秦韜玉','唐','御定全唐诗','yuding','','[]','到處人皆著戰袍，麾旗風緊馬蹄勞。黑山霜重弓添硬，',40,'御定全唐詩/json/670.json','["到處人皆著戰袍，麾旗風緊馬蹄勞。黑山霜重弓添硬，", "鳳林關外皆唐土，何日陳兵戍不毛。"]'),
('yuding-15','織錦婦','秦韜玉','唐','御定全唐诗','yuding','','[]','桃花日日覓新奇，有鏡何曾及畫眉。只恐輕梭難作匹，',40,'御定全唐詩/json/670.json','["桃花日日覓新奇，有鏡何曾及畫眉。只恐輕梭難作匹，", "豪貴大堆酬曲徹，可憐辛苦一絲絲。"]'),
('yuding-16','釣翁','秦韜玉','唐','御定全唐诗','yuding','','[]','一竿青竹老江隈，荷葉衣裳可自裁。潭定靜懸絲影直，',40,'御定全唐詩/json/670.json','["一竿青竹老江隈，荷葉衣裳可自裁。潭定靜懸絲影直，", "世上無窮嶮巇事，算應難入釣船來。"]'),
('yuding-17','曲江','秦韜玉','唐','御定全唐诗','yuding','','[]','曲沼深塘躍錦鱗，槐煙徑裏碧波新。此中境既無佳境，',40,'御定全唐詩/json/670.json','["曲沼深塘躍錦鱗，槐煙徑裏碧波新。此中境既無佳境，", "明年二月重來看，好共東風作主人。"]'),
('yuding-18','隋堤','秦韜玉','唐','御定全唐诗','yuding','','[]','種柳開河為勝遊，堤前常使路人愁。陰埋野色萬條思，',40,'御定全唐詩/json/670.json','["種柳開河為勝遊，堤前常使路人愁。陰埋野色萬條思，", "遠山應見繁華事，不語青青對水流。"]'),
('yuding-19','天街','秦韜玉','唐','御定全唐诗','yuding','','[]','九衢風景盡爭新，獨佔天門近紫宸。寶馬競隨朝暮客，',40,'御定全唐詩/json/670.json','["九衢風景盡爭新，獨佔天門近紫宸。寶馬競隨朝暮客，", "莫見繁華只如此，暗中還換往來人。"]'),
('yuding-20','紫騮馬','秦韜玉','唐','御定全唐诗','yuding','','[]','渥窪奇骨本難求，況是豪家重紫騮。膘大宜懸銀壓胯，',40,'御定全唐詩/json/670.json','["渥窪奇骨本難求，況是豪家重紫騮。膘大宜懸銀壓胯，", "若遇丈夫能控馭，任從騎取覓封侯。"]'),
('yuding-21','問古','秦韜玉','唐','御定全唐诗','yuding','','[]','大底榮枯各自行，兼疑陰騭也難明。無門雪向頭中出，',40,'御定全唐詩/json/670.json','["大底榮枯各自行，兼疑陰騭也難明。無門雪向頭中出，", "都來總向人間看，直到皇天可是平。"]'),
('yuding-22','豪家','秦韜玉','唐','御定全唐诗','yuding','','[]','石甃通渠引禦波，綠槐陰裏五侯家。地衣鎮角香獅子，',40,'御定全唐詩/json/670.json','["石甃通渠引禦波，綠槐陰裏五侯家。地衣鎮角香獅子，", "四鄰池館吞將盡，尚自堆金為買花。"]'),
('yuding-23','陳宮','秦韜玉','唐','御定全唐诗','yuding','','[]','臨春高閣擬瀛洲，貪寵張妃作勝遊。更把江山為己有，',40,'御定全唐詩/json/670.json','["臨春高閣擬瀛洲，貪寵張妃作勝遊。更把江山為己有，", "誰識古宮堪恨處，井桐吟雨不勝秋。"]'),
('yuding-24','送友人罷舉授南陵令','秦韜玉','唐','御定全唐诗','yuding','','[]','共言愁是酌離杯，況值弦歌枉大才。獻賦未為龍化去，',40,'御定全唐詩/json/670.json','["共言愁是酌離杯，況值弦歌枉大才。獻賦未為龍化去，", "莫把新詩題別處，謝家臨水有池台。"]'),
('yuding-25','投知己','秦韜玉','唐','御定全唐诗','yuding','','[]','爐中九轉煉雖成，教主看時亦自驚。群嶽並天先減翠，',40,'御定全唐詩/json/670.json','["爐中九轉煉雖成，教主看時亦自驚。群嶽並天先減翠，", "唯有太平方寸血，今朝盡向隗台傾。"]'),
('yuding-26','牡丹','秦韜玉','唐','御定全唐诗','yuding','','[]','拆妖放豔有誰催，疑就仙中旋折來。圖把一春皆占斷，',40,'御定全唐詩/json/670.json','["拆妖放豔有誰催，疑就仙中旋折來。圖把一春皆占斷，", "好是酒闌絲竹罷，倚風含笑向樓臺。"]'),
('yuding-27','春遊','秦韜玉','唐','御定全唐诗','yuding','','[]','選勝逢君敘解攜，思和芳草遠煙迷。小梅香裏黃鶯囀，',40,'御定全唐詩/json/670.json','["選勝逢君敘解攜，思和芳草遠煙迷。小梅香裏黃鶯囀，", "早知有此關身事，悔不前年住越溪。"]'),
('yuding-28','仙掌','秦韜玉','唐','御定全唐诗','yuding','','[]','萬仞連峰積翠新，靈蹤依舊印輪巡。何如捧日安皇道，',40,'御定全唐詩/json/670.json','["萬仞連峰積翠新，靈蹤依舊印輪巡。何如捧日安皇道，", "為餘勢負天工背，索取風雲際會身。"]'),
('yuding-29','燕子','秦韜玉','唐','御定全唐诗','yuding','','[]','不知大廈許棲無，頻已銜泥到座隅。',32,'御定全唐詩/json/670.json','["不知大廈許棲無，頻已銜泥到座隅。", "曾與佳人並頭語，幾回拋卻繡工夫。"]'),
('yuding-30','奉和春日玩雪','秦韜玉','唐','御定全唐诗','yuding','','[]','北闕同雲掩曉霞，東風春雪滿山家。',32,'御定全唐詩/json/670.json','["北闕同雲掩曉霞，東風春雪滿山家。", "瓊章定少千人和，銀樹先開六出花。"]'),
('yuding-31','獨坐吟','秦韜玉','唐','御定全唐诗','yuding','','[]','客愁不盡本如水，草色含情更無已。',32,'御定全唐詩/json/670.json','["客愁不盡本如水，草色含情更無已。", "又覺春愁似草生，何人種在情田裏。"]'),
('yuding-32','採茶歌','秦韜玉','唐','御定全唐诗','yuding','','[]','天柱香芽露香發，爛研瑟瑟穿荻篾。太守憐才寄野人，',64,'御定全唐詩/json/670.json','["天柱香芽露香發，爛研瑟瑟穿荻篾。太守憐才寄野人，", "看著晴天早日明，鼎中颯颯篩風雨。老翠看塵下才熟，", "洗我胸中幽思清，鬼神應愁歌欲成。"]'),
('yuding-33','貴公子行','秦韜玉','唐','御定全唐诗','yuding','','[]','階前莎球綠不卷，銀龜噴香挽不斷。亂花織錦柳撚線，',48,'御定全唐詩/json/670.json','["階前莎球綠不卷，銀龜噴香挽不斷。亂花織錦柳撚線，", "鬥雞走狗家世事，抱來皆佩黃金魚。卻笑儒生把書卷，"]'),
('yuding-34','吹笙歌','秦韜玉','唐','御定全唐诗','yuding','','[]','信陵名重憐高才，見我長吹青眼開。便出燕姬再傾醑，',72,'御定全唐詩/json/670.json','["信陵名重憐高才，見我長吹青眼開。便出燕姬再傾醑，", "逸豔初因醉態見，濃春可是韶光與。纖纖軟玉捧暖笙，", "岐山取得嬌鳳雛，管中藏著輕輕語。好笑襄王大迂闊，"]'),
('yuding-35','詠手','秦韜玉','唐','御定全唐诗','yuding','','[]','一雙十指玉纖纖，不是風流物不拈。鸞鏡巧梳勻翠黛，',40,'御定全唐詩/json/670.json','["一雙十指玉纖纖，不是風流物不拈。鸞鏡巧梳勻翠黛，", "因把剪刀嫌道冷，泥人呵了弄人髯。"]'),
('yuding-36','句','秦韜玉','唐','御定全唐诗','yuding','','[]','女媧羅裙長百尺，搭在湘江作山色。（《瀟湘》。',30,'御定全唐詩/json/670.json','["女媧羅裙長百尺，搭在湘江作山色。（《瀟湘》。", "見《詩話總龜》）"]'),
('yuding-0','逢韓喜','唐彥謙','唐','御定全唐诗','yuding','','[]','相逢渾不覺，只似茂陵貧。嫋嫋花驕客，瀟瀟雨淨春。',48,'御定全唐詩/json/671.json','["相逢渾不覺，只似茂陵貧。嫋嫋花驕客，瀟瀟雨淨春。", "借書消茗困，索句寫梅真。此去青雲上，知君有幾人。"]'),
('yuding-1','夜坐示友','唐彥謙','唐','御定全唐诗','yuding','','[]','夜久燭花落，淒聲生遠林。有懷嫌會淺，無事又秋深。',48,'御定全唐詩/json/671.json','["夜久燭花落，淒聲生遠林。有懷嫌會淺，無事又秋深。", "黃葉歸田夢，白頭行路吟。山中亦可樂，不似此同襟。"]'),
('yuding-2','梅亭','唐彥謙','唐','御定全唐诗','yuding','','[]','東海窮詩客，西風古驛亭。發從殘歲白，山入故鄉青。',48,'御定全唐詩/json/671.json','["東海窮詩客，西風古驛亭。發從殘歲白，山入故鄉青。", "世事徒三窟，兒曹且一經。丁寧速賒酒，煮栗試砂瓶。"]'),
('yuding-3','歲除','唐彥謙','唐','御定全唐诗','yuding','','[]','索索風搜客，沉沉雨洗年。殘林生獵跡，歸鳥避窯煙。',48,'御定全唐詩/json/671.json','["索索風搜客，沉沉雨洗年。殘林生獵跡，歸鳥避窯煙。", "節物杯漿外，溪山鬢影前。行藏都未定，筆硯或能捐。"]'),
('yuding-4','詠月','唐彥謙','唐','御定全唐诗','yuding','','[]','陰盛此宵中，多為雨與風。坐無風雨至，看與雪霜同。',48,'御定全唐詩/json/671.json','["陰盛此宵中，多為雨與風。坐無風雨至，看與雪霜同。", "抱濕離遙海，傾寒向遠空。年年不相值，還似道難通。"]'),
('yuding-5','聞應德茂先離棠溪','唐彥謙','唐','御定全唐诗','yuding','','[]','落日蘆花雨，行人谷樹村。青山時問路，紅葉自知門。',48,'御定全唐詩/json/671.json','["落日蘆花雨，行人谷樹村。青山時問路，紅葉自知門。", "苜蓿窮詩味，芭蕉醉墨痕。端知棄城市，經席許頻溫。"]'),
('yuding-6','松','唐彥謙','唐','御定全唐诗','yuding','','[]','托根蟠泰華，倚幹蝕莓苔。誰雲山澤間，而無梁棟材。',24,'御定全唐詩/json/671.json','["托根蟠泰華，倚幹蝕莓苔。誰雲山澤間，而無梁棟材。"]'),
('yuding-7','梅','唐彥謙','唐','御定全唐诗','yuding','','[]','玉人下瑤台，香風動輕素。畫角弄江城，鳴璫月中墮。',24,'御定全唐詩/json/671.json','["玉人下瑤台，香風動輕素。畫角弄江城，鳴璫月中墮。"]'),
('yuding-8','蘭二首','唐彥謙','唐','御定全唐诗','yuding','','[]','清風搖翠環，涼露滴蒼玉。美人胡不紉，幽香藹空穀。',48,'御定全唐詩/json/671.json','["清風搖翠環，涼露滴蒼玉。美人胡不紉，幽香藹空穀。", "謝庭漫芳草，楚畹多綠莎。于焉忽相見，歲晏將如何。"]'),
('yuding-9','葡萄','唐彥謙','唐','御定全唐诗','yuding','','[]','金穀風露涼，綠珠醉初醒。珠帳夜不收，月明墮清影。',24,'御定全唐詩/json/671.json','["金穀風露涼，綠珠醉初醒。珠帳夜不收，月明墮清影。"]'),
('yuding-10','春草','唐彥謙','唐','御定全唐诗','yuding','','[]','隨夢入池塘，無心在金穀。青風自年年，吹遍天涯綠。',24,'御定全唐詩/json/671.json','["隨夢入池塘，無心在金穀。青風自年年，吹遍天涯綠。"]'),
('yuding-11','漁','唐彥謙','唐','御定全唐诗','yuding','','[]','相聚即為鄰，煙火自成簇。約伴過前溪，撐破蘼蕪綠。',24,'御定全唐詩/json/671.json','["相聚即為鄰，煙火自成簇。約伴過前溪，撐破蘼蕪綠。"]'),
('yuding-12','留別四首','唐彥謙','唐','御定全唐诗','yuding','','[]','鵬程三萬里，別酒一千鐘。好景當三月，春光上國濃。',96,'御定全唐詩/json/671.json','["鵬程三萬里，別酒一千鐘。好景當三月，春光上國濃。", "野花紅滴滴，江燕語喃喃。鼓吹翻新調，都亭酒正酣。", "登庸趨俊乂，廁用野無遺。起喜賡歌日，明良際會時。", "鹽車淹素志，長阪入青雲。老驥春風裏，奔騰獨異群。"]'),
('yuding-13','秋葵','唐彥謙','唐','御定全唐诗','yuding','','[]','月瓣團欒剪赭羅，長條排蕊綴鳴珂。',32,'御定全唐詩/json/671.json','["月瓣團欒剪赭羅，長條排蕊綴鳴珂。", "傾陽一點丹心在，承得中天雨露多。"]'),
('yuding-14','春草','唐彥謙','唐','御定全唐诗','yuding','','[]','天北天南繞路邊，托根無處不延綿。',32,'御定全唐詩/json/671.json','["天北天南繞路邊，托根無處不延綿。", "萋萋總是無情物，吹綠東風又一年。"]'),
('yuding-15','春日偶成','唐彥謙','唐','御定全唐诗','yuding','','[]','dG箏簫管和琵琶，興滿金尊酒量賒。',33,'御定全唐詩/json/671.json','["dG箏簫管和琵琶，興滿金尊酒量賒。", "歌舞留春春似海，美人顏色正如花。"]'),
('yuding-16','秋日感懷','唐彥謙','唐','御定全唐诗','yuding','','[]','溪上芙蓉映醉顏，悲秋宋玉鬢毛斑。',32,'御定全唐詩/json/671.json','["溪上芙蓉映醉顏，悲秋宋玉鬢毛斑。", "無情最恨東流水，暗逐芳年去不還。"]'),
('yuding-17','七夕','唐彥謙','唐','御定全唐诗','yuding','','[]','會合無由歎久違，一年一度是緣非。',32,'御定全唐詩/json/671.json','["會合無由歎久違，一年一度是緣非。", "而予願乞天孫巧，五色紉針補袞衣。"]'),
('yuding-18','懷友','唐彥謙','唐','御定全唐诗','yuding','','[]','金井涼生梧葉秋，閑看新月上簾鉤。',32,'御定全唐詩/json/671.json','["金井涼生梧葉秋，閑看新月上簾鉤。", "冰壺總憶人如玉，目斷重雲十二樓。"]'),
('yuding-19','翡翠','唐彥謙','唐','御定全唐诗','yuding','','[]','莎草江汀漫晚潮，翠華香撲水光遙。',32,'御定全唐詩/json/671.json','["莎草江汀漫晚潮，翠華香撲水光遙。", "玉樓春暖笙歌夜，妝點花鈿上舞翹。"]'),
('yuding-20','詠馬二首','唐彥謙','唐','御定全唐诗','yuding','','[]','紫雲團影電飛瞳，駿骨龍媒自不同。',64,'御定全唐詩/json/671.json','["紫雲團影電飛瞳，駿骨龍媒自不同。", "騎過玉樓金轡響，一聲嘶斷落花風。", "崚嶒高聳骨如山，遠放春郊苜蓿間。", "百戰沙場汗流血，夢魂猶在玉門關。"]'),
('yuding-21','留別','唐彥謙','唐','御定全唐诗','yuding','','[]','丹湖湖上送行舟，白雁啼殘蘆葉秋。',32,'御定全唐詩/json/671.json','["丹湖湖上送行舟，白雁啼殘蘆葉秋。", "採石江頭舊時路，題詩還憶水邊樓。"]'),
('yuding-22','詠竹','唐彥謙','唐','御定全唐诗','yuding','','[]','醉臥涼陰沁骨清，石床冰簟夢難成。',32,'御定全唐詩/json/671.json','["醉臥涼陰沁骨清，石床冰簟夢難成。", "月明午夜生虛籟，誤聽風聲是雨聲。"]'),
('yuding-23','憶孟浩然','唐彥謙','唐','御定全唐诗','yuding','','[]','郊外淩兢西複東，雪晴驢背興無窮。',32,'御定全唐詩/json/671.json','["郊外淩兢西複東，雪晴驢背興無窮。", "句搜明月梨花內，趣入春風柳絮中。"]'),
('yuding-24','寄友三首','唐彥謙','唐','御定全唐诗','yuding','','[]','新酒秦淮縮項鯿，淩霄花下共流連。',96,'御定全唐詩/json/671.json','["新酒秦淮縮項鯿，淩霄花下共流連。", "別來客邸空翹首，細雨春風憶往年。", "寒燈孤對擁青氈，牢落何如似客邊。", "卻憶花前酣後飲，醉呼明月上遙天。", "客裏逢春一惘然，梅花落盡柳如煙。", "無情最恨東來雁，底事音書不肯傳。"]'),
('yuding-25','無題十首','唐彥謙','唐','御定全唐诗','yuding','','[]','細草鋪茵綠滿堤，燕飛晴日正遲遲。',320,'御定全唐詩/json/671.json','["細草鋪茵綠滿堤，燕飛晴日正遲遲。", "尋芳陌上花如錦，折得東風第一枝。", "錦箏銀甲響鶤弦，勾引春聲上綺筵。", "醉倚闌幹花下月，犀梳斜嚲鬢雲邊。", "楚雲湘雨會陽臺，錦帳芙蓉向夜開。", "吹罷玉簫春似海，一雙彩鳳忽飛來。", "春江新水促歸航，惜別花前酒漫觴。", "倒盡銀瓶渾不醉，卻憐和淚入愁腸。", "誰知別易會應難，目斷青鸞信渺漫。", "情似藍橋橋下水，年來流恨幾時幹。", "漏滴銅龍夜已深，柳梢斜月弄疏陰。", "滿園芳草年年恨，剔盡燈花夜夜心。", "夜合庭前花正開，輕羅小扇為誰裁。", "多情驚起雙蝴蝶，飛入巫山夢裏來。", "憶別悠悠歲月長，酒兵無計敵愁腸。", "柔絲漫折長亭柳，綰得同心欲寄將。", "楊柳青青映畫樓，翠眉終日鎖離愁。", "杜鵑啼落枝頭月，多為傷春恨不休。", "雲色鮫綃拭淚顏，一簾春雨杏花寒。", "幾時重會鴛鴦侶，月下吹笙和彩鸞。"]'),
('yuding-26','寄同上人','唐彥謙','唐','御定全唐诗','yuding','','[]','高高山頂寺，更有最高人。定起松鳴屋，吟圓月上身。',48,'御定全唐詩/json/671.json','["高高山頂寺，更有最高人。定起松鳴屋，吟圓月上身。", "雲藏三伏熱，水散百溪津。曾乞蘭花供，無書又過春。"]'),
('yuding-27','夜坐','唐彥謙','唐','御定全唐诗','yuding','','[]','愁鬢丁年白，寒燈丙夜青。不眠驚戍鼓，久客厭郵鈴。',48,'御定全唐詩/json/671.json','["愁鬢丁年白，寒燈丙夜青。不眠驚戍鼓，久客厭郵鈴。", "洶洶城噴海，疏疏屋漏星。十年窮父子，相守慰飄零。"]'),
('yuding-28','吊方幹處士二首','唐彥謙','唐','御定全唐诗','yuding','','[]','不謂高名下，終全玉雪身。交猶及前輩，語不似今人。',96,'御定全唐詩/json/671.json','["不謂高名下，終全玉雪身。交猶及前輩，語不似今人。", "別號行鳴雁，遺編感獲麟。斂衣應自定，只著古衣巾。", "不比他人死，何詩可挽君。淵明元懶仕，東野別攻文。", "滄海諸公淚，青山處士墳。相看莫浪哭，私諡有前聞。"]'),
('yuding-29','題證道寺','唐彥謙','唐','御定全唐诗','yuding','','[]','彎環青徑斜，自是野僧家。滿澗洗岩液，插天排石牙。',48,'御定全唐詩/json/671.json','["彎環青徑斜，自是野僧家。滿澗洗岩液，插天排石牙。", "爐寒餘柏子，架靜落藤花。記得逃兵日，門多貴客車。"]'),
('yuding-30','宿趙gj別業','唐彥謙','唐','御定全唐诗','yuding','','[]','溪山兵後縣，風雪旅中人。迫夜愁嚴鼓，沖寒托軟巾。',48,'御定全唐詩/json/671.json','["溪山兵後縣，風雪旅中人。迫夜愁嚴鼓，沖寒托軟巾。", "摧藏名字在，疏率饌殽真。今代徐元直，高風自可親。"]'),
('yuding-31','原上','唐彥謙','唐','御定全唐诗','yuding','','[]','危橋橫古渡，村野帶平林。野鶩寒塘靜，山禽曉樹深。',48,'御定全唐詩/json/671.json','["危橋橫古渡，村野帶平林。野鶩寒塘靜，山禽曉樹深。", "雨微風矗□，雲暗雪侵尋。安道門前水，清遊豈獨吟。"]'),
('yuding-32','寄台省知己','唐彥謙','唐','御定全唐诗','yuding','','[]','久懷聲籍甚，千里致雙魚。宦路終推轂，親幃且著書。',48,'御定全唐詩/json/671.json','["久懷聲籍甚，千里致雙魚。宦路終推轂，親幃且著書。", "才名賈太傅，文學馬相如。轍跡東巡海，何時適我閭。"]'),
('yuding-33','自詠','唐彥謙','唐','御定全唐诗','yuding','','[]','白髮三千丈，青春四十年。兩牙搖欲落，雙膝痹如攣。',48,'御定全唐詩/json/671.json','["白髮三千丈，青春四十年。兩牙搖欲落，雙膝痹如攣。", "強仕非時彥，無聞惜昔賢。自期終見惡，未忍舍遺編。"]'),
('yuding-34','游陽明洞呈王理得諸君','唐彥謙','唐','御定全唐诗','yuding','','[]','禹穴蒼茫不可探，人傳靈笈鎖煙嵐。初晴鶴點青邊嶂，',40,'御定全唐詩/json/671.json','["禹穴蒼茫不可探，人傳靈笈鎖煙嵐。初晴鶴點青邊嶂，", "堪憐尹叟非關吏，猶向江南逐老聃。"]'),
('yuding-35','新豐','唐彥謙','唐','御定全唐诗','yuding','','[]','沛中歌舞百餘人，帝業功成裏巷新。半夜素靈先哭楚，',40,'御定全唐詩/json/671.json','["沛中歌舞百餘人，帝業功成裏巷新。半夜素靈先哭楚，", "惆悵故園前事遠，曉風長路起埃塵。"]'),
('yuding-36','拜越公墓因游定水寺有懷源老','唐彥謙','唐','御定全唐诗','yuding','','[]','越公已作飛仙去，猶得潭潭好墓田。老樹背風深拓地，',40,'御定全唐詩/json/671.json','["越公已作飛仙去，猶得潭潭好墓田。老樹背風深拓地，", "我與源公舊相識，遺言瀟灑有人傳。"]'),
('yuding-37','任潛謀隱之作','唐彥謙','唐','御定全唐诗','yuding','','[]','江邊秋日逢任子，大理索詩吾欲忘。為問山資何次第，',40,'御定全唐詩/json/671.json','["江邊秋日逢任子，大理索詩吾欲忘。為問山資何次第，", "千古浮雲共歸思，曉風城郭水花香。"]'),
('yuding-38','晚秋遊中溪','唐彥謙','唐','御定全唐诗','yuding','','[]','淡竹岡前沙雁飛，小花尖下柘丸肥。山雲不卷雨自薄，',40,'御定全唐詩/json/671.json','["淡竹岡前沙雁飛，小花尖下柘丸肥。山雲不卷雨自薄，", "故人舊業依稀在，怪石老松今是非。"]'),
('yuding-39','寄陳少府兼簡叔高','唐彥謙','唐','御定全唐诗','yuding','','[]','懷人路絕雲歸海，避俗門深草蔽丘。萬事漸消閒客夢，',40,'御定全唐詩/json/671.json','["懷人路絕雲歸海，避俗門深草蔽丘。萬事漸消閒客夢，", "近日鄰家有新釀，每逢詩伴得淹留。"]'),
('yuding-40','過清涼寺王導墓下','唐彥謙','唐','御定全唐诗','yuding','','[]','江左風流廊廟人，荒墳拋與梵宮鄰。多年羊虎猶眠石，',40,'御定全唐詩/json/671.json','["江左風流廊廟人，荒墳拋與梵宮鄰。多年羊虎猶眠石，", "永思陵下猶淒切，廢屋寒風吹野薪。"]'),
('yuding-41','第三溪','唐彥謙','唐','御定全唐诗','yuding','','[]','日晏霜濃十二月，林疏石瘦第三溪。雲沙有徑縈寒燒，',40,'御定全唐詩/json/671.json','["日晏霜濃十二月，林疏石瘦第三溪。雲沙有徑縈寒燒，", "早知涉世真成夢，不棄山田春雨犁。"]'),
('yuding-42','蒲津河亭','唐彥謙','唐','御定全唐诗','yuding','','[]','宿雨清秋霽景澄，廣亭高樹向晨興。煙橫博望乘槎水，',40,'御定全唐詩/json/671.json','["宿雨清秋霽景澄，廣亭高樹向晨興。煙橫博望乘槎水，", "思鄉懷古多傷別，況此哀吟意不勝。"]'),
('yuding-43','毗陵道中','唐彥謙','唐','御定全唐诗','yuding','','[]','百年只有百清明，狼狽今年又避兵。煙火誰開寒食禁，',40,'御定全唐詩/json/671.json','["百年只有百清明，狼狽今年又避兵。煙火誰開寒食禁，", "渺渺飛鴻天斷處，古來還是闔閭城。"]'),
('yuding-44','越城待旦','唐彥謙','唐','御定全唐诗','yuding','','[]','策策虛樓竹隔明，悲來輾轉向誰傾。天寒胡雁出萬里，',40,'御定全唐詩/json/671.json','["策策虛樓竹隔明，悲來輾轉向誰傾。天寒胡雁出萬里，", "清溪白石村村有，五尺烏犍托此生。"]'),
('yuding-45','過浩然先生墓','唐彥謙','唐','御定全唐诗','yuding','','[]','人間萬卷龐眉老，眼見堂堂入草萊。行客須當下馬過，',40,'御定全唐詩/json/671.json','["人間萬卷龐眉老，眼見堂堂入草萊。行客須當下馬過，", "猶勝黃金買碑碣，百年名字已煙埃。"]'),
('yuding-46','贈孟德茂','唐彥謙','唐','御定全唐诗','yuding','','[]','江海悠悠雪欲飛，抱書空出又空歸。沙頭人滿鷗應笑，',40,'御定全唐詩/json/671.json','["江海悠悠雪欲飛，抱書空出又空歸。沙頭人滿鷗應笑，", "平生萬卷應夫子，兩世功名窮布衣。"]'),
('yuding-47','秋霽豐德寺與玄貞師詠月','唐彥謙','唐','御定全唐诗','yuding','','[]','露冷風輕霽魄圓，高樓更在碧山巔。四溟水合疑無地，',40,'御定全唐詩/json/671.json','["露冷風輕霽魄圓，高樓更在碧山巔。四溟水合疑無地，", "夜深獨與岩僧語，群動消聲舉世眠。"]'),
('yuding-48','長陵','唐彥謙','唐','御定全唐诗','yuding','','[]','長安高闕此安劉，祔葬累累盡列侯。豐上舊居無故裏，',40,'御定全唐詩/json/671.json','["長安高闕此安劉，祔葬累累盡列侯。豐上舊居無故裏，", "千載腐儒騎瘦馬，渭城斜月重回頭。"]'),
('yuding-49','留別','唐彥謙','唐','御定全唐诗','yuding','','[]','西入潼關路，何時更盍簪。年來人事改，老去鬢毛侵。',48,'御定全唐詩/json/671.json','["西入潼關路，何時更盍簪。年來人事改，老去鬢毛侵。", "花染離筵淚，葵傾報國心。龍潭千尺水，不似別情深。"]'),
('yuding-50','宿獨留','唐彥謙','唐','御定全唐诗','yuding','','[]','日晚宿留城，人家半掩門。群鴉棲老樹，一犬吠荒村。',48,'御定全唐詩/json/671.json','["日晚宿留城，人家半掩門。群鴉棲老樹，一犬吠荒村。", "爭買魚添價，新篘酒帶渾。船頭對新月，誰與共清論。"]'),
('yuding-51','客中感懷','唐彥謙','唐','御定全唐诗','yuding','','[]','客路三千里，西風兩鬢塵。貪名笑吳起，說國歎蘇秦。',48,'御定全唐詩/json/671.json','["客路三千里，西風兩鬢塵。貪名笑吳起，說國歎蘇秦。", "托興非耽酒，思家豈為蓴。可憐今夜月，獨照異鄉人。"]'),
('yuding-52','過三山寺','唐彥謙','唐','御定全唐诗','yuding','','[]','三山江上寺，宮殿望岧嶢。石徑侵高樹，沙灘半種苗。',48,'御定全唐詩/json/671.json','["三山江上寺，宮殿望岧嶢。石徑侵高樹，沙灘半種苗。", "一僧歸晚日，群鷺宿寒潮。遙聽風鈴語，興亡話六朝。"]'),
('yuding-53','望夫石','唐彥謙','唐','御定全唐诗','yuding','','[]','江上見危磯，人形立翠微。妾來終日望，夫去幾時歸。',48,'御定全唐詩/json/671.json','["江上見危磯，人形立翠微。妾來終日望，夫去幾時歸。", "明月空懸鏡，蒼苔漫補衣。可憐雙淚眼，千古斷斜暉。"]'),
('yuding-54','過湖口','唐彥謙','唐','御定全唐诗','yuding','','[]','江湖分兩路，此地是通津。雲淨山浮翠，風高浪潑銀。',48,'御定全唐詩/json/671.json','["江湖分兩路，此地是通津。雲淨山浮翠，風高浪潑銀。", "人行俱是客，舟住即為鄰。俯仰煙波內，蜉蝣寄此身。"]'),
('yuding-55','夜泊東溪有懷','唐彥謙','唐','御定全唐诗','yuding','','[]','水昏天色晚，崖下泊行舟。獨客傷歸雁，孤眠歎野鷗。',48,'御定全唐詩/json/671.json','["水昏天色晚，崖下泊行舟。獨客傷歸雁，孤眠歎野鷗。", "溪聲牽別恨，鄉夢惹離愁。酒醒推篷坐，淒涼望女牛。"]'),
('yuding-56','登廬山','唐彥謙','唐','御定全唐诗','yuding','','[]','五老峰巔望，天涯在目前。湘潭浮夜雨，巴蜀暝寒煙。',48,'御定全唐詩/json/671.json','["五老峰巔望，天涯在目前。湘潭浮夜雨，巴蜀暝寒煙。", "泰華根同峙，嵩衡脈共聯。憑虛有仙骨，日月看推遷。"]'),
('yuding-57','金陵九日','唐彥謙','唐','御定全唐诗','yuding','','[]','野菊西風滿路香，雨花臺上集壺觴。九重天近瞻鐘阜，',40,'御定全唐詩/json/671.json','["野菊西風滿路香，雨花臺上集壺觴。九重天近瞻鐘阜，", "清歌驚起南飛雁，散作秋聲送夕陽。"]'),
('yuding-58','遊清涼寺','唐彥謙','唐','御定全唐诗','yuding','','[]','白雲紅樹路紆縈，古殿長廊次第行。南望水連桃葉渡，',40,'御定全唐詩/json/671.json','["白雲紅樹路紆縈，古殿長廊次第行。南望水連桃葉渡，", "竹院逢僧舊曾識，旋披禪衲為相迎。"]'),
('yuding-59','高平九日','唐彥謙','唐','御定全唐诗','yuding','','[]','雲淨南山紫翠浮，憑陵絕頂望悠悠。偶逢佳節牽詩興，',40,'御定全唐詩/json/671.json','["雲淨南山紫翠浮，憑陵絕頂望悠悠。偶逢佳節牽詩興，", "烏紗頻岸西風裏，笑插黃花滿鬢秋。"]'),
('yuding-60','金陵懷古','唐彥謙','唐','御定全唐诗','yuding','','[]','碧樹涼生宿雨收，荷花荷葉滿汀洲。登高有酒渾忘醉，',40,'御定全唐詩/json/671.json','["碧樹涼生宿雨收，荷花荷葉滿汀洲。登高有酒渾忘醉，", "太平時節殊風景，山自青青水自流。"]'),
('yuding-61','道中逢故人','唐彥謙','唐','御定全唐诗','yuding','','[]','蘭陵市上忽相逢，敘別殷勤興倍濃。良會若同雞黍約，',40,'御定全唐詩/json/671.json','["蘭陵市上忽相逢，敘別殷勤興倍濃。良會若同雞黍約，", "行色一鞭催去馬，畫橋嘶斷落花風。"]'),
('yuding-62','早行遇雪','唐彥謙','唐','御定全唐诗','yuding','','[]','下馬天未明，風高雪何急。須臾路欲迷，頃刻山盡白。',60,'御定全唐詩/json/671.json','["下馬天未明，風高雪何急。須臾路欲迷，頃刻山盡白。", "雞犬寂無聲，曙光射寒色。荒村絕煙火，髯凍布袍濕。", "王事不可緩，行行動淒惻。"]'),
('yuding-63','樊登見寄四首','唐彥謙','唐','御定全唐诗','yuding','','[]','新辭翦秋水，洗我胸中塵。無由愜良會，極目空懷人。',144,'御定全唐詩/json/671.json','["新辭翦秋水，洗我胸中塵。無由愜良會，極目空懷人。", "醉來拔劍歌，字字皆陽春。", "輕黃著柳條，新春喜更始。感時重搔首，悵望不能已。", "無由托深情，傾瀉芳尊裏。", "明月入我室，天風吹我袍。良夜最岑寂，旅況何蕭條。", "馳情望海波，一鶴鳴九皋。", "悠悠括城北，眄眄岩泉西。宿草暝煙綠，苦竹含雲低。", "幽懷不可托，鷓鴣空自啼。"]'),
('yuding-64','春風四首','唐彥謙','唐','御定全唐诗','yuding','','[]','春風吹愁端，散漫不可收。不如古溪水，只望鄉江流。',96,'御定全唐詩/json/671.json','["春風吹愁端，散漫不可收。不如古溪水，只望鄉江流。", "新花紅爍爍，舊花滿山白。昔日金張門，狼藉餘廢宅。", "回頭語春風，莫向新花叢。我見朱顏人，多金亦成翁。", "多金不足惜，丹砂亦何益。更種明年花，春風自相識。"]'),
('yuding-65','感物二首','唐彥謙','唐','御定全唐诗','yuding','','[]','騄驥初失群，亦自矜趫騰。俯仰歲時久，帖然困蚊蠅。',144,'御定全唐詩/json/671.json','["騄驥初失群，亦自矜趫騰。俯仰歲時久，帖然困蚊蠅。", "豪鯨逸其穴，尺水成滄溟。豈無魚鱉交，望望為所憎。", "物理有翕張，達人同廢興。幸無怵迫憂，聊複曲吾肱。", "魚目出泥沙，空村百金珍。豫章值擁輳，細細供蒸薪。", "論材何必多，適用即能神。托交何必深，寡求永相親。", "鮑叔拙羈魯，張生窮厄陳。茫然扳援際，豈意出風塵。"]'),
('yuding-66','和陶淵明貧士詩七首','唐彥謙','唐','御定全唐诗','yuding','','[]','貧賤如故舊，少壯即相依。中心不敢厭，但覺少光輝。',504,'御定全唐詩/json/671.json','["貧賤如故舊，少壯即相依。中心不敢厭，但覺少光輝。", "向來乘時士，亦有能奮飛。一朝權勢歇，欲退無所歸。", "不如行其素，辛苦奈寒饑。人生系天運，何用發深悲。", "我居在窮巷，來往無華軒。辛勤衣食物，出此二畝園。", "薤菘郁朝露，桑柘浮春煙。以茲亂心曲，智計無他奸。", "擇勝不在奢，興至發清言。相逢樵牧徒，混混誰愚賢。", "松風四山來，清宵響瑤琴。聽之不能寐，中有怨歎音。", "旦起繞其樹，磈砢不計尋。清陰可敷席，有酒誰與斟。", "由來大度士，不受流俗侵。浩歌相倡答，慰此霜雪心。", "中年涉事熟，欲學唾面婁。逡巡避少年，赴穢不敢酬。", "旁人籲已甚，自喜計慮周。微勞消厚疚，殘辱勝深憂。", "從知為下安，處上反無儔。人生各有志，勇懦從所求。", "古人重畎畝，有祿不待幹。德成祿自至，釋耒列王官。", "不仕亦不貧，本自足饔餐。後世恥躬耕，號呼脫饑寒。", "我生千祀後，念此愧在顏。為農倘可飽，何用出柴關。", "村郊多父老，面垢頭如蓬。我嘗使之年，言語不待工。", "古來名節士，敢望彭城龔。有叟誚其後，更恨道不通。", "鄙哉譊譊者，為隘不為通。低頭拜野老，負米吾願從。", "去年秋事荒，販糴仰鄰州。健者道路間，什百成朋儔。", "今年漸向熟，庶幾民不流。書生自無田，與眾同喜憂。", "作詩勞鄰曲，有倡誰與酬。亦無采詩者，此修何可修。"]'),
('yuding-67','舟中望紫岩','唐彥謙','唐','御定全唐诗','yuding','','[]','近山如畫牆，遠山如帚長。我從雲中來，回頭白茫茫。',96,'御定全唐詩/json/671.json','["近山如畫牆，遠山如帚長。我從雲中來，回頭白茫茫。", "惜去乃爾覺，常時自相忘。相忘豈不佳，遣此懷春傷。", "飄灑從何來，衣巾濕微涼。初疑風雨集，冉冉游塵黃。", "無歸亦自可，信美非吾鄉。登舟望東雲，猶向帆端翔。"]'),
('yuding-68','九日遊中溪','唐彥謙','唐','御定全唐诗','yuding','','[]','悠悠循澗行，磊磊據石坐。林垂短長雲，山綴丹碧顆。',84,'御定全唐詩/json/671.json','["悠悠循澗行，磊磊據石坐。林垂短長雲，山綴丹碧顆。", "蓼花最無數，照水嬌婀娜。何知是節序，風日自清妥。", "群童競時新，萬果間蔬蓏。欣然為之醉，烏帽危不墮。", "此日山中懷，孟公不如我。"]'),
('yuding-69','六月十三日上陳微博士','唐彥謙','唐','御定全唐诗','yuding','','[]','驕雲飛散雨，隨風為有無。老農終歲心，望施在須臾。',144,'御定全唐詩/json/671.json','["驕雲飛散雨，隨風為有無。老農終歲心，望施在須臾。", "平生官田粟，長此禮義軀。置之且勿戚，一飽任妻孥。", "青青澤中蒲，九夏氣淒寒。翾翾翠碧羽，照影蒼溪間。", "巢由薄天下，俗士榮一官。小大各有適，自全良獨難。", "窮居無公憂，私此長夏日。蚊蠅如俗子，正爾相妒嫉。", "麾驅非吾任，遁避亦無術。惟當俟其定，靜坐萬慮一。"]'),
('yuding-70','宿田家','唐彥謙','唐','御定全唐诗','yuding','','[]','落日下遙峰，荒村倦行履。停車息茅店，安寢正鼾睡。',156,'御定全唐詩/json/671.json','["落日下遙峰，荒村倦行履。停車息茅店，安寢正鼾睡。", "忽聞扣門急，雲是下鄉隸。公文捧花柙，鷹隼駕聲勢。", "良民懼官府，聽之肝膽碎。阿母出搪塞，老腳走顛躓。", "小心事延款，□餘糧複匱。東鄰借種雞，西舍覓芳醑。", "再飯不厭飽，一飲直呼醉。明朝怯見官，苦苦燈前跪。", "使我不成眠，為渠滴清淚。民膏日已瘠，民力日愈弊。", "空懷伊尹心，何補堯舜治。"]'),
('yuding-71','夏日訪友','唐彥謙','唐','御定全唐诗','yuding','','[]','堤樹生晝涼，濃陰撲空翠。孤舟喚野渡，村疃入幽邃。',168,'御定全唐詩/json/671.json','["堤樹生晝涼，濃陰撲空翠。孤舟喚野渡，村疃入幽邃。", "高軒俯清流，一犬隔花吠。童子立門牆，問我向何處。", "主人聞故舊，出迎時倒屣。驚迓敘間闊，屈指越寒暑。", "殷勤為延款，偶爾得良會。春盤擘紫蝦，冰鯉斫銀鱠。", "荷梗白玉香，荇菜青絲脆。臘酒擊泥封，羅列總新味。", "移席臨湖濱，對此有佳趣。流連送深杯，賓主共忘醉。", "清風岸烏紗，長揖謝君去。世事如浮雲，東西渺煙水。"]'),
('yuding-72','遊南明山','唐彥謙','唐','御定全唐诗','yuding','','[]','久聞南明山，共慕南明寺。幾度欲登臨，日逐擾人事。',264,'御定全唐詩/json/671.json','["久聞南明山，共慕南明寺。幾度欲登臨，日逐擾人事。", "於焉偶閒暇，鳴轡忽相聚。乘興樂遨遊，聊此托佳趣。", "涉水渡溪南，迢遙翠微裏。石磴千疊斜，峭壁半空起。", "白雲鎖峰腰，紅葉暗溪嘴。長藤絡虛岩，疏花映寒水。", "金銀拱梵刹，丹青照廊宇。石樑臥秋溟，風鈴作簷語。", "深洞結苔陰，嵐氣滴晴雨。羊腸轉咫尺，鳥道轉千里。", "屈曲到禪房，上人喜延佇。香分宿火熏，茶汲清泉煮。", "投閑息萬機，三生有宿契。行廚出盤飧，擔甕倒芳醑。", "脫冠掛長松，白石藉憑倚。宦途勞營營，暫此滌塵慮。", "鬮令促傳觴，投壺更聯句。興來較勝負，醉後忘爾汝。", "忽聞吼蒲牢，落日下雲嶼。長嘯出煙蘿，揚鞭賦歸去。"]'),
('yuding-73','索蝦','唐彥謙','唐','御定全唐诗','yuding','','[]','姑孰多紫蝦，獨有湖陽優。出產在四時，極美宜於秋。',157,'御定全唐詩/json/671.json','["姑孰多紫蝦，獨有湖陽優。出產在四時，極美宜於秋。", "雙箝鼓繁須，當頂抽長矛。鞠躬見湯王，封作朱衣侯。", "所以供盤餐，羅列同珍羞。蒜友日相親，瓜朋時與儔。", "既名釣詩釣，又作鉤詩鉤。于時同相訪，數日承款留。", "厭飲多美味，獨此心相投。別來歲雲久，馳想空悠悠。", "銜杯動遐思，uT口涎空流。封緘托雙鯉，於焉來遠求。", "慷慨胡隱君，果肯分惠否。"]'),
('yuding-74','采桑女','唐彥謙','唐','御定全唐诗','yuding','','[]','春風吹蠶細如蟻，桑芽才努青鴉嘴。侵晨探采誰家女，',40,'御定全唐詩/json/671.json','["春風吹蠶細如蟻，桑芽才努青鴉嘴。侵晨探采誰家女，", "愁聽門外催裏胥，官家二月收新絲。"]'),
('yuding-75','送許戶曹','唐彥謙','唐','御定全唐诗','yuding','','[]','沙頭小燕鳴春和，楊柳垂絲煙倒拖。將軍樓船發浩歌，',40,'御定全唐詩/json/671.json','["沙頭小燕鳴春和，楊柳垂絲煙倒拖。將軍樓船發浩歌，", "神鼇駕粟升天河，新承雨澤浮恩波。"]'),
('yuding-76','詠葡萄','唐彥謙','唐','御定全唐诗','yuding','','[]','西園晚霽浮嫩涼，開尊漫摘葡萄嘗。滿架高撐紫絡索，',72,'御定全唐詩/json/671.json','["西園晚霽浮嫩涼，開尊漫摘葡萄嘗。滿架高撐紫絡索，", "神蛟清夜蟄寒潭，萬片濕雲飛不起。石家美人金谷游，", "勝遊記得當年景，清氣逼人毛骨冷。笑呼明鏡上遙天，"]'),
('yuding-77','蟹','唐彥謙','唐','御定全唐诗','yuding','','[]','湖田十月清霜墮，晚稻初香蟹如虎。扳罾拖網取賽多，',96,'御定全唐詩/json/671.json','["湖田十月清霜墮，晚稻初香蟹如虎。扳罾拖網取賽多，", "蟛蜞石蟹已曾食，使我一見驚非常。買之最厭黃髯老，", "充盤煮熟堆琳琅，橙膏醬渫調堪嘗。一鬥擘開紅玉滿，", "西風張翰苦思鱸，如斯豐味能知否？物之可愛尤可憎，"]'),
('yuding-78','敘別','唐彥謙','唐','御定全唐诗','yuding','','[]','譙樓夜促蓮花漏，樹陰搖月蛟螭走。蟠拏對月吸深杯，',48,'御定全唐詩/json/671.json','["譙樓夜促蓮花漏，樹陰搖月蛟螭走。蟠拏對月吸深杯，", "十載番思舊時事，好懷不似當年狂。夜合花香開小院，"]'),
('yuding-0','緋桃','唐彥謙','唐','御定全唐诗','yuding','','[]','短牆荒圃四無鄰，烈火緋桃照地春。坐久好風休掩袂，',40,'御定全唐詩/json/672.json','["短牆荒圃四無鄰，烈火緋桃照地春。坐久好風休掩袂，", "盡日更無鄉井念，此時何必見秦人。"]'),
('yuding-1','小院','唐彥謙','唐','御定全唐诗','yuding','','[]','小院無人夜，煙斜月轉明。清宵易惆悵，不必有離情。',24,'御定全唐詩/json/672.json','["小院無人夜，煙斜月轉明。清宵易惆悵，不必有離情。"]'),
('yuding-2','春雪初霽杏花正芳月上夜吟','唐彥謙','唐','御定全唐诗','yuding','','[]','霽景明如練，繁英杏正芳。姮娥應有語，悔共雪爭光。',24,'御定全唐詩/json/672.json','["霽景明如練，繁英杏正芳。姮娥應有語，悔共雪爭光。"]'),
('yuding-3','文惠宮人','唐彥謙','唐','御定全唐诗','yuding','','[]','認得前家令，宮人淚滿裾。不知梁佐命，全是沈尚書。',24,'御定全唐詩/json/672.json','["認得前家令，宮人淚滿裾。不知梁佐命，全是沈尚書。"]'),
('yuding-4','贈竇尊師','唐彥謙','唐','御定全唐诗','yuding','','[]','我愛竇高士，棄官仍在家。為嫌句漏令，兼不要丹砂。',24,'御定全唐詩/json/672.json','["我愛竇高士，棄官仍在家。為嫌句漏令，兼不要丹砂。"]'),
('yuding-5','穆天子傳','唐彥謙','唐','御定全唐诗','yuding','','[]','王母清歌玉管悲，瑤台應有再來期。',32,'御定全唐詩/json/672.json','["王母清歌玉管悲，瑤台應有再來期。", "穆王不得重相見，恐為無端哭盛姬。"]'),
('yuding-6','楚天','唐彥謙','唐','御定全唐诗','yuding','','[]','楚天遙望每長嚬，宋玉襄王盡作塵。',32,'御定全唐詩/json/672.json','["楚天遙望每長嚬，宋玉襄王盡作塵。", "不會瑤姬朝與暮，更為雲雨待何人。"]'),
('yuding-7','寄徐山人','唐彥謙','唐','御定全唐诗','yuding','','[]','一室清羸鶴體孤，氣和神瑩爽冰壺。',32,'御定全唐詩/json/672.json','["一室清羸鶴體孤，氣和神瑩爽冰壺。", "吳中高士雖求死，不那稽山有謝敷。"]'),
('yuding-8','題宗人故帖','唐彥謙','唐','御定全唐诗','yuding','','[]','所忠無處訪相如，風笈塵編跡尚餘。',32,'御定全唐詩/json/672.json','["所忠無處訪相如，風笈塵編跡尚餘。", "惟有孝標情最厚，一編遺在茂陵書。"]'),
('yuding-9','垂柳','唐彥謙','唐','御定全唐诗','yuding','','[]','絆惹春風別有情，世間誰敢鬥輕盈。',32,'御定全唐詩/json/672.json','["絆惹春風別有情，世間誰敢鬥輕盈。", "楚王江畔無端種，餓損纖腰學不成。"]'),
('yuding-10','登興元城觀烽火','唐彥謙','唐','御定全唐诗','yuding','','[]','漢川城上角三呼，扈蹕防邊列萬夫。',32,'御定全唐詩/json/672.json','["漢川城上角三呼，扈蹕防邊列萬夫。", "褒姒塚前烽火起，不知泉下破顏無。"]'),
('yuding-11','鄧艾廟','唐彥謙','唐','御定全唐诗','yuding','','[]','昭烈遺黎死尚羞，揮刀斫石恨譙周。',32,'御定全唐詩/json/672.json','["昭烈遺黎死尚羞，揮刀斫石恨譙周。", "如何千載留遺廟，血食巴山伴武侯。"]'),
('yuding-12','曲江春望','唐彥謙','唐','御定全唐诗','yuding','','[]','杏豔桃光奪晚霞，樂遊無廟有年華。',32,'御定全唐詩/json/672.json','["杏豔桃光奪晚霞，樂遊無廟有年華。", "漢朝冠蓋皆陵墓，十裏宜春漢苑花。"]'),
('yuding-13','漢殿','唐彥謙','唐','御定全唐诗','yuding','','[]','鳥去雲飛意不通，夜壇斜月轉松風。',32,'御定全唐詩/json/672.json','["鳥去雲飛意不通，夜壇斜月轉松風。", "君王寂慮無消息，卻就閒人覓巨公。"]'),
('yuding-14','賀李昌時禁苑新命','唐彥謙','唐','御定全唐诗','yuding','','[]','振鷺翔鸞集禁闈，玉堂珠樹瑩風儀。',32,'御定全唐詩/json/672.json','["振鷺翔鸞集禁闈，玉堂珠樹瑩風儀。", "不知新到靈和殿，張緒何如柳一枝。"]'),
('yuding-15','牡丹','唐彥謙','唐','御定全唐诗','yuding','','[]','顏色無因饒錦繡，馨香惟解掩蘭蓀。',32,'御定全唐詩/json/672.json','["顏色無因饒錦繡，馨香惟解掩蘭蓀。", "那堪更被煙蒙蔽，南國西施泣斷魂。"]'),
('yuding-16','羅江驛','唐彥謙','唐','御定全唐诗','yuding','','[]','數枝高柳帶鳴鴉，一樹山榴自落花。',32,'御定全唐詩/json/672.json','["數枝高柳帶鳴鴉，一樹山榴自落花。", "已是向來多淚眼，短亭回首在天涯。"]'),
('yuding-17','奏捷西蜀題沱江驛','唐彥謙','唐','御定全唐诗','yuding','','[]','野客乘軺非所宜，況將儒懦報戎機。',32,'御定全唐詩/json/672.json','["野客乘軺非所宜，況將儒懦報戎機。", "錦江不識臨邛酒，且免相如渴病歸。"]'),
('yuding-18','春早落英','唐彥謙','唐','御定全唐诗','yuding','','[]','紛紛從此見花殘，轉覺長繩系日難。',32,'御定全唐詩/json/672.json','["紛紛從此見花殘，轉覺長繩系日難。", "樓上有愁春不淺，小桃風雪憑闌幹。"]'),
('yuding-19','仲山','唐彥謙','唐','御定全唐诗','yuding','','[]','千載遺蹤寄薜蘿，沛中鄉里舊山河。',32,'御定全唐詩/json/672.json','["千載遺蹤寄薜蘿，沛中鄉里舊山河。", "長陵亦是閑丘隴，異日誰知與仲多。"]'),
('yuding-20','漢嗣','唐彥謙','唐','御定全唐诗','yuding','','[]','漢嗣安危係數君，高皇決意勢難分。',32,'御定全唐詩/json/672.json','["漢嗣安危係數君，高皇決意勢難分。", "張良口辨周昌吃，同建儲宮第一勳。"]'),
('yuding-21','四老廟','唐彥謙','唐','御定全唐诗','yuding','','[]','西漢儲宮定不傾，可能園綺勝良平。',32,'御定全唐詩/json/672.json','["西漢儲宮定不傾，可能園綺勝良平。", "舉朝公將無全策，借請閒人羽翼成。"]'),
('yuding-22','南梁戲題漢高廟','唐彥謙','唐','御定全唐诗','yuding','','[]','數載從軍似武夫，今隨戎捷氣偏粗。',32,'御定全唐詩/json/672.json','["數載從軍似武夫，今隨戎捷氣偏粗。", "漢皇若問何為者，免道高陽舊酒徒。"]'),
('yuding-23','洛神','唐彥謙','唐','御定全唐诗','yuding','','[]','人世仙家本自殊，何須相見向中途。',32,'御定全唐詩/json/672.json','["人世仙家本自殊，何須相見向中途。", "驚鴻瞥過游龍去，漫惱陳王一事無。"]'),
('yuding-24','初秋到慈州冬首換絳牧','唐彥謙','唐','御定全唐诗','yuding','','[]','秋杪方攀玉樹枝，來年無計待春暉。',32,'御定全唐詩/json/672.json','["秋杪方攀玉樹枝，來年無計待春暉。", "自嫌暫作仙城守，不逐鶯來共燕飛。"]'),
('yuding-25','重經馮家舊裏','唐彥謙','唐','御定全唐诗','yuding','','[]','馮家舊宅閉柴關，修竹猶存潏水灣。',32,'御定全唐詩/json/672.json','["馮家舊宅閉柴關，修竹猶存潏水灣。", "應系星辰天上去，不留英骨葬人間。"]'),
('yuding-26','克復後登安國寺閣','唐彥謙','唐','御定全唐诗','yuding','','[]','千門萬戶鞠蒿藜，斷燼遺垣一望迷。',32,'御定全唐詩/json/672.json','["千門萬戶鞠蒿藜，斷燼遺垣一望迷。", "惆悵建章鴛瓦盡，夜來空見玉繩低。"]'),
('yuding-27','題虔僧室','唐彥謙','唐','御定全唐诗','yuding','','[]','何緣春恨貯離憂，欲入空門萬事休。',32,'御定全唐詩/json/672.json','["何緣春恨貯離憂，欲入空門萬事休。", "水月定中何所謂，也嚬眉黛托腮愁。"]'),
('yuding-28','見煬帝寶帳','唐彥謙','唐','御定全唐诗','yuding','','[]','漢文窮相作前王，慳惜明珠不鬥量。',32,'御定全唐詩/json/672.json','["漢文窮相作前王，慳惜明珠不鬥量。", "翡翠鮫鮹何所直，千裨萬接上書囊。"]'),
('yuding-29','樓上偶題','唐彥謙','唐','御定全唐诗','yuding','','[]','塵土無因狎隱淪，青山一望每傷神。',32,'御定全唐詩/json/672.json','["塵土無因狎隱淪，青山一望每傷神。", "可能前嶺空喬木，應有懷才抱器人。"]'),
('yuding-30','親仁裏聞猿','唐彥謙','唐','御定全唐诗','yuding','','[]','朱雀街東半夜驚，楚魂湘夢兩徒清。',32,'御定全唐詩/json/672.json','["朱雀街東半夜驚，楚魂湘夢兩徒清。", "五更撩亂趨朝火，滿口塵埃亦數聲。"]'),
('yuding-31','聞李瀆司勳下世','唐彥謙','唐','御定全唐诗','yuding','','[]','異鄉丹旐已飄揚，一顧深知實未亡。',32,'御定全唐詩/json/672.json','["異鄉丹旐已飄揚，一顧深知實未亡。", "任被褚裒泉下笑，重將北面哭真長。"]'),
('yuding-32','試夜題省廊桂','唐彥謙','唐','御定全唐诗','yuding','','[]','麻衣穿穴兩京塵，十見東堂綠桂春。',32,'御定全唐詩/json/672.json','["麻衣穿穴兩京塵，十見東堂綠桂春。", "今日競飛楊葉箭，魏舒休作畫籌人。"]'),
('yuding-33','竹風','唐彥謙','唐','御定全唐诗','yuding','','[]','竹映風窗數陣斜，旅人愁坐思無涯。',32,'御定全唐詩/json/672.json','["竹映風窗數陣斜，旅人愁坐思無涯。", "夜來留得江湖夢，全為幹聲似荻花。"]'),
('yuding-34','長溪秋望','唐彥謙','唐','御定全唐诗','yuding','','[]','柳短莎長溪水流，雨微煙暝立溪頭。',32,'御定全唐詩/json/672.json','["柳短莎長溪水流，雨微煙暝立溪頭。", "寒鴉閃閃前山去，杜曲黃昏獨自愁。"]'),
('yuding-35','嚴子陵','唐彥謙','唐','御定全唐诗','yuding','','[]','嚴陵情性是真狂，抵觸三公傲帝王。',32,'御定全唐詩/json/672.json','["嚴陵情性是真狂，抵觸三公傲帝王。", "不怕舊交嗔僭越，喚他侯霸作君房。"]'),
('yuding-36','北齊','唐彥謙','唐','御定全唐诗','yuding','','[]','草草招提強據鞍，周師乘勝莫回看。',32,'御定全唐詩/json/672.json','["草草招提強據鞍，周師乘勝莫回看。", "背城肯戰知虛實，爭奈人前忍笑難。"]'),
('yuding-37','楚世家','唐彥謙','唐','御定全唐诗','yuding','','[]','偏信由來惑是非，一言邪佞脫危機。',32,'御定全唐詩/json/672.json','["偏信由來惑是非，一言邪佞脫危機。", "張儀重入懷王手，駟馬安車卻放歸。"]'),
('yuding-38','驪山道中','唐彥謙','唐','御定全唐诗','yuding','','[]','月殿真妃下彩煙，漁陽追虜及湯泉。',32,'御定全唐詩/json/672.json','["月殿真妃下彩煙，漁陽追虜及湯泉。", "君王指點新豐樹，幾不親留七寶鞭。"]'),
('yuding-39','韋曲','唐彥謙','唐','御定全唐诗','yuding','','[]','欲寫愁腸愧不才，多情練漉已低摧。',32,'御定全唐詩/json/672.json','["欲寫愁腸愧不才，多情練漉已低摧。", "窮郊二月初離別，獨傍寒村嗅野梅。"]'),
('yuding-40','黃子陂荷花','唐彥謙','唐','御定全唐诗','yuding','','[]','十頃狂風撼曲塵，緣堤照水露紅新。',32,'御定全唐詩/json/672.json','["十頃狂風撼曲塵，緣堤照水露紅新。", "世間花氣皆愁絕，恰是蓮香更惱人。"]'),
('yuding-41','野行','唐彥謙','唐','御定全唐诗','yuding','','[]','蝶戀晚花終不去，鷗逢春水固難飛。',32,'御定全唐詩/json/672.json','["蝶戀晚花終不去，鷗逢春水固難飛。", "野人心地都無著，伴蝶隨鷗亦不歸。"]'),
('yuding-42','興元沈氏莊','唐彥謙','唐','御定全唐诗','yuding','','[]','清淺縈紆一水間，竹岡藤樹小躋攀。露沾荒草行人過，',40,'御定全唐詩/json/672.json','["清淺縈紆一水間，竹岡藤樹小躋攀。露沾荒草行人過，", "異鄉一笑因酣醉，忘卻愁來鬢髮斑。"]'),
('yuding-43','亂後經表兄瓊華觀舊居','唐彥謙','唐','御定全唐诗','yuding','','[]','一去仙居似轉蓬，再經花謝倚春叢。醉中篇什金聲在，',40,'御定全唐詩/json/672.json','["一去仙居似轉蓬，再經花謝倚春叢。醉中篇什金聲在，", "東風狼藉苔侵徑，蕙草香銷杏帶紅。"]'),
('yuding-44','秋霽夜吟寄友人','唐彥謙','唐','御定全唐诗','yuding','','[]','槐柳蕭疏溽暑收，金商頻伏火西流。塵衣歲晚緣身賤，',40,'御定全唐詩/json/672.json','["槐柳蕭疏溽暑收，金商頻伏火西流。塵衣歲晚緣身賤，", "惟思待月高梧下，更就東床訪惠休。"]'),
('yuding-45','賀李昌時禁苑新命','唐彥謙','唐','御定全唐诗','yuding','','[]','玉簡金文直上清，禁垣丹地閉嚴扃。黃扉議政參元化，',40,'御定全唐詩/json/672.json','["玉簡金文直上清，禁垣丹地閉嚴扃。黃扉議政參元化，", "塵中舊侶無音信，知道遼東鶴姓丁。"]'),
('yuding-46','寄蔣二十四','唐彥謙','唐','御定全唐诗','yuding','','[]','鳥囀蜂飛日漸長，旅人情味悔思量。禪門澹薄無心地，',40,'御定全唐詩/json/672.json','["鳥囀蜂飛日漸長，旅人情味悔思量。禪門澹薄無心地，", "大知高士禁愁寂，試倚闌幹莫斷腸。"]'),
('yuding-47','寄懷','唐彥謙','唐','御定全唐诗','yuding','','[]','有客傷春複怨離，夕陽亭畔草青時。淚從紅蠟無由制，',40,'御定全唐詩/json/672.json','["有客傷春複怨離，夕陽亭畔草青時。淚從紅蠟無由制，", "雙溪未去饒歸夢，夜夜孤眠枕獨欹。"]'),
('yuding-48','送樊管司業歸朝','唐彥謙','唐','御定全唐诗','yuding','','[]','近者蘇司業，文雄道最光。夫君居太學，妙譽繼中行。',264,'御定全唐詩/json/672.json','["近者蘇司業，文雄道最光。夫君居太學，妙譽繼中行。", "汲郡陵初發，汾陰篋久亡。寂寥方倚席，容易忽升堂。", "去日應懸榻，來時定裂裳。愜心頻拾芥，應手屢穿楊。", "辯急如無敵，飛騰固自強。論心期舌在，問事畏頭長。", "駟馬終題柱，諸生悉面牆。啖螯譏爾雅，賣餅訴公羊。", "未見泥函穀，俄驚火建章。煙塵昏象魏，行在隔巴梁。", "紅粟填郿塢，青袍過壽陽。翦茅行殿濕，伐柏舊陵香。", "黌室青衿盡，渠門火旆揚。雲飛同去國，星散各殊方。", "賤子悲窮轍，當年亦擅場。齏辛尋幼婦，醴酒憶先王。", "聖域探姬孔，皇風樂禹湯。畏誅輕李喜，言命小臧倉。", "折樹休盤槊，沈鉤且釣璜。鴻都問詞客，他日莫相忘。"]'),
('yuding-49','奉使岐下聞唐弘夫行軍為賊所擒，傷而有作','唐彥謙','唐','御定全唐诗','yuding','','[]','報國捐軀實壯夫，楚囚垂欲複神都。雲台畫像皆何者，',40,'御定全唐詩/json/672.json','["報國捐軀實壯夫，楚囚垂欲複神都。雲台畫像皆何者，", "聞君敗績無歸計，氣激星辰坐向隅。"]'),
('yuding-50','咸通中始聞褚河南歸葬陽翟是歲上平徐方大肆慶賞又詔八品錫其裔孫追敘風概因成二十韻','唐彥謙','唐','御定全唐诗','yuding','','[]','冊府藏餘烈，皇綱正本朝。不聽還笏諫，幾覆綴旒祧。',240,'御定全唐詩/json/672.json','["冊府藏餘烈，皇綱正本朝。不聽還笏諫，幾覆綴旒祧。", "咫尺言終直，愴惶道已消。淚心傳位日，揮涕授遺朝。", "飛燕潛來趙，黃龍豈見譙。既迷秦帝鹿，難問賈生雕。", "穆卜緘縢秘，金根轍跡遙。北軍那奪印，東海漫難橋。", "羅織黃門訟，笙簧白骨銷。炎方無信息，丹旐竟淪漂。", "邂逅江魚食，淒涼楚客招。文忠徒諡議，子卯但簫韶。", "未見公侯複，尋傷嗣續凋。流年隨水逝，高誼薄層霄。", "柱石林公遠，縑緗故國饒。奇蹤天驥活，遺軸錦鸞翹。", "近者淮夷戮，前年歸馬調。始聞移北葬，兼議蔭山苗。", "聖澤覃將溥，貞魂喜定飄。異時窮巷客，懷古漫成謠。"]'),
('yuding-51','岐王宅','唐彥謙','唐','御定全唐诗','yuding','','[]','朱邸平臺隔禁闈，貴游陳跡尚依稀。雲低雍畤祈年去，',40,'御定全唐詩/json/672.json','["朱邸平臺隔禁闈，貴游陳跡尚依稀。雲低雍畤祈年去，", "承平舊物惟君盡，猶寫雕鞍伴六飛。"]'),
('yuding-52','東韋曲野思','唐彥謙','唐','御定全唐诗','yuding','','[]','淡霧輕雲匝四垂，綠塘秋望獨顰眉。野蓮隨水無人見，',40,'御定全唐詩/json/672.json','["淡霧輕雲匝四垂，綠塘秋望獨顰眉。野蓮隨水無人見，", "孤燈夜夜愁欹枕，一覺滄洲似昔時。"]'),
('yuding-53','上巳','唐彥謙','唐','御定全唐诗','yuding','','[]','上巳接寒食，鶯花寥落晨。微微潑火雨，草草踏青人。',48,'御定全唐詩/json/672.json','["上巳接寒食，鶯花寥落晨。微微潑火雨，草草踏青人。", "涼似三秋景，清無九陌塵。與餘同病者，對此合傷神。"]'),
('yuding-54','移莎','唐彥謙','唐','御定全唐诗','yuding','','[]','移從杜城曲，置在小齋東。正是高秋裏，仍兼細雨中。',96,'御定全唐詩/json/672.json','["移從杜城曲，置在小齋東。正是高秋裏，仍兼細雨中。", "結根方迸竹，疏蔭托高桐。苒苒齊芳草，飄飄笑斷蓬。", "片時留靜者，一夜響鳴蛩。野露通宵滴，溪煙盡日蒙。", "試才卑庾薤，求味笑周菘。只此霜栽好，他時贈伯翁。"]'),
('yuding-55','西明寺威公盆池新稻','唐彥謙','唐','御定全唐诗','yuding','','[]','為笑江南種稻時，露蟬鳴後雨霏霏。蓮盆積潤分畦小，',40,'御定全唐詩/json/672.json','["為笑江南種稻時，露蟬鳴後雨霏霏。蓮盆積潤分畦小，", "支公尚有三吳思，更使幽人憶釣磯。"]'),
('yuding-56','紅葉','唐彥謙','唐','御定全唐诗','yuding','','[]','無處不飄揚，高樓臨道旁。素娥前夕月，青女夜來霜。',168,'御定全唐詩/json/672.json','["無處不飄揚，高樓臨道旁。素娥前夕月，青女夜來霜。", "宿雨隨時潤，秋晴著物光。幽懷長若此，病眼更相妨。", "蜀紙裁深色，燕脂落靚妝。低叢侵小閣，倒影入回塘。", "謝脁留霞綺，甘甯棄錦張。何人休遠道，是處有斜陽。", "薜荔垂書幌，梧桐墜井床。晚風生旅館，寒籟近僧房。", "桂綠明淮甸，楓丹照楚鄉。雁疏臨鄠杜，蟬急傍瀟湘。", "樹異桓宣武，園非顧辟疆。茂陵愁臥客，不自保危腸。"]'),
('yuding-57','鸂鶒','唐彥謙','唐','御定全唐诗','yuding','','[]','一宿南塘煙雨時，好風搖動綠波微。驚離曉岸沖花去，',40,'御定全唐詩/json/672.json','["一宿南塘煙雨時，好風搖動綠波微。驚離曉岸沖花去，", "畫屏見後長回首，爭得雕籠莫放歸。"]'),
('yuding-58','螢','唐彥謙','唐','御定全唐诗','yuding','','[]','日下蕪城莽蒼中，濕螢撩亂起衰叢。寒煙陳後長門閉，',40,'御定全唐詩/json/672.json','["日下蕪城莽蒼中，濕螢撩亂起衰叢。寒煙陳後長門閉，", "羈人此夕方愁緒，心似寒灰首似蓬。"]'),
('yuding-59','夜蟬','唐彥謙','唐','御定全唐诗','yuding','','[]','翠竹高梧夾後溪，勁風危露雨淒淒。那知北牖殘燈暗，',40,'御定全唐詩/json/672.json','["翠竹高梧夾後溪，勁風危露雨淒淒。那知北牖殘燈暗，", "羈人此夕如三歲，不整寒衾待曙雞。"]'),
('yuding-60','七夕','唐彥謙','唐','御定全唐诗','yuding','','[]','露白風清夜向晨，小星垂佩月埋輪。絳河浪淺休相隔，',40,'御定全唐詩/json/672.json','["露白風清夜向晨，小星垂佩月埋輪。絳河浪淺休相隔，", "倚闌殿北斜樓上，多少通宵不寐人。"]'),
('yuding-61','中秋夜玩月','唐彥謙','唐','御定全唐诗','yuding','','[]','一夜高樓萬景奇，碧天無際水無涯。只留皎月當層漢，',40,'御定全唐詩/json/672.json','["一夜高樓萬景奇，碧天無際水無涯。只留皎月當層漢，", "坐來離思憂將曉，爭得嫦娥仔細知。"]'),
('yuding-62','八月十六日夜月','唐彥謙','唐','御定全唐诗','yuding','','[]','斷腸佳賞固難期，昨夜銷魂更不疑。丹桂影空蟾有露，',40,'御定全唐詩/json/672.json','["斷腸佳賞固難期，昨夜銷魂更不疑。丹桂影空蟾有露，", "堪恨賈生曾慟哭，不緣清景為憂時。"]'),
('yuding-63','送韋向之睦州謁使君','唐彥謙','唐','御定全唐诗','yuding','','[]','才子南游多遠情，閑舟蕩漾任春行。',32,'御定全唐詩/json/672.json','["才子南游多遠情，閑舟蕩漾任春行。", "新安江上長如此，何似新安太守清。"]'),
('yuding-64','春殘','唐彥謙','唐','御定全唐诗','yuding','','[]','景為春時短，愁隨別夜長。暫棋寧號隱，輕醉不成鄉。',48,'御定全唐詩/json/672.json','["景為春時短，愁隨別夜長。暫棋寧號隱，輕醉不成鄉。", "風雨曾通夕，莓苔有眾芳。落花如便去，樓上即河梁。"]'),
('yuding-65','玫瑰','唐彥謙','唐','御定全唐诗','yuding','','[]','麝炷騰清燎，鮫紗覆綠蒙。宮妝臨曉日，錦段落東風。',48,'御定全唐詩/json/672.json','["麝炷騰清燎，鮫紗覆綠蒙。宮妝臨曉日，錦段落東風。", "無力春煙裏，多愁暮雨中。不知何事意，深淺兩般紅。"]'),
('yuding-66','牡丹','唐彥謙','唐','御定全唐诗','yuding','','[]','真宰多情巧思新，固將能事送殘春。為雲為雨徒虛語，',40,'御定全唐詩/json/672.json','["真宰多情巧思新，固將能事送殘春。為雲為雨徒虛語，", "嫦娥婺女曾相送，留下鴉黃作蕊塵。"]'),
('yuding-67','秋晚高樓','唐彥謙','唐','御定全唐诗','yuding','','[]','松拂疏窗竹映闌，素琴幽怨不成彈。清宵霽極雲離岫，',40,'御定全唐詩/json/672.json','["松拂疏窗竹映闌，素琴幽怨不成彈。清宵霽極雲離岫，", "高樓瞪目歸鴻遠，如信嵇康欲畫難。"]'),
('yuding-68','離鸞','唐彥謙','唐','御定全唐诗','yuding','','[]','聞道離鸞思故鄉，也知情願嫁王昌。塵埃一別楊朱路，',40,'御定全唐詩/json/672.json','["聞道離鸞思故鄉，也知情願嫁王昌。塵埃一別楊朱路，", "庭前佳樹名梔子，試結同心寄謝娘。"]'),
('yuding-69','柳','唐彥謙','唐','御定全唐诗','yuding','','[]','春思春愁一萬枝，遠村遙岸寄相思。西園有雨和苔長，',40,'御定全唐詩/json/672.json','["春思春愁一萬枝，遠村遙岸寄相思。西園有雨和苔長，", "晚來飛絮如霜鬢，恐為多情管別離。"]'),
('yuding-70','春陰','唐彥謙','唐','御定全唐诗','yuding','','[]','一寸回腸百慮侵，旅愁危涕兩爭禁。天涯已有銷魂別，',40,'御定全唐詩/json/672.json','["一寸回腸百慮侵，旅愁危涕兩爭禁。天涯已有銷魂別，", "春雲更覺愁於我，閑蓋低村作暝陰。"]'),
('yuding-71','春深獨行馬上有作','唐彥謙','唐','御定全唐诗','yuding','','[]','日烈風高野草香，百花狼藉柳披猖。連天瑞靄千門遠，',40,'御定全唐詩/json/672.json','["日烈風高野草香，百花狼藉柳披猖。連天瑞靄千門遠，", "年來與問閒遊者，若個傷春向路旁。"]'),
('yuding-72','春雨','唐彥謙','唐','御定全唐诗','yuding','','[]','綺陌夜來雨，春樓寒望迷。遠容迎燕戲，亂響隔鶯啼。',120,'御定全唐詩/json/672.json','["綺陌夜來雨，春樓寒望迷。遠容迎燕戲，亂響隔鶯啼。", "有恨開蘭室，無言對李蹊。花欹渾拂檻，柳重欲垂堤。", "燈檠昏魚目，熏爐咽麝臍。別輕天北鶴，夢怯汝南雞。", "入戶侵羅幌，捎簷潤繡題。新豐樹已失，長信草初齊。", "亂蝶寒猶舞，驚烏暝不棲。庾郎盤馬地，卻怕有春泥。"]'),
('yuding-73','漢代','唐彥謙','唐','御定全唐诗','yuding','','[]','漢代金為屋，吳宮綺作寮。豔詞傳靜婉，新曲定妖嬈。',240,'御定全唐詩/json/672.json','["漢代金為屋，吳宮綺作寮。豔詞傳靜婉，新曲定妖嬈。", "箭響猶殘夢，簽聲報早朝。鮮明臨曉日，回轉度春宵。", "半袖籠清鏡，前絲壓翠翹。靜多如有待，閑極似無憀。", "梓澤花猶滿，靈和柳未凋。障昏巫峽雨，屏掩浙江潮。", "未信潘名岳，應疑史姓蕭。漏因歌暫斷，燈為雨頻挑。", "飲酒闌三雅，投壺賽百嬌。鈿蟬新翅重，金鴨舊香焦。", "水淨疑澄練，霞孤欲建標。別隨秦柱促，愁為蜀弦麼。", "玄晏難瘳痹，臨邛但發痟。聯詩征弱絮，思友詠甘蕉。", "王氏憐諸謝，周郎定小喬。黼幃翹彩雉，波扇畫文鰩。", "荇密妨垂釣，荷欹欲度橋。不因衣帶水，誰覺路迢迢。"]'),
('yuding-74','牡丹','唐彥謙','唐','御定全唐诗','yuding','','[]','青帝於君事分偏，穠堆浮豔倚朱門。',32,'御定全唐詩/json/672.json','["青帝於君事分偏，穠堆浮豔倚朱門。", "雖然占得笙歌地，將甚酬他雨露恩。"]'),
('yuding-75','湘妃廟','唐彥謙','唐','御定全唐诗','yuding','','[]','劉表荒碑斷水濱，廟前幽草閉殘春。已將愁淚留斑竹，',40,'御定全唐詩/json/672.json','["劉表荒碑斷水濱，廟前幽草閉殘春。已將愁淚留斑竹，", "九峰相似堪疑處，望見蒼梧不見人。"]'),
('yuding-76','句','唐彥謙','唐','御定全唐诗','yuding','','[]','獨來成悵望，不去泥欄幹。',12,'御定全唐詩/json/672.json','["獨來成悵望，不去泥欄幹。"]'),
('yuding-0','題甘露寺','周樸','唐','御定全唐诗','yuding','','[]','層閣疊危壁，瑞因千古名。幾連揚子路，獨倚潤州城。',48,'御定全唐詩/json/673.json','["層閣疊危壁，瑞因千古名。幾連揚子路，獨倚潤州城。", "雲近銜江色，雕高背磬聲。僧居上方久，端坐見營營。"]'),
('yuding-1','題玄公院','周樸','唐','御定全唐诗','yuding','','[]','院深塵自外，如佛值玄公。常跡或非次，志門因得中。',48,'御定全唐詩/json/673.json','["院深塵自外，如佛值玄公。常跡或非次，志門因得中。", "衣巾離暑氣，床榻向涼風。是事不逾分，只應明德同。"]'),
('yuding-2','福州東禪寺','周樸','唐','御定全唐诗','yuding','','[]','甌閩在郊外，師院號東禪。物得居來正，人經論後賢。',48,'御定全唐詩/json/673.json','["甌閩在郊外，師院號東禪。物得居來正，人經論後賢。", "瓟槽柳塞馬，蓋地月支綖。鸛鵲尚巢頂，誰堪舉世傳。"]'),
('yuding-3','贈大溈和尚','周朴','唐','御定全唐诗','yuding','','[]','大溈清複深，萬象影沉沉。有客衣多毳，空門偈勝金。',48,'御定全唐詩/json/673.json','["大溈清複深，萬象影沉沉。有客衣多毳，空門偈勝金。", "王侯皆作禮，陸子只來吟。我問師心處，師言無處心。"]'),
('yuding-4','秋夜不寐寄崔溫進士','周朴','唐','御定全唐诗','yuding','','[]','愁多難得寐，輾轉讀書床。不是旅人病，豈知秋夜長。',48,'御定全唐詩/json/673.json','["愁多難得寐，輾轉讀書床。不是旅人病，豈知秋夜長。", "歸鄉憑遠夢，無夢更思鄉。枕上移窗月，分明是淚光。"]'),
('yuding-5','春中途中寄南巴崔使君','周樸','唐','御定全唐诗','yuding','','[]','旅人遊汲汲，春氣又融融。農事蛙聲裏，歸程草色中。',48,'御定全唐詩/json/673.json','["旅人遊汲汲，春氣又融融。農事蛙聲裏，歸程草色中。", "獨慚出穀雨，未變暖天風。子玉和予去，應憐恨不窮。"]'),
('yuding-6','寄處士方幹','周樸','唐','御定全唐诗','yuding','','[]','桐廬江水閑，終日對柴關。因想別離處，不知多少山。',48,'御定全唐詩/json/673.json','["桐廬江水閑，終日對柴關。因想別離處，不知多少山。", "釣舟春岸泊，庭樹曉鶯還。莫便求棲隱，桂枝堪恨顏。"]'),
('yuding-7','寄塞北張符','周樸','唐','御定全唐诗','yuding','','[]','隴樹塞風吹，遼城角幾枝。霜凝無暫歇，君貌莫應衰。',48,'御定全唐詩/json/673.json','["隴樹塞風吹，遼城角幾枝。霜凝無暫歇，君貌莫應衰。", "萬里平沙際，一行邊雁移。那堪朔煙起，家信正相離。"]'),
('yuding-8','次梧州卻寄永州使君','周樸','唐','御定全唐诗','yuding','','[]','隨風身不定，今夜在蒼梧。客淚有時有，猿聲無處無。',48,'御定全唐詩/json/673.json','["隨風身不定，今夜在蒼梧。客淚有時有，猿聲無處無。", "潮添瘴海闊，煙拂粵山孤。卻憶零陵住，吟詩半玉壺。"]'),
('yuding-9','贈念經僧','周樸','唐','御定全唐诗','yuding','','[]','庵前古折碑，夜靜念經時。月皎海霞散，露濃山草垂。',48,'御定全唐詩/json/673.json','["庵前古折碑，夜靜念經時。月皎海霞散，露濃山草垂。", "鬼聞拋故塚，禽聽離寒枝。想得天花墜，馨香拂白眉。"]'),
('yuding-10','董嶺水','周朴','唐','御定全唐诗','yuding','','[]','湖州安吉縣，門與白雲齊。禹力不到處，河聲流向西。',48,'御定全唐詩/json/673.json','["湖州安吉縣，門與白雲齊。禹力不到處，河聲流向西。", "去衙山色遠，近水月光低。中有高人在，沙中曳杖藜。"]'),
('yuding-11','早春','周樸','唐','御定全唐诗','yuding','','[]','良夜歲應足，嚴風為變春。遍回寒作暖，通改舊成新。',48,'御定全唐詩/json/673.json','["良夜歲應足，嚴風為變春。遍回寒作暖，通改舊成新。", "秀樹因馨雨，融冰雨泛蘋。韶光不偏黨，積漸煦疲民。"]'),
('yuding-12','秋深','周朴','唐','御定全唐诗','yuding','','[]','柳色尚沉沉，風吹秋更深。山河空遠道，鄉國自鳴砧。',48,'御定全唐詩/json/673.json','["柳色尚沉沉，風吹秋更深。山河空遠道，鄉國自鳴砧。", "巷有千家月，人無萬里心。長城哭崩後，寂絕至如今。"]'),
('yuding-13','贈雙峰山和尚','周朴','唐','御定全唐诗','yuding','','[]','峨峨雙髻山，瀑布瀉雲間。塵世自疑水，禪門長去關。',48,'御定全唐詩/json/673.json','["峨峨雙髻山，瀑布瀉雲間。塵世自疑水，禪門長去關。", "茯神松不異，藏寶石俱閑。向此師清業，如何方可攀。"]'),
('yuding-14','贈無了禪師','周朴','唐','御定全唐诗','yuding','','[]','不學世所惜，是何無了公。靈匡虛院外，虎跡亂山中。',48,'御定全唐詩/json/673.json','["不學世所惜，是何無了公。靈匡虛院外，虎跡亂山中。", "晝夜必連去，古今爭敢同。禪情豈堪問，問答更無窮。"]'),
('yuding-15','王霸壇','周朴','唐','御定全唐诗','yuding','','[]','王君上升處，信首古居前。皂樹即須朽，白龜應亦全。',48,'御定全唐詩/json/673.json','["王君上升處，信首古居前。皂樹即須朽，白龜應亦全。", "雲間猶一日，塵裏已千年。碧色壇如黛，時人誰可仙。"]'),
('yuding-16','送梁道士','周朴','唐','御定全唐诗','yuding','','[]','舊居桐柏觀，歸去愛安閒。倒樹造新屋，化人修古壇。',48,'御定全唐詩/json/673.json','["舊居桐柏觀，歸去愛安閒。倒樹造新屋，化人修古壇。", "晚花霜後落，山雨夜深寒。應有同溪客，相尋學煉丹。"]'),
('yuding-17','邊思','周朴','唐','御定全唐诗','yuding','','[]','年高來遠戍，白首罷幹戎。夜色薊門火，秋聲邊塞風。',48,'御定全唐詩/json/673.json','["年高來遠戍，白首罷幹戎。夜色薊門火，秋聲邊塞風。", "磧浮悲老馬，月滿引新弓。百戰陰山去，唯添上將雄。"]'),
('yuding-18','哭陳庾','周朴','唐','御定全唐诗','yuding','','[]','系馬向山立，一杯聊奠君。野煙孤客路，寒草故人墳。',48,'御定全唐詩/json/673.json','["系馬向山立，一杯聊奠君。野煙孤客路，寒草故人墳。", "琴韻歸流水，詩情寄白雲。日斜休哭後，松韻不堪聞。"]'),
('yuding-19','宿玉泉寺','周樸','唐','御定全唐诗','yuding','','[]','野寺度殘夏，空房欲暮時。夜聽猿不睡，秋思客先知。',48,'御定全唐詩/json/673.json','["野寺度殘夏，空房欲暮時。夜聽猿不睡，秋思客先知。", "竹迥煙生薄，山高月上遲。又登塵路去，難與老僧期。"]'),
('yuding-20','題赤城中岩寺','周樸','唐','御定全唐诗','yuding','','[]','浮世師休話，晉時燈照岩。禽飛穿靜戶，藤結入高杉。',48,'御定全唐詩/json/673.json','["浮世師休話，晉時燈照岩。禽飛穿靜戶，藤結入高杉。", "存沒詩千首，廢興經數函。誰知將俗耳，來此避囂讒。"]'),
('yuding-21','塞上行','周朴','唐','御定全唐诗','yuding','','[]','秦築長城在，連雲磧氣侵。風吹邊草急，角絕塞鴻沈。',48,'御定全唐詩/json/673.json','["秦築長城在，連雲磧氣侵。風吹邊草急，角絕塞鴻沈。", "世世征人往，年年戰骨深。遼天望鄉者，回首盡沾襟。"]'),
('yuding-22','玉泉寺','周樸','唐','御定全唐诗','yuding','','[]','寺還名玉泉，澄水亦遭賢。物尚猶如此，人爭合偶然。',48,'御定全唐詩/json/673.json','["寺還名玉泉，澄水亦遭賢。物尚猶如此，人爭合偶然。", "溪流雲斷外，山峻鳥飛還。初日長廊下，高僧正坐禪。"]'),
('yuding-23','春宮怨','周樸','唐','御定全唐诗','yuding','','[]','早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。',48,'御定全唐詩/json/673.json','["早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。", "風暖鳥聲碎，日高花影重。年年越溪女，相憶采芙蓉。"]'),
('yuding-24','宿劉溫書齋','周樸','唐','御定全唐诗','yuding','','[]','不掩盈窗日，天然格調高。涼風移蟋蟀，落葉在離騷。',48,'御定全唐詩/json/673.json','["不掩盈窗日，天然格調高。涼風移蟋蟀，落葉在離騷。", "回筆挑燈燼，懸圖見海潮。因論三國志，空載幾英豪。"]'),
('yuding-25','登福州南澗寺','周樸','唐','御定全唐诗','yuding','','[]','萬里重山繞福州，南橫一道見溪流。天邊飛鳥東西沒，',40,'御定全唐詩/json/673.json','["萬里重山繞福州，南橫一道見溪流。天邊飛鳥東西沒，", "那堪望斷他鄉目，只此蕭條自白頭。"]'),
('yuding-26','望中懷古','周朴','唐','御定全唐诗','yuding','','[]','齊心樓上望浮雲，萬古千秋空姓名。堯水永銷天際去，',40,'御定全唐詩/json/673.json','["齊心樓上望浮雲，萬古千秋空姓名。堯水永銷天際去，", "從此安然寰海內，後來無複謾相傾。"]'),
('yuding-27','升山寺','周樸','唐','御定全唐诗','yuding','','[]','升山自古道飛來，此是神功不可猜。氣色雖然離禹穴，',40,'御定全唐詩/json/673.json','["升山自古道飛來，此是神功不可猜。氣色雖然離禹穴，", "南望閩城塵世界，千秋萬古卷塵埃。"]'),
('yuding-28','哭李端','周樸','唐','御定全唐诗','yuding','','[]','三年剪拂感知音，哭向青山永夜心。竹在曉煙孤鳳去，',40,'御定全唐詩/json/673.json','["三年剪拂感知音，哭向青山永夜心。竹在曉煙孤鳳去，", "不及此時親執紼，石門遙想淚沾襟。"]'),
('yuding-29','福州神光寺塔','周樸','唐','御定全唐诗','yuding','','[]','良匠用材為塔了，神光寺更得高名。風雲會處千尋出，',40,'御定全唐詩/json/673.json','["良匠用材為塔了，神光寺更得高名。風雲會處千尋出，", "相輪頂上望浮世，塵裏人心應總平。"]'),
('yuding-30','福州開元寺塔','周樸','唐','御定全唐诗','yuding','','[]','開元寺裏七重塔，遙對方山影擬齊。雜俗人看離世界，',40,'御定全唐詩/json/673.json','["開元寺裏七重塔，遙對方山影擬齊。雜俗人看離世界，", "心若無私羅漢在，參差免向日虹西。"]'),
('yuding-31','春日秦國懷古','周樸','唐','御定全唐诗','yuding','','[]','荒郊一望欲消魂，涇水縈紆傍遠村。牛馬放多春草盡，',40,'御定全唐詩/json/673.json','["荒郊一望欲消魂，涇水縈紆傍遠村。牛馬放多春草盡，", "數裏黃沙行客路，不堪回首思秦原。"]'),
('yuding-32','春日遊北園寄韓侍郎','周朴','唐','御定全唐诗','yuding','','[]','灼灼春園晚色分，露珠千點映寒雲。多情舞蝶穿花去，',40,'御定全唐詩/json/673.json','["灼灼春園晚色分，露珠千點映寒雲。多情舞蝶穿花去，", "仙桃不肯全開拆，應借餘芳待使君。"]'),
('yuding-33','喜賀拔先輩衡陽除正字','周朴','唐','御定全唐诗','yuding','','[]','黃紙晴空墜一緘，聖朝恩澤洗冤讒。李膺門客為閑客，',40,'御定全唐詩/json/673.json','["黃紙晴空墜一緘，聖朝恩澤洗冤讒。李膺門客為閑客，", "寰中不用憂天旱，霖雨看看屬傅岩。"]'),
('yuding-34','客州賃居寄蕭郎中','周朴','唐','御定全唐诗','yuding','','[]','松店茅軒向水開，東頭舍賃一裴徊。窗吟苦為秋江靜，',40,'御定全唐詩/json/673.json','["松店茅軒向水開，東頭舍賃一裴徊。窗吟苦為秋江靜，", "眼看白筆為霖雨，肯使紅鱗便曝腮。"]'),
('yuding-35','贈李裕先輩','周朴','唐','御定全唐诗','yuding','','[]','曉擎弓箭入初場，一發曾穿百步楊。仙籍舊題前進士，',40,'御定全唐詩/json/673.json','["曉擎弓箭入初場，一發曾穿百步楊。仙籍舊題前進士，", "閑伴李膺紅燭下，慢吟絲竹淺飛觴。"]'),
('yuding-36','桐柏觀','周朴','唐','御定全唐诗','yuding','','[]','東南一境清心目，有此千峰插翠微。人在下方沖月上，',40,'御定全唐詩/json/673.json','["東南一境清心目，有此千峰插翠微。人在下方沖月上，", "欲識蓬萊今便是，更於何處學忘機。"]'),
('yuding-37','塞上','周樸','唐','御定全唐诗','yuding','','[]','受降城必破，回落隴頭移。蕃道北海北，謀生今始知。',24,'御定全唐詩/json/673.json','["受降城必破，回落隴頭移。蕃道北海北，謀生今始知。"]'),
('yuding-38','塞上曲','周樸','唐','御定全唐诗','yuding','','[]','一陣風來一陣砂，有人行處沒人家。',32,'御定全唐詩/json/673.json','["一陣風來一陣砂，有人行處沒人家。", "黃河九曲冰先合，紫塞三春不見花。"]'),
('yuding-39','塞下曲','周朴','唐','御定全唐诗','yuding','','[]','石國胡兒向磧東，愛吹橫笛引秋風。',32,'御定全唐詩/json/673.json','["石國胡兒向磧東，愛吹橫笛引秋風。", "夜來雲雨皆飛盡，月照平沙萬里空。"]'),
('yuding-40','詠猿','周樸','唐','御定全唐诗','yuding','','[]','生在巫山更向西，不知何事到巴溪。',32,'御定全唐詩/json/673.json','["生在巫山更向西，不知何事到巴溪。", "中宵為憶秋雲伴，遙隔朱門向月啼。"]'),
('yuding-41','桃花','周朴','唐','御定全唐诗','yuding','','[]','桃花春色暖先開，明媚誰人不看來。',32,'御定全唐詩/json/673.json','["桃花春色暖先開，明媚誰人不看來。", "可惜狂風吹落後，殷紅片片點莓苔。"]'),
('yuding-42','薛老峰','周朴','唐','御定全唐诗','yuding','','[]','薛老峰頭三個字，須知此與石齊生。',32,'御定全唐詩/json/673.json','["薛老峰頭三個字，須知此與石齊生。", "直教截斷蒼苔色，浮世人儕眼始明。"]'),
('yuding-43','吊李群玉','周樸','唐','御定全唐诗','yuding','','[]','群玉詩名冠李唐，投詩換得校書郎。',32,'御定全唐詩/json/673.json','["群玉詩名冠李唐，投詩換得校書郎。", "吟魂醉魄知何處，空有幽蘭隔岸香。"]'),
('yuding-44','無等岩','周樸','唐','御定全唐诗','yuding','','[]','建造上方藤影裏，高僧往往似天臺。',32,'御定全唐詩/json/673.json','["建造上方藤影裏，高僧往往似天臺。", "不知名樹簷前長，曾問道人岩下來。"]'),
('yuding-45','句','周朴','唐','御定全唐诗','yuding','','[]','古陵寒雨集，高鳥夕陽明。',156,'御定全唐詩/json/673.json','["古陵寒雨集，高鳥夕陽明。", "高情千裏外，長嘯一聲初。", "月離山一丈，風吹花數苞。", "曉來山鳥鬧，雨過杏花稀。", "曲渚回灣鎖釣舟。", "平潮晚影沈清底，遠岳危欄等翠尖。", "白日才離滄海底，清光先照戶窗前。（靈岩廣化寺，", "連雲天塹有山色，極目海門無雁行。", "可憐黃雀銜將去，從此莊周夢不成。（《詠蝶》。", "見《泉州志》）", "禪是大溈詩是朴，大唐天子只三人。"]'),
('yuding-0','感興','鄭穀','唐','御定全唐诗','yuding','','[]','禾黍不陽豔，競栽桃李春。翻令力耕者，半作賣花人。',24,'御定全唐詩/json/674.json','["禾黍不陽豔，競栽桃李春。翻令力耕者，半作賣花人。"]'),
('yuding-1','望湘亭','鄭谷','唐','御定全唐诗','yuding','','[]','湘水似伊水，湘人非故人。登臨獨無語，風柳自搖春。',24,'御定全唐詩/json/674.json','["湘水似伊水，湘人非故人。登臨獨無語，風柳自搖春。"]'),
('yuding-2','采桑','鄭穀','唐','御定全唐诗','yuding','','[]','曉陌攜籠去，桑林路隔淮。何如鬥百草，賭取鳳凰釵。',24,'御定全唐詩/json/674.json','["曉陌攜籠去，桑林路隔淮。何如鬥百草，賭取鳳凰釵。"]'),
('yuding-3','悶題','鄭穀','唐','御定全唐诗','yuding','','[]','落第春相困，無心惜落花。荊山歸不得，歸得亦無家。',24,'御定全唐詩/json/674.json','["落第春相困，無心惜落花。荊山歸不得，歸得亦無家。"]'),
('yuding-4','中台五題：乳毛松','鄭穀','唐','御定全唐诗','yuding','','[]','松格一何高，何人號乳毛。霜天寓直夜，愧爾伴閑曹。',24,'御定全唐詩/json/674.json','["松格一何高，何人號乳毛。霜天寓直夜，愧爾伴閑曹。"]'),
('yuding-5','中台五題：樗里子墓','鄭谷','唐','御定全唐诗','yuding','','[]','賢人骨已銷，墓樹幾榮凋。正直魂如在，齋心願一招。',24,'御定全唐詩/json/674.json','["賢人骨已銷，墓樹幾榮凋。正直魂如在，齋心願一招。"]'),
('yuding-6','中台五題：牡丹','鄭穀','唐','御定全唐诗','yuding','','[]','亂前看不足，亂後眼偏明。卻得蓬蒿力，遮藏見太平。',24,'御定全唐詩/json/674.json','["亂前看不足，亂後眼偏明。卻得蓬蒿力，遮藏見太平。"]'),
('yuding-7','中台五題：玉蕊','鄭谷','唐','御定全唐诗','yuding','','[]','唐昌樹已荒，天意眷文昌。曉入微風起，春時雪滿牆。',24,'御定全唐詩/json/674.json','["唐昌樹已荒，天意眷文昌。曉入微風起，春時雪滿牆。"]'),
('yuding-8','中台五題：石柱','鄭穀','唐','御定全唐诗','yuding','','[]','暴亂免遺折，森羅賢達名。末郎何所取，叨繼外門榮。',24,'御定全唐詩/json/674.json','["暴亂免遺折，森羅賢達名。末郎何所取，叨繼外門榮。"]'),
('yuding-9','別同志','鄭谷','唐','御定全唐诗','yuding','','[]','所立共寒苦，平生同與遊。相看臨遠水，獨自上孤舟。',48,'御定全唐詩/json/674.json','["所立共寒苦，平生同與遊。相看臨遠水，獨自上孤舟。", "天淡滄浪晚，風悲蘭杜秋。前程吟此景，為子上高樓。"]'),
('yuding-10','送進士盧棨東歸','鄭穀','唐','御定全唐诗','yuding','','[]','灞岸草萋萋，離觴我獨攜。流年俱老大，失意又東西。',48,'御定全唐詩/json/674.json','["灞岸草萋萋，離觴我獨攜。流年俱老大，失意又東西。", "曉楚山雲滿，春吳水樹低。到家梅雨歇，猶有子規啼。"]'),
('yuding-11','從叔郎中諴輟自秋曹分符安陸屬，群盜倡致熾流毒江壖，竟以援兵不來，城池失守例削，今任卻敘省銜退居荊漢之間，頗得琴尊之趣，因有寄獻','鄭谷','唐','御定全唐诗','yuding','','[]','華省稱前任，何慚削一麾。滄洲失孤壘，白髮出重圍。',48,'御定全唐詩/json/674.json','["華省稱前任，何慚削一麾。滄洲失孤壘，白髮出重圍。", "苦節翻多難，空山自喜歸。悠悠清漢上，漁者日相依。"]'),
('yuding-12','送徐渙端公南歸','鄭穀','唐','御定全唐诗','yuding','','[]','青衿離白社，朱綬始言歸。此去應多羨，初心盡不違。',48,'御定全唐詩/json/674.json','["青衿離白社，朱綬始言歸。此去應多羨，初心盡不違。", "江帆和日落，越鳥近鄉飛。一路春風裏，楊花雪滿衣。"]'),
('yuding-13','送祠部曹郎中鄴出守洋州','鄭穀','唐','御定全唐诗','yuding','','[]','為儒欣出守，上路亦戎裝。舊制詩多諷，分憂俗必康。',48,'御定全唐詩/json/674.json','["為儒欣出守，上路亦戎裝。舊制詩多諷，分憂俗必康。", "開懷江稻熟，寄信露橙香。郡閣清吟夜，寒星識望郎。"]'),
('yuding-14','送進士許彬','鄭穀','唐','御定全唐诗','yuding','','[]','泗上未休兵，壺關事可驚。流年催我老，遠道念君行。',48,'御定全唐詩/json/674.json','["泗上未休兵，壺關事可驚。流年催我老，遠道念君行。", "殘雪臨晴水，寒梅發故城。何當食新稻，歲稔又時平。"]'),
('yuding-15','次韻和王駕校書結綬見寄之什','鄭谷','唐','御定全唐诗','yuding','','[]','直應歸諫署，方肯別山村。勤苦常同業，孤單共感恩。',48,'御定全唐詩/json/674.json','["直應歸諫署，方肯別山村。勤苦常同業，孤單共感恩。", "醉披仙鶴氅，吟扣野僧門。夢見君高趣，天涼自灌園。"]'),
('yuding-16','秘閣伴直','鄭谷','唐','御定全唐诗','yuding','','[]','秘閣鎖書深，牆南列晚岑。吏人同野鹿，庭木似山林。',48,'御定全唐詩/json/674.json','["秘閣鎖書深，牆南列晚岑。吏人同野鹿，庭木似山林。", "淺井寒蕪入，回廊疊蘚侵。閑看薛稷鶴，共起五湖心。"]'),
('yuding-17','送太學顏明經及第東歸','鄭谷','唐','御定全唐诗','yuding','','[]','平楚干戈後，田園失耦耕。艱難登一第，離亂省諸兄。',48,'御定全唐詩/json/674.json','["平楚干戈後，田園失耦耕。艱難登一第，離亂省諸兄。", "樹沒春江漲，人繁野渡晴。閑來思學館，猶夢雪窗明。"]'),
('yuding-18','送進士趙能卿下第南歸','鄭穀','唐','御定全唐诗','yuding','','[]','不歸何慰親，歸去舊風塵。灑淚慚關吏，無言對越人。',48,'御定全唐詩/json/674.json','["不歸何慰親，歸去舊風塵。灑淚慚關吏，無言對越人。", "遠帆花月夜，微岸水天春。莫便隨漁釣，平生已苦辛。"]'),
('yuding-19','送人游邊','鄭穀','唐','御定全唐诗','yuding','','[]','春亦怯邊遊，此行風正秋。別離逢雨夜，道路向雲州。',48,'御定全唐詩/json/674.json','["春亦怯邊遊，此行風正秋。別離逢雨夜，道路向雲州。", "磧樹藏城近，沙河漾日流。將軍方破虜，莫惜獻良籌。"]'),
('yuding-20','送人之九江謁郡侯苗員外紳','鄭谷','唐','御定全唐诗','yuding','','[]','澤國尋知己，南浮不偶遊。湓城分楚塞，廬岳對江州。',48,'御定全唐詩/json/674.json','["澤國尋知己，南浮不偶遊。湓城分楚塞，廬岳對江州。", "曉飯臨孤嶼，春帆入亂流。雙旌相望處，月白庾公樓。"]'),
('yuding-21','送許棠先輩之官涇縣','鄭穀','唐','御定全唐诗','yuding','','[]','白頭新作尉，縣在故山中。高第能卑宦，前賢尚此風。',48,'御定全唐詩/json/674.json','["白頭新作尉，縣在故山中。高第能卑宦，前賢尚此風。", "蕪湖春蕩漾，梅雨晝溟蒙。佐理人安後，篇章莫廢功。"]'),
('yuding-22','送司封從叔員外徼赴華州裴尚書均辟','鄭穀','唐','御定全唐诗','yuding','','[]','如何拋錦帳，蓮府對蓮峰。舊有雲霞約，暫留鵷鷺蹤。',48,'御定全唐詩/json/674.json','["如何拋錦帳，蓮府對蓮峰。舊有雲霞約，暫留鵷鷺蹤。", "敷溪秋雪岸，樹谷夕陽鐘。盡入新吟境，歸朝興莫慵。"]'),
('yuding-23','送京參翁先輩歸閩中','鄭谷','唐','御定全唐诗','yuding','','[]','解印東歸去，人情此際多。名高五七字，道勝兩重科。',48,'御定全唐詩/json/674.json','["解印東歸去，人情此際多。名高五七字，道勝兩重科。", "宿館明寒燒，吟船兀夜波。家山春更好，越鳥在庭柯。"]'),
('yuding-24','贈別','鄭谷','唐','御定全唐诗','yuding','','[]','南游曾共遊，相別倍相留。行色回燈曉，離聲滿竹秋。',48,'御定全唐詩/json/674.json','["南游曾共遊，相別倍相留。行色回燈曉，離聲滿竹秋。", "穩眠彭蠡浪，好醉岳陽樓。明日逢佳景，為君成白頭。"]'),
('yuding-25','南游','鄭谷','唐','御定全唐诗','yuding','','[]','淒涼懷古意，湘浦吊靈均。故國經新歲，扁舟寄病身。',48,'御定全唐詩/json/674.json','["淒涼懷古意，湘浦吊靈均。故國經新歲，扁舟寄病身。", "山城多曉瘴，澤國少晴春。漸遠無相識，青梅獨向人。"]'),
('yuding-26','巴賨旅寓寄朝中從叔','鄭谷','唐','御定全唐诗','yuding','','[]','驚秋思浩然，信美向巴天。獨倚臨江樹，初聞落日蟬。',48,'御定全唐詩/json/674.json','["驚秋思浩然，信美向巴天。獨倚臨江樹，初聞落日蟬。", "哀榮悲往事，漂泊念多年。未便甘休去，吾宗盡見憐。"]'),
('yuding-27','寄司勳張員外學士','鄭谷','唐','御定全唐诗','yuding','','[]','平昔偏知我，司勳張外郎。昨來聞俶擾，憂甚欲顛狂。',48,'御定全唐詩/json/674.json','["平昔偏知我，司勳張外郎。昨來聞俶擾，憂甚欲顛狂。", "煙暝搔愁鬢，春陰賴酒鄉。江樓倚不得，橫笛數聲長。"]'),
('yuding-28','寄邊上從事','鄭穀','唐','御定全唐诗','yuding','','[]','男兒懷壯節，何不事嫖姚。高疊觀諸寨，全師護大朝。',48,'御定全唐詩/json/674.json','["男兒懷壯節，何不事嫖姚。高疊觀諸寨，全師護大朝。", "淺山寒放馬，亂火夜防苗。下第春愁甚，勞君遠見招。"]'),
('yuding-29','寄左省韋起居序','鄭谷','唐','御定全唐诗','yuding','','[]','風神何蘊藉，張緒正當年。端簡爐香裏，濡毫洞案邊。',48,'御定全唐詩/json/674.json','["風神何蘊藉，張緒正當年。端簡爐香裏，濡毫洞案邊。", "飾裝無雨備，著述減春眠。旦夕應彌入，銀台曉候宣。"]'),
('yuding-30','寄贈藍田韋少府先輩','鄭谷','唐','御定全唐诗','yuding','','[]','王畿第一縣，縣尉是詞人。館殿非初意，圖書是舊貧。',48,'御定全唐詩/json/674.json','["王畿第一縣，縣尉是詞人。館殿非初意，圖書是舊貧。", "斫冰泉竇響，賽雪廟松春。自此升通籍，清華日近身。"]'),
('yuding-31','寄懷元秀上人','鄭穀','唐','御定全唐诗','yuding','','[]','悠悠幹祿利，草草廢漁樵。身世堪惆悵，風騷頗寂寥。',48,'御定全唐詩/json/674.json','["悠悠幹祿利，草草廢漁樵。身世堪惆悵，風騷頗寂寥。", "高秋期野步，積雨放趨朝。得句如相憶，莎齋且見招。"]'),
('yuding-32','贈圓昉公','鄭穀','唐','御定全唐诗','yuding','','[]','天階讓紫衣，冷格鶴猶卑。道勝嫌名出，身閑覺老遲。',48,'御定全唐詩/json/674.json','["天階讓紫衣，冷格鶴猶卑。道勝嫌名出，身閑覺老遲。", "晚香延宿火，寒磬度高枝。長說長松寺，他年與我期。"]'),
('yuding-33','寄題方幹處士','鄭穀','唐','御定全唐诗','yuding','','[]','山雪照湖水，漾舟湖畔歸。松篁調遠籟，台榭發清輝。',48,'御定全唐詩/json/674.json','["山雪照湖水，漾舟湖畔歸。松篁調遠籟，台榭發清輝。", "野岫分閑徑，漁家並掩扉。暮年詩力在，新句更幽微。"]'),
('yuding-34','寄獻湖州從叔員外','鄭谷','唐','御定全唐诗','yuding','','[]','顧渚山邊郡，溪將罨畫通。遠看城郭裏，全在水雲中。',72,'御定全唐詩/json/674.json','["顧渚山邊郡，溪將罨畫通。遠看城郭裏，全在水雲中。", "西閣歸何晚，東吳興未窮。茶香紫筍露，洲回白蘋風。", "歌緩眉低翠，杯明蠟翦紅。政成尋往事，輟棹問漁翁。"]'),
('yuding-35','訪姨兄王斌渭口別墅','鄭谷','唐','御定全唐诗','yuding','','[]','枯桑河上村，寥落舊田園。少小曾來此，悲涼不可言。',120,'御定全唐詩/json/674.json','["枯桑河上村，寥落舊田園。少小曾來此，悲涼不可言。", "訪鄰多指塚，問路半移原。久歉家僮散，初晴野薺繁。", "客帆懸極浦，漁網曬危軒。苦澀詩盈篋，荒唐酒滿尊。", "高枝霜果在，幽渚暝禽喧。遠靄籠樵響，微煙起燒痕。", "哀榮孤族分，感激外兄恩。三宿忘歸去，圭峰恰對門。"]'),
('yuding-36','放朝偶作','鄭穀','唐','御定全唐诗','yuding','','[]','寒極放朝天，欣聞半夜宣。時安逢密雪，日晏得高眠。',48,'御定全唐詩/json/674.json','["寒極放朝天，欣聞半夜宣。時安逢密雪，日晏得高眠。", "擁褐同休假，吟詩賀有年。坐來幽興在，松亞小窗前。"]'),
('yuding-37','順動後藍田偶作','鄭穀','唐','御定全唐诗','yuding','','[]','小諫升中諫，三年侍玉除。且言無所補，浩歎欲何如。',48,'御定全唐詩/json/674.json','["小諫升中諫，三年侍玉除。且言無所補，浩歎欲何如。", "宮闕飛灰燼，嬪嬙落裏閭。藍峰秋更碧，沾灑望鑾輿。"]'),
('yuding-38','府中寓止寄趙大諫','鄭穀','唐','御定全唐诗','yuding','','[]','老作含香客，貧無僦舍錢。神州容寄跡，大尹是同年。',48,'御定全唐詩/json/674.json','["老作含香客，貧無僦舍錢。神州容寄跡，大尹是同年。", "密邇都忘倦，乖慵益見憐。雪風花月好，中夜便招延。"]'),
('yuding-39','峽中寓止二首','鄭穀','唐','御定全唐诗','yuding','','[]','荊州未解圍，小縣結茅茨。強對官人笑，甘為野鶴欺。',96,'御定全唐詩/json/674.json','["荊州未解圍，小縣結茅茨。強對官人笑，甘為野鶴欺。", "江春鋪網闊，市晚鬻蔬遲。子美猶如此，翻然不敢悲。", "傳聞殊不定，鑾輅幾時還。俗易無常性，江清見老顏。", "夜船歸草市，春步上茶山。寨將來相問，兒童競啟關。"]'),
('yuding-40','顏惠詹事即孤侄舅氏謫官黔巫舟中相遇愴然有寄','鄭穀','唐','御定全唐诗','yuding','','[]','猶子在天末，念渠懷渭陽。巴山偶會遇，江浦共悲涼。',48,'御定全唐詩/json/674.json','["猶子在天末，念渠懷渭陽。巴山偶會遇，江浦共悲涼。", "謫宦君何遠，窮游我自強。瘴村三月暮，雨熟野梅黃。"]'),
('yuding-41','訪題進士孫秦延福南街居','鄭穀','唐','御定全唐诗','yuding','','[]','多病久離索，相尋聊解顏。短牆通禦水，疏樹出南山。',48,'御定全唐詩/json/674.json','["多病久離索，相尋聊解顏。短牆通禦水，疏樹出南山。", "歲月何難老，園林未得還。無門共榮達，孤坐卻如閑。"]'),
('yuding-42','訪題進士張喬延興門外所居','鄭谷','唐','御定全唐诗','yuding','','[]','平生苦節同，旦夕會原東。掩卷斜陽裏，看山落木中。',48,'御定全唐詩/json/674.json','["平生苦節同，旦夕會原東。掩卷斜陽裏，看山落木中。", "星霜今欲老，江海業全空。近日文場內，因君起古風。"]'),
('yuding-43','寄南浦謫官','鄭穀','唐','御定全唐诗','yuding','','[]','多才翻得罪，天末抱窮憂。白首為遷客，青山繞萬州。',48,'御定全唐詩/json/674.json','["多才翻得罪，天末抱窮憂。白首為遷客，青山繞萬州。", "醉欹梅障曉，歌厭竹枝秋。望闕懷鄉淚，荊江水共流。"]'),
('yuding-44','李夷遇侍禦久滯水鄉因抒寄懷','鄭穀','唐','御定全唐诗','yuding','','[]','簪豸年何久，懸帆興甚長。江流愛吳越，詩格愈齊梁。',48,'御定全唐詩/json/674.json','["簪豸年何久，懸帆興甚長。江流愛吳越，詩格愈齊梁。", "竹寺晴吟遠，蘭洲晚泊香。高閑徒自任，華省待為郎。"]'),
('yuding-45','寄膳部李郎中昌符','鄭穀','唐','御定全唐诗','yuding','','[]','鄠郊陪野步，早歲偶因詩。自後吟新句，長愁減舊知。',48,'御定全唐詩/json/674.json','["鄠郊陪野步，早歲偶因詩。自後吟新句，長愁減舊知。", "靜燈微落燼，寒硯旋生澌。夜夜冥搜苦，那能鬢不衰。"]'),
('yuding-46','寄前水部賈員外嵩','鄭谷','唐','御定全唐诗','yuding','','[]','謝病別文昌，仙舟向越鄉。貴為金馬客，雅稱水曹郎。',48,'御定全唐詩/json/674.json','["謝病別文昌，仙舟向越鄉。貴為金馬客，雅稱水曹郎。", "白鷺同孤潔，清波共渺茫。相如詞賦外，騷雅趣何長。"]'),
('yuding-47','寄棋客','鄭穀','唐','御定全唐诗','yuding','','[]','松窗楸局穩，相顧思皆凝。幾局賭山果，一先饒海僧。',48,'御定全唐詩/json/674.json','["松窗楸局穩，相顧思皆凝。幾局賭山果，一先饒海僧。", "覆圖聞夜雨，下子對秋燈。何日無羈束，期君向杜陵。"]'),
('yuding-48','聞進士許彬罷舉歸睦州悵然懷寄','鄭穀','唐','御定全唐诗','yuding','','[]','桐廬歸舊廬，垂老複樵漁。吾子雖言命，鄉人懶讀書。',48,'御定全唐詩/json/674.json','["桐廬歸舊廬，垂老複樵漁。吾子雖言命，鄉人懶讀書。", "煙舟撐晚浦，雨屐剪春蔬。異代名方振，哀吟莫廢初。"]'),
('yuding-49','長安夜坐寄懷湖外嵇處士','鄭穀','唐','御定全唐诗','yuding','','[]','萬里念江海，浩然天地秋。風高群木落，夜久數星流。',48,'御定全唐詩/json/674.json','["萬里念江海，浩然天地秋。風高群木落，夜久數星流。", "鐘絕分宮漏，螢微隔禦溝。遙思洞庭上，葦露滴漁舟。"]'),
('yuding-50','贈文士王雄','鄭谷','唐','御定全唐诗','yuding','','[]','知己竟何人，哀君尚苦辛。圖書長在手，文學老於身。',48,'御定全唐詩/json/674.json','["知己竟何人，哀君尚苦辛。圖書長在手，文學老於身。", "公道天難廢，貞姿世任嗔。小齋松菊靜，願蔔子為鄰。"]'),
('yuding-51','贈富平李宰','鄭谷','唐','御定全唐诗','yuding','','[]','夫君清且貧，琴鶴最相親。簡肅諸曹事，安閒一境人。',48,'御定全唐詩/json/674.json','["夫君清且貧，琴鶴最相親。簡肅諸曹事，安閒一境人。", "陵山雲裏拜，渠路雨中巡。易得連宵醉，千缸石凍春。"]'),
('yuding-52','贈尚顏上人','鄭穀','唐','御定全唐诗','yuding','','[]','相尋喜可知，放錫便論詩。酷愛山兼水，唯應我與師。',48,'御定全唐詩/json/674.json','["相尋喜可知，放錫便論詩。酷愛山兼水，唯應我與師。", "風雷吟不覺，猿鶴老為期。近輩推棲白，其如趣向卑。"]'),
('yuding-53','贈泗口苗居士','鄭谷','唐','御定全唐诗','yuding','','[]','歲晏樂園林，維摩契道心。江雲寒不散，庭雪夜方深。',48,'御定全唐詩/json/674.json','["歲晏樂園林，維摩契道心。江雲寒不散，庭雪夜方深。", "酒勸漁人飲，詩憐稚子吟。四郊多壘日，勉我舍朝簪。"]'),
('yuding-54','梁燭處士辭金陵，相國杜公歸舊山，因以寄贈','鄭穀','唐','御定全唐诗','yuding','','[]','相庭留不得，江野有苔磯。兩浙尋山遍，孤舟載鶴歸。',48,'御定全唐詩/json/674.json','["相庭留不得，江野有苔磯。兩浙尋山遍，孤舟載鶴歸。", "世間書讀盡，雲外客來稀。諫署搜賢急，應難惜布衣。"]'),
('yuding-55','哭建州李員外頻','鄭穀','唐','御定全唐诗','yuding','','[]','令終歸故里，末歲道如初。舊友誰為志，清風豈易書。',48,'御定全唐詩/json/674.json','["令終歸故里，末歲道如初。舊友誰為志，清風豈易書。", "雨墳生野蕨，鄉奠釣江魚。獨夜吟還泣，前年伴直廬。"]'),
('yuding-56','哭進士李洞二首','鄭穀','唐','御定全唐诗','yuding','','[]','所惜絕吟聲，不悲君不榮。李端終薄宦，賈島得高名。',96,'御定全唐詩/json/674.json','["所惜絕吟聲，不悲君不榮。李端終薄宦，賈島得高名。", "旅葬新墳小，遺孤遠俗輕。猶疑隨計晚，昨夜草蟲鳴。", "自聞東蜀病，唯我獨關情。若近長江死，想君勝在生。", "瘴蒸丹旐濕，燈隔素帷清。塚樹僧栽後，新蟬一兩聲。"]'),
('yuding-57','南康郡牧陸肱郎中辟許棠先輩為郡從事，因有寄贈','鄭穀','唐','御定全唐诗','yuding','','[]','末路思前侶，猶為戀故巢。江山多勝境，賓主是貧交。',48,'御定全唐詩/json/674.json','["末路思前侶，猶為戀故巢。江山多勝境，賓主是貧交。", "飲舫閑依葦，琴堂雅結茅。夜清僧伴宿，水月在松梢。"]'),
('yuding-58','久不得張喬消息','鄭穀','唐','御定全唐诗','yuding','','[]','天末去程孤，沿淮複向吳。亂離何處甚，安穩到家無。',48,'御定全唐詩/json/674.json','["天末去程孤，沿淮複向吳。亂離何處甚，安穩到家無。", "樹盡雲垂野，檣稀月滿湖。傷心繞村落，應少舊耕夫。"]'),
('yuding-59','題嵩高隱者居','鄭谷','唐','御定全唐诗','yuding','','[]','豈易訪仙蹤，雲蘿千萬重。他年來卜隱，此景願相容。',48,'御定全唐詩/json/674.json','["豈易訪仙蹤，雲蘿千萬重。他年來卜隱，此景願相容。", "亂水林中路，深山雪裏鐘。見君琴酒樂，回首興何慵。"]'),
('yuding-60','趙璘郎中席上賦蝴蝶','鄭穀','唐','御定全唐诗','yuding','','[]','尋豔複尋香，似閑還似忙。暖煙沈蕙徑，微雨宿花房。',48,'御定全唐詩/json/674.json','["尋豔複尋香，似閑還似忙。暖煙沈蕙徑，微雨宿花房。", "書幌輕隨夢，歌樓誤采妝。王孫深屬意，繡入舞衣裳。"]'),
('yuding-61','賀進士駱用錫登第','鄭谷','唐','御定全唐诗','yuding','','[]','苦辛垂二紀，擢第卻沾裳。春榜到春晚，一家榮一鄉。',48,'御定全唐詩/json/674.json','["苦辛垂二紀，擢第卻沾裳。春榜到春晚，一家榮一鄉。", "題名登塔喜，醵宴為花忙。好是東歸日，高槐蕊半黃。"]'),
('yuding-62','興州東池','鄭谷','唐','御定全唐诗','yuding','','[]','南連乳郡流，闊碧浸晴樓。徹底千峰影，無風一片秋。',48,'御定全唐詩/json/674.json','["南連乳郡流，闊碧浸晴樓。徹底千峰影，無風一片秋。", "垂楊拂蓮葉，返照媚漁舟。鑒貌還惆悵，難遮兩鬢羞。"]'),
('yuding-63','渠江旅思','鄭穀','唐','御定全唐诗','yuding','','[]','流落複蹉跎，交親半逝波。謀身非不切，言命欲如何。',48,'御定全唐詩/json/674.json','["流落複蹉跎，交親半逝波。謀身非不切，言命欲如何。", "故楚春田廢，窮巴瘴雨多。引人鄉淚盡，夜夜竹枝歌。"]'),
('yuding-64','登杭州城','鄭穀','唐','御定全唐诗','yuding','','[]','漠漠江天外，登臨返照間。潮來無別浦，木落見他山。',48,'御定全唐詩/json/674.json','["漠漠江天外，登臨返照間。潮來無別浦，木落見他山。", "沙鳥晴飛遠，漁人夜唱閑。歲窮歸未得，心逐片帆還。"]'),
('yuding-65','曲江','鄭穀','唐','御定全唐诗','yuding','','[]','細草岸西東，酒旗搖水風。樓臺在煙杪，鷗鷺下沙中。',48,'御定全唐詩/json/674.json','["細草岸西東，酒旗搖水風。樓臺在煙杪，鷗鷺下沙中。", "翠幄晴相接，芳洲夜暫空。何人賞秋景，興與此時同。"]'),
('yuding-66','沙苑','鄭穀','唐','御定全唐诗','yuding','','[]','茫茫信馬行，不似近都城。苑吏猶迷路，江人莫問程。',48,'御定全唐詩/json/674.json','["茫茫信馬行，不似近都城。苑吏猶迷路，江人莫問程。", "聚來千嶂出，落去一川平。日暮客心速，愁聞雁數聲。"]'),
('yuding-67','通川客舍','鄭穀','唐','御定全唐诗','yuding','','[]','奔走失前計，淹留非本心。已難消永夜，況複聽秋霖。',48,'御定全唐詩/json/674.json','["奔走失前計，淹留非本心。已難消永夜，況複聽秋霖。", "漸解巴兒語，誰憐越客吟。黃花徒滿手，白髮不勝簪。"]'),
('yuding-68','潼關道中','鄭谷','唐','御定全唐诗','yuding','','[]','白道曉霜迷，離燈照馬嘶。秋風滿關樹，殘月隔河雞。',48,'御定全唐詩/json/674.json','["白道曉霜迷，離燈照馬嘶。秋風滿關樹，殘月隔河雞。", "來往非無倦，窮通豈易齊。何年歸故社，披雨剪春畦。"]'),
('yuding-69','終南白鶴觀','鄭谷','唐','御定全唐诗','yuding','','[]','步步景通真，門前眾水分。檉蘿諸洞合，鐘磬上清聞。',48,'御定全唐詩/json/674.json','["步步景通真，門前眾水分。檉蘿諸洞合，鐘磬上清聞。", "古木千尋雪，寒山萬丈雲。終期掃壇級，來事紫陽君。"]'),
('yuding-70','題興善寺寂上人院','鄭穀','唐','御定全唐诗','yuding','','[]','客來風雨後，院靜似荒涼。罷講蛩離砌，思山葉滿廊。',48,'御定全唐詩/json/674.json','["客來風雨後，院靜似荒涼。罷講蛩離砌，思山葉滿廊。", "臘高興故疾，爐暖發餘香。自說匡廬側，杉陰半石床。"]'),
('yuding-71','題水部李羽員外招國裏居','鄭穀','唐','御定全唐诗','yuding','','[]','野色入前軒，翛然琴與尊。畫僧依寺壁，栽葦學江村。',48,'御定全唐詩/json/674.json','["野色入前軒，翛然琴與尊。畫僧依寺壁，栽葦學江村。", "自醞花前酒，誰敲雪裏門。不辭朝謁遠，唯要近慈恩。"]'),
('yuding-72','信美寺岑上人','鄭谷','唐','御定全唐诗','yuding','','[]','巡禮諸方遍，湘南頗有緣。焚香老山寺，乞食向江船。',48,'御定全唐詩/json/674.json','["巡禮諸方遍，湘南頗有緣。焚香老山寺，乞食向江船。", "紗碧籠名畫，燈寒照淨禪。我來能永日，蓮漏滴階前。"]'),
('yuding-73','池上','鄭谷','唐','御定全唐诗','yuding','','[]','池榭愜幽獨，狂吟學解嘲。露荷香自在，風竹冷相敲。',48,'御定全唐詩/json/674.json','["池榭愜幽獨，狂吟學解嘲。露荷香自在，風竹冷相敲。", "喪志嫌孤宦，忘機愛澹交。仙山如有分，必擬訪三茅。"]'),
('yuding-74','游貴侯城南林墅','鄭谷','唐','御定全唐诗','yuding','','[]','韋杜八九月，亭台高下風。獨來新霽後，閒步澹煙中。',48,'御定全唐詩/json/674.json','["韋杜八九月，亭台高下風。獨來新霽後，閒步澹煙中。", "荷密連池綠，柿繁和葉紅。主人貪貴達，清境屬鄰翁。"]'),
('yuding-75','江行','鄭穀','唐','御定全唐诗','yuding','','[]','漂泊病難任，逢人淚滿襟。關東多事日，天末未歸心。',48,'御定全唐詩/json/674.json','["漂泊病難任，逢人淚滿襟。關東多事日，天末未歸心。", "夜雨荊江漲，春雲郢樹深。殷勤聽漁唱，漸次入吳音。"]'),
('yuding-76','舟次通泉精舍','鄭谷','唐','御定全唐诗','yuding','','[]','江清如洛汭，寺好似香山。勞倦孤舟裏，登臨半日間。',48,'御定全唐詩/json/674.json','["江清如洛汭，寺好似香山。勞倦孤舟裏，登臨半日間。", "樹涼巢鶴健，岩響語僧閑。更共幽雲約，秋隨絳帳還。"]'),
('yuding-77','水軒','鄭穀','唐','御定全唐诗','yuding','','[]','日日狎沙禽，偷安且放吟。讀書老不入，愛酒病還深。',48,'御定全唐詩/json/674.json','["日日狎沙禽，偷安且放吟。讀書老不入，愛酒病還深。", "歉後為羈客，兵餘問故林。楊花滿床席，搔首度春陰。"]'),
('yuding-78','潯陽姚宰廳作','鄭穀','唐','御定全唐诗','yuding','','[]','縣幽公事稀，庭草是山薇。足得招棋侶，何妨著道衣。',48,'御定全唐詩/json/674.json','["縣幽公事稀，庭草是山薇。足得招棋侶，何妨著道衣。", "野泉當案落，汀鷺入衙飛。寺去東林近，多應隔宿歸。"]'),
('yuding-79','梓潼歲暮','鄭谷','唐','御定全唐诗','yuding','','[]','江城無宿雪，風物易為春。酒美消磨日，梅香著莫人。',48,'御定全唐詩/json/674.json','["江城無宿雪，風物易為春。酒美消磨日，梅香著莫人。", "老吟窮景象，多難損精神。漸有還京望，綿州減戰塵。"]'),
('yuding-80','咸陽','鄭穀','唐','御定全唐诗','yuding','','[]','咸陽城下宿，往事可悲思。未有謀身計，頻遷反正期。',48,'御定全唐詩/json/674.json','["咸陽城下宿，往事可悲思。未有謀身計，頻遷反正期。", "凍河孤棹澀，老樹疊巢危。莫問今行止，漂漂不自知。"]');
